definition: "CREATE OR REPLACE FUNCTION public."AAA_CHECKTHISFIRST__AAA_balance_ledger"()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_type text := lower(new.type);
  v_provider text := lower(coalesce(new.payment_provider, ''));
BEGIN
  v_type := trim(v_type);
  v_provider := trim(v_provider);

  -- type sanity
  IF v_type NOT IN ('entry','purchase','topup') THEN
    RAISE EXCEPTION 'AAA_CHECKTHISFIRST__AAA: invalid type: % (expected entry|purchase|topup)', new.type;
  END IF;

  -- topup must always credit
  IF v_type = 'topup' THEN
    IF new.amount <= 0 THEN
      RAISE EXCEPTION 'AAA_CHECKTHISFIRST__AAA: topup must CREDIT internal balance (amount > 0), got %', new.amount;
    END IF;
  END IF;

  -- payment_provider = balance_payment must always debit
  IF v_provider = 'balance_payment' THEN
    IF new.amount >= 0 THEN
      RAISE EXCEPTION 'AAA_CHECKTHISFIRST__AAA: balance_payment must always DEBIT (amount < 0), got %', new.amount;
    END IF;
  END IF;

  -- Only when type=topup & payment_provider=base_account do we credit from base
  IF v_provider = 'base_account' THEN
    IF v_type = 'topup' THEN
      IF new.amount <= 0 THEN
        RAISE EXCEPTION 'AAA_CHECKTHISFIRST__AAA: base_account topup must CREDIT (amount > 0), got %', new.amount;
      END IF;
    ELSE
      -- For entry/purchase with base_account, do not change internal balance
      IF new.amount <> 0 THEN
        RAISE EXCEPTION 'AAA_CHECKTHISFIRST__AAA: base_account % must not change internal balance (amount = 0), got %', v_type, new.amount;
      END IF;
    END IF;
  END IF;

  RETURN new;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public._apply_wallet_delta(p_canonical_user_id text, p_currency text, p_delta numeric)
 RETURNS TABLE(balance_before numeric, balance_after numeric)
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF p_canonical_user_id IS NULL THEN
    RAISE EXCEPTION 'canonical_user_id is required';
  END IF;

  IF p_currency IS NULL OR upper(p_currency) NOT IN ('USD','USDC') THEN
    RAISE EXCEPTION 'Unsupported currency: %', p_currency;
  END IF;

  -- Ensure row exists
  INSERT INTO public.sub_account_balances (id, canonical_user_id, user_id, currency, available_balance, pending_balance, last_updated)
  SELECT gen_random_uuid(), p_canonical_user_id, p_canonical_user_id, 'USD', 0, 0, now()
  ON CONFLICT DO NOTHING;

  -- Lock row and read before
  SELECT available_balance INTO balance_before
  FROM public.sub_account_balances
  WHERE canonical_user_id = p_canonical_user_id
  FOR UPDATE;

  IF balance_before IS NULL THEN
    balance_before := 0;
  END IF;

  balance_after := balance_before + p_delta;

  IF balance_after < 0 THEN
    RAISE EXCEPTION 'Insufficient wallet balance for %: before %, delta %, after %', p_canonical_user_id, balance_before, p_delta, balance_after;
  END IF;

  UPDATE public.sub_account_balances
  SET available_balance = balance_after,
      last_updated = now()
  WHERE canonical_user_id = p_canonical_user_id;

  RETURN;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public._bl_guard_reference_id()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF NEW.type IN ('entry','purchase') AND NEW.reference_id IS NULL THEN
    RAISE EXCEPTION 'balance_ledger.reference_id must not be NULL for type %, amount %, desc %',
      NEW.type, NEW.amount, NEW.description;
  END IF;
  RETURN NEW;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public._cdp_first_number_in_braces(input text)
 RETURNS numeric
 LANGUAGE plpgsql
AS $function$
DECLARE
  cleaned text;
  first_part text;
BEGIN
  IF input IS NULL THEN RETURN NULL; END IF;
  cleaned := regexp_replace(input, '[{}]', '', 'g');
  first_part := split_part(cleaned, ' ', 1);
  -- Strip non-digits just in case and cast
  RETURN NULLIF(regexp_replace(first_part, '\\D', '', 'g'), '')::numeric;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public._test_block(p_ticket_count integer DEFAULT 0)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_res public.pending_tickets%ROWTYPE;
  v_competition_id uuid;
  v_needed int := GREATEST(COALESCE(p_ticket_count, 0), 0);
  v_available int[] := ARRAY[]::int[];
  v_selected int[] := ARRAY[]::int[];
  v_now timestamptz := now();
BEGIN
  RAISE NOTICE 'v_needed=%', v_needed;
END
$function$
"

definition: "CREATE OR REPLACE FUNCTION public._upsert_competition_entry_from_ticket()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_cuid text;
  v_comp uuid;
  v_wallet text;
  v_price numeric;
  v_ts timestamptz := now();
  v_num int;
BEGIN
  IF TG_OP = 'DELETE' THEN
    RETURN OLD;
  END IF;

  -- Use NEW only
  v_cuid := COALESCE(NEW.canonical_user_id, NEW.user_id, NEW.wallet_address);
  v_comp := NEW.competition_id;
  v_wallet := COALESCE(NEW.wallet_address, replace(NEW.canonical_user_id, 'prize:pid:', ''));
  v_price := COALESCE(NEW.purchase_price, NEW.payment_amount, 0);
  v_num := NEW.ticket_number;

  IF v_cuid IS NULL OR v_comp IS NULL OR v_num IS NULL THEN
    RETURN NEW;
  END IF;

  -- Only act on finalized tickets
  IF COALESCE(NEW.status,'') NOT IN ('sold','purchased') THEN
    RETURN NEW;
  END IF;

  INSERT INTO public.competition_entries AS ce (
    id, canonical_user_id, competition_id, wallet_address, tickets_count, ticket_numbers_csv, amount_spent, latest_purchase_at, created_at, updated_at
  ) VALUES (
    gen_random_uuid(), v_cuid, v_comp, v_wallet, 1, v_num::text, v_price, COALESCE(NEW.purchase_date, NEW.purchased_at, NEW.created_at, v_ts), v_ts, v_ts
  )
  ON CONFLICT (canonical_user_id, competition_id)
  DO UPDATE SET
    tickets_count = ce.tickets_count + 1,
    amount_spent = COALESCE(ce.amount_spent,0) + v_price,
    ticket_numbers_csv = CASE
      WHEN ce.ticket_numbers_csv IS NULL OR ce.ticket_numbers_csv = '' THEN v_num::text
      ELSE ce.ticket_numbers_csv || ',' || v_num::text
    END,
    wallet_address = COALESCE(ce.wallet_address, v_wallet),
    latest_purchase_at = GREATEST(COALESCE(ce.latest_purchase_at, v_ts), COALESCE(NEW.purchase_date, NEW.purchased_at, NEW.created_at, v_ts)),
    updated_at = v_ts;

  RETURN NEW;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.after_cep_change()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  PERFORM public.recompute_competition_entry(NEW.canonical_user_id, NEW.competition_id);
  RETURN NEW;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.allocate_lucky_dip_tickets(p_competition_id text, p_user_id text, p_ticket_count integer)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_allocated_tickets INTEGER[];
  v_total_tickets INTEGER;
  v_sold_tickets INTEGER;
  v_ticket INTEGER;
  v_unavailable INTEGER[];
BEGIN
  -- Get competition info (competitions.id is UUID now)
  SELECT total_tickets, sold_tickets INTO v_total_tickets, v_sold_tickets
  FROM competitions
  WHERE id = p_competition_id::UUID OR uid = p_competition_id::UUID;

  -- Get unavailable tickets (tickets_sold.competition_id is still TEXT)
  SELECT ARRAY_AGG(ticket_number) INTO v_unavailable
  FROM tickets_sold
  WHERE competition_id = p_competition_id;

  -- Allocate tickets
  v_allocated_tickets := ARRAY[]::INTEGER[];
  FOR v_ticket IN 1..v_total_tickets
  LOOP
    IF v_ticket = ANY(COALESCE(v_unavailable, ARRAY[]::INTEGER[])) THEN
      CONTINUE;
    END IF;
    IF array_length(v_allocated_tickets, 1) >= p_ticket_count THEN
      EXIT;
    END IF;
    v_allocated_tickets := array_append(v_allocated_tickets, v_ticket);
  END LOOP;

  RETURN jsonb_build_object(
    'success', true,
    'ticket_numbers', v_allocated_tickets
  );
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.allocate_temp_canonical_user()
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_temp_id TEXT;
  v_canonical_user_id TEXT;
  v_uid TEXT;
BEGIN
  -- Allocate next temp ID atomically from sequence
  v_temp_id := nextval('temp_user_sequence')::TEXT;
  v_canonical_user_id := 'prize:pid:temp' || v_temp_id;
  
  -- Generate unique uid for this user (used as stable identifier)
  v_uid := gen_random_uuid()::TEXT;
  
  -- Return both values for frontend to use
  RETURN jsonb_build_object(
    'uid', v_uid,
    'canonical_user_id', v_canonical_user_id,
    'temp_id', v_temp_id
  );
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.apply_user_tx_usdc_balance()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_uid text;
  current_balance numeric;
BEGIN
  -- Only enforce for USDC
  IF NEW.currency <> 'USDC' THEN
    RETURN NEW;
  END IF;

  -- Resolve user identifier used in sub_account_balances
  v_uid := COALESCE(NEW.canonical_user_id, NEW.user_id::text);

  -- Lock SAB row; create if missing
  SELECT available_balance
    INTO current_balance
    FROM public.sub_account_balances
   WHERE user_id = v_uid AND currency = 'USDC'
   FOR UPDATE;

  IF current_balance IS NULL THEN
    current_balance := 0;

    INSERT INTO public.sub_account_balances(
      id, user_id, currency, available_balance, pending_balance, last_updated, canonical_user_id
    )
    VALUES (
      gen_random_uuid(), v_uid, 'USDC', current_balance, 0, NOW(), v_uid
    )
    ON CONFLICT (user_id, currency) DO NOTHING;

    SELECT available_balance
      INTO current_balance
      FROM public.sub_account_balances
     WHERE user_id = v_uid AND currency = 'USDC'
     FOR UPDATE;
  END IF;

  NEW.balance_before := current_balance;
  NEW.balance_after  := current_balance + NEW.amount;

  -- Update SAB as source of truth
  UPDATE public.sub_account_balances
     SET available_balance = NEW.balance_after,
         last_updated = NOW()
   WHERE user_id = v_uid AND currency = 'USDC';

  -- Mirror to canonical_users.usdc_balance
  UPDATE public.canonical_users cu
     SET usdc_balance = NEW.balance_after,
         updated_at = NOW()
   WHERE cu.canonical_user_id = v_uid
      OR cu.id::text = v_uid;

  RETURN NEW;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.apply_wallet_mutation(p_canonical_user_id text, p_currency text, p_amount numeric, p_reference_id text DEFAULT NULL::text, p_description text DEFAULT NULL::text, p_top_up_tx_id text DEFAULT NULL::text)
 RETURNS TABLE(ledger_id uuid, canonical_user_id text, currency text, amount numeric, balance_before numeric, balance_after numeric, available_balance numeric, top_up_tx_id text)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_user_id text;
  v_before numeric;
  v_after numeric;
  v_ledger_id uuid;
  v_tx_type text;
  v_top_up_tx_id text;
begin
  v_user_id := case when p_canonical_user_id ilike 'prize:pid:%'
                    then p_canonical_user_id
                    else 'prize:pid:' || p_canonical_user_id
               end;

  if p_amount = 0 then
    raise exception 'Amount must be non-zero';
  end if;

  if p_amount > 0 then
    v_tx_type := 'top_up';
    if p_top_up_tx_id is null or length(trim(p_top_up_tx_id)) = 0 then
      raise exception 'top_up_tx_id is required for top-ups';
    end if;
    v_top_up_tx_id := p_top_up_tx_id;
  else
    v_tx_type := 'entry';
    if p_top_up_tx_id is not null then
      raise exception 'top_up_tx_id must be null for debits/entries';
    end if;
    v_top_up_tx_id := null;
  end if;

  insert into sub_account_balances (canonical_user_id, currency, available_balance, pending_balance)
  values (v_user_id, p_currency, 0, 0)
  on conflict (canonical_user_id) do nothing;

  select available_balance
    into v_before
  from sub_account_balances
  where canonical_user_id = v_user_id and currency = p_currency
  for update;

  if v_before is null then
    insert into sub_account_balances (canonical_user_id, currency, available_balance, pending_balance)
    values (v_user_id, p_currency, 0, 0)
    on conflict do nothing;

    select available_balance
      into v_before
    from sub_account_balances
    where canonical_user_id = v_user_id and currency = p_currency
    for update;
  end if;

  v_after := v_before + p_amount;

  if v_after < 0 then
    raise exception 'Insufficient funds: % % would drop to %', v_user_id, p_currency, v_after
      using errcode = 'P0001';
  end if;

  insert into balance_ledger (
    id, canonical_user_id, transaction_type, amount, currency,
    balance_before, balance_after, reference_id, description, created_at, top_up_tx_id
  )
  values (
    gen_random_uuid(),
    v_user_id,
    v_tx_type,
    p_amount,
    p_currency,
    v_before,
    v_after,
    p_reference_id,
    coalesce(p_description, case when p_amount > 0 then 'Top up' else 'Execute balance payment' end),
    now(),
    v_top_up_tx_id
  )
  returning id into v_ledger_id;

  update sub_account_balances
  set available_balance = v_after,
      last_updated = now()
  where canonical_user_id = v_user_id and currency = p_currency;

  return query
  select v_ledger_id, v_user_id, p_currency, p_amount, v_before, v_after, v_after, v_top_up_tx_id;
end;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.auto_allocate_paid_tickets()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_ticket_count INTEGER;
  v_existing_tickets INTEGER;
  v_competition_id TEXT;
  v_user_id TEXT;
  v_canonical_user_id TEXT;
  v_wallet_address TEXT;
  v_payment_provider TEXT;
  v_tx_hash TEXT;
BEGIN
  -- Only process completed/confirmed payments
  IF NEW.status NOT IN ('completed', 'confirmed') OR NEW.payment_status NOT IN ('completed', 'confirmed') THEN
    RETURN NEW;
  END IF;

  -- Only process entry transactions (not top-ups)
  IF NEW.competition_id IS NULL THEN
    RETURN NEW;
  END IF;

  -- Get transaction details
  v_competition_id := NEW.competition_id;
  v_user_id := COALESCE(NEW.user_id, NEW.canonical_user_id);
  v_canonical_user_id := COALESCE(NEW.canonical_user_id, NEW.user_id);
  v_wallet_address := NEW.wallet_address;
  v_payment_provider := COALESCE(NEW.payment_provider, 'unknown');
  v_tx_hash := COALESCE(NEW.tx_id, NEW.id::text);
  v_ticket_count := COALESCE(NEW.ticket_count, 1);

  -- Check if tickets already exist for this transaction
  SELECT COUNT(*)
  INTO v_existing_tickets
  FROM tickets
  WHERE (transaction_hash = v_tx_hash OR tx_id = v_tx_hash)
    AND competition_id = v_competition_id;

  -- If no tickets exist but payment is completed, we need to allocate
  IF v_existing_tickets = 0 AND v_ticket_count > 0 THEN
    RAISE NOTICE '[AutoAllocate] Payment completed but no tickets found. TxID: %, Competition: %, User: %, TicketCount: %',
      v_tx_hash, v_competition_id, v_user_id, v_ticket_count;

    -- Create a pending_tickets entry for automatic allocation
    -- The confirm-pending-tickets function will process this
    INSERT INTO pending_tickets (
      user_id,
      canonical_user_id,
      wallet_address,
      competition_id,
      status,
      hold_minutes,
      expires_at,
      reservation_id,
      ticket_count,
      ticket_price,
      total_amount,
      session_id,
      payment_provider,
      transaction_hash,
      note
    )
    VALUES (
      v_user_id,
      v_canonical_user_id,
      v_wallet_address,
      v_competition_id,
      'pending',
      15, -- 15 minute hold
      NOW() + INTERVAL '15 minutes',
      gen_random_uuid(),
      v_ticket_count,
      COALESCE(NEW.amount / NULLIF(v_ticket_count, 0), 0),
      NEW.amount,
      NEW.id,
      v_payment_provider,
      v_tx_hash,
      'Auto-created by auto_allocate_paid_tickets trigger - payment succeeded but no tickets allocated'
    )
    ON CONFLICT DO NOTHING; -- Prevent duplicates if trigger fires multiple times

    RAISE NOTICE '[AutoAllocate] Created pending_tickets entry for auto-allocation. Session: %', NEW.id;

    -- Call confirm-pending-tickets via HTTP (background job)
    -- This will be handled by an edge function or cron job
    -- For now, just log and the reconcile-payments function will pick it up

  END IF;

  RETURN NEW;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.auto_debit_on_balance_order()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_amount numeric;
  v_tx json;
BEGIN
  IF (TG_OP = 'INSERT' OR TG_OP = 'UPDATE') AND
     (NEW.payment_method = 'balance' OR NEW.order_type = 'balance') AND
     (NEW.status ILIKE 'completed' OR COALESCE(NEW.payment_status,'') ILIKE 'paid%') THEN

    v_amount := COALESCE(NEW.amount_usd, NEW.amount);
    v_tx := public.debit_balance_and_confirm_tickets(
      NEW.user_id,
      NEW.id,
      NEW.competition_id,
      v_amount,
      md5(NEW.id::text || '-balance'),
      'USD'
    );
  END IF;
  RETURN NEW;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.auto_expire_reservations()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_grace_period_minutes INTEGER := 15; -- Default grace period
  v_hold_minutes INTEGER;
  v_time_since_creation INTERVAL;
  v_should_expire BOOLEAN := FALSE;
BEGIN
  -- Called on INSERT or UPDATE
  -- Only process if expires_at is set and status is pending
  IF NEW.expires_at IS NOT NULL AND NEW.status = 'pending' THEN
    
    -- Get the hold_minutes value (default to 15 if not set)
    v_hold_minutes := COALESCE(NEW.hold_minutes, v_grace_period_minutes);
    
    -- Calculate time since creation
    v_time_since_creation := NOW() - NEW.created_at;
    
    -- Determine if reservation should expire
    -- CRITICAL: NEVER expire if within hold_minutes window
    -- This protects active reservations from premature expiration
    IF NEW.expires_at < NOW() THEN
      -- Check if we're past the grace period
      IF v_time_since_creation > (v_hold_minutes || ' minutes')::INTERVAL THEN
        v_should_expire := TRUE;
      END IF;
    END IF;
    
    -- Only mark as expired if truly past the grace period
    IF v_should_expire THEN
      NEW.status := 'expired';
      RAISE NOTICE 'Reservation % expired after % minutes (hold window: % minutes)', 
        NEW.id, 
        EXTRACT(EPOCH FROM v_time_since_creation) / 60,
        v_hold_minutes;
    ELSE
      -- Log that we're protecting this reservation
      IF NEW.expires_at < NOW() THEN
        RAISE NOTICE 'Reservation % protected from expiration (within %min grace period, age: %min)', 
          NEW.id,
          v_hold_minutes,
          EXTRACT(EPOCH FROM v_time_since_creation) / 60;
      END IF;
    END IF;
  END IF;
  
  RETURN NEW;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.award_first_topup_bonus()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_first_tx_id uuid;
  v_first_amount numeric;
  v_bonus numeric;
  v_cu_id uuid;
  v_canonical_user_id text;
  v_wallet_address text;
  v_privy_user_id text;
BEGIN
  -- Only react to transitions to completed
  IF TG_OP <> 'UPDATE' OR (OLD.status = NEW.status) OR NEW.status <> 'completed' THEN
    RETURN NEW;
  END IF;

  -- Only deposits/top_up in USD sub-account
  IF NEW.transaction_type NOT IN ('deposit','top_up') OR NEW.currency IS NULL OR NEW.currency NOT ILIKE 'USD%' THEN
    RETURN NEW;
  END IF;

  -- Map user
  SELECT cu.id, cu.canonical_user_id, cu.wallet_address, cu.privy_user_id
    INTO v_cu_id, v_canonical_user_id, v_wallet_address, v_privy_user_id
  FROM public.canonical_users cu
  WHERE cu.id = NEW.user_id;

  IF v_cu_id IS NULL THEN
    -- No matching canonical user; nothing to do
    RETURN NEW;
  END IF;

  -- Skip if user already used bonus
  PERFORM 1 FROM public.canonical_users cu
   WHERE cu.id = v_cu_id AND cu.has_used_new_user_bonus = true;
  IF FOUND THEN
    RETURN NEW;
  END IF;

  -- Identify the true first completed USD deposit/top_up for this user
  SELECT ct.id, ct.amount
    INTO v_first_tx_id, v_first_amount
  FROM public.custody_transactions ct
  WHERE ct.user_id = v_cu_id
    AND ct.status = 'completed'
    AND ct.transaction_type IN ('deposit','top_up')
    AND ct.currency ILIKE 'USD%'
  ORDER BY ct.created_at ASC, ct.id ASC
  LIMIT 1;

  -- If none found or current row isn't the first, exit
  IF v_first_tx_id IS NULL OR v_first_tx_id <> NEW.id THEN
    RETURN NEW;
  END IF;

  -- Compute 50% bonus (no cap)
  v_bonus := COALESCE(v_first_amount, 0) * 0.5;
  IF v_bonus <= 0 THEN
    RETURN NEW;
  END IF;

  -- Atomically mark bonus used and credit balance
  UPDATE public.canonical_users cu
     SET bonus_balance = COALESCE(cu.bonus_balance, 0) + v_bonus,
         has_used_new_user_bonus = true,
         updated_at = now()
   WHERE cu.id = v_cu_id;

  -- Log user transaction with audit fields
  INSERT INTO public.user_transactions (
    user_id,
    canonical_user_id,
    wallet_address,
    user_privy_id,
    type,
    amount,
    currency,
    description
  ) VALUES (
    v_cu_id::text,
    v_canonical_user_id,
    v_wallet_address,
    v_privy_user_id,
    'bonus_credit',
    v_bonus,
    'USD',
    'First deposit 50% bonus'
  );

  RETURN NEW;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.award_first_topup_bonus(p_canonical_user_id text, p_topup_amount numeric, p_bonus_amount numeric, p_currency text DEFAULT 'USDC'::text, p_provider text DEFAULT 'topup'::text, p_tx_ref text DEFAULT NULL::text)
 RETURNS TABLE(balance_before numeric, balance_after numeric, bonus_applied boolean, bonus_amount numeric)
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_before numeric := 0;
  v_after numeric := 0;
  v_bonus_applied boolean := false;
  v_has_used boolean := false;
  v_existing_balance record;
  v_user_id uuid;
BEGIN
  IF p_topup_amount <= 0 THEN
    RAISE EXCEPTION 'Topup amount must be positive';
  END IF;
  IF p_bonus_amount < 0 THEN
    RAISE EXCEPTION 'Bonus amount cannot be negative';
  END IF;

  -- 1) Lock/seed sub_account_balances row
  LOOP
    BEGIN
      SELECT * INTO v_existing_balance
      FROM public.sub_account_balances
      WHERE canonical_user_id = p_canonical_user_id AND currency = p_currency
      FOR UPDATE;

      IF NOT FOUND THEN
        INSERT INTO public.sub_account_balances (canonical_user_id, currency, available_balance, pending_balance, last_updated)
        VALUES (p_canonical_user_id, p_currency, 0, 0, now())
        ON CONFLICT (canonical_user_id, currency) DO NOTHING;
        CONTINUE;
      END IF;

      EXIT;
    EXCEPTION WHEN unique_violation THEN
      CONTINUE;
    END;
  END LOOP;

  v_before := COALESCE(v_existing_balance.available_balance, 0);

  -- 2) Check and lock canonical_users row for first-bonus flag
  -- Seed canonical_users row if missing (by canonical_user_id), capturing its UUID id for potential FKs
  LOOP
    BEGIN
      SELECT id, has_used_new_user_bonus
      INTO v_user_id, v_has_used
      FROM public.canonical_users
      WHERE canonical_user_id = p_canonical_user_id
      FOR UPDATE;

      IF NOT FOUND THEN
        INSERT INTO public.canonical_users (canonical_user_id)
        VALUES (p_canonical_user_id)
        ON CONFLICT (canonical_user_id) DO NOTHING;
        CONTINUE;
      END IF;

      EXIT;
    EXCEPTION WHEN unique_violation THEN
      CONTINUE;
    END;
  END LOOP;

  -- 3) Apply top-up and first-time bonus exactly once
  v_after := v_before + p_topup_amount;

  IF NOT v_has_used AND p_bonus_amount > 0 THEN
    v_after := v_after + p_bonus_amount;
    v_bonus_applied := true;

    UPDATE public.canonical_users
    SET has_used_new_user_bonus = true,
        updated_at = now()
    WHERE id = v_user_id;

    -- Audit bonus award
    INSERT INTO public.bonus_award_audit (
      canonical_user_id,
      amount,
      currency,
      awarded_at,
      reason,
      sub_account_balance_before,
      sub_account_balance_after,
      note
    ) VALUES (
      p_canonical_user_id,
      p_bonus_amount,
      p_currency,
      now(),
      'first_topup_bonus',
      v_before,
      v_after,
      p_tx_ref
    );
  END IF;

  -- 4) Persist balance
  UPDATE public.sub_account_balances
  SET available_balance = v_after,
      last_updated = now()
  WHERE canonical_user_id = p_canonical_user_id AND currency = p_currency;

  -- 5) Log transactions: topup and bonus (if applied)
  INSERT INTO public.user_transactions (
    user_id,
    canonical_user_id,
    type,
    amount,
    currency,
    balance_before,
    balance_after,
    status,
    description,
    metadata
  ) VALUES (
    p_canonical_user_id, -- storing canonical id in user_id for compatibility with your schema
    p_canonical_user_id,
    'topup',
    p_topup_amount,
    p_currency,
    v_before,
    v_before + p_topup_amount,
    'completed',
    'Balance top-up',
    jsonb_build_object('provider', p_provider, 'tx_ref', p_tx_ref)
  );

  IF v_bonus_applied THEN
    INSERT INTO public.user_transactions (
      user_id,
      canonical_user_id,
      type,
      amount,
      currency,
      balance_before,
      balance_after,
      status,
      description,
      metadata
    ) VALUES (
      p_canonical_user_id,
      p_canonical_user_id,
      'bonus_credit',
      p_bonus_amount,
      p_currency,
      v_before + p_topup_amount,
      v_after,
      'completed',
      'First-time top-up bonus',
      jsonb_build_object('provider', p_provider, 'tx_ref', p_tx_ref)
    );
  END IF;

  RETURN QUERY SELECT v_before, v_after, v_bonus_applied, CASE WHEN v_bonus_applied THEN p_bonus_amount ELSE 0 END;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.award_first_topup_bonus_via_webhook(p_provider_event_id text, p_preferred_currency text DEFAULT 'USDC'::text, p_bonus_amount numeric DEFAULT NULL::numeric)
 RETURNS TABLE(success boolean, bonus_applied boolean, bonus_amount numeric, balance_before numeric, balance_after numeric, canonical_user_id text, credited_amount numeric, credited_currency text)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_row record;
  v_is_first boolean;
  v_amount numeric;
  v_currency text;
  v_bonus numeric;
  v_before numeric;
  v_after numeric;
  v_res record;
BEGIN
  SELECT e.id,
         e.provider,
         e.event_type,
         e.event_id,
         e.status,
         (e.payload->'event'->'data'->'metadata'->>'user_id')::text AS canonical_user_id,
         COALESCE(
           NULLIF((e.payload->'event'->'data'->'pricing'->'settlement'->>'amount')::numeric, NULL),
           (e.payload->'event'->'data'->'pricing'->'local'->>'amount')::numeric
         ) AS amt,
         COALESCE(
           NULLIF((e.payload->'event'->'data'->'pricing'->'settlement'->>'currency')::text, ''),
           (e.payload->'event'->'data'->'pricing'->'local'->>'currency')::text
         ) AS cur
  INTO v_row
  FROM public.payment_webhook_events e
  WHERE e.provider = 'coinbase-commerce'
    AND e.event_id = p_provider_event_id
    AND e.event_type = 'charge:confirmed'
  LIMIT 1;

  IF NOT FOUND OR v_row.canonical_user_id IS NULL OR v_row.amt IS NULL THEN
    RETURN QUERY SELECT false, false, 0::numeric, NULL::numeric, NULL::numeric, NULL::text, NULL::numeric, NULL::text;
    RETURN;
  END IF;

  IF v_row.status = 'confirmed' OR v_row.status = 'COMPLETED' THEN
    SELECT sab.available_balance INTO v_after
    FROM sub_account_balances sab
    WHERE sab.canonical_user_id = v_row.canonical_user_id
      AND sab.currency = COALESCE(p_preferred_currency, v_row.cur)
    LIMIT 1;

    RETURN QUERY SELECT true, false, 0::numeric, NULL::numeric, COALESCE(v_after,0), v_row.canonical_user_id, NULL::numeric, COALESCE(p_preferred_currency, v_row.cur);
    RETURN;
  END IF;

  v_currency := COALESCE(p_preferred_currency, v_row.cur);
  v_amount := v_row.amt;

  SELECT NOT EXISTS (
    SELECT 1
    FROM public.payment_webhook_events pe
    WHERE pe.provider = 'coinbase-commerce'
      AND pe.event_type = 'charge:confirmed'
      AND (pe.payload->'event'->'data'->'metadata'->>'type') IN ('topup','TOPUP')
      AND (pe.payload->'event'->'data'->'metadata'->>'user_id') = v_row.canonical_user_id
      AND pe.event_id <> p_provider_event_id
  ) INTO v_is_first;

  v_bonus := COALESCE(p_bonus_amount, ROUND(v_amount * 0.5, 2));

  SELECT * INTO v_res
  FROM credit_sub_account_balance(
    v_row.canonical_user_id, v_amount, v_currency, p_provider_event_id, 'Top-up (principal)'
  );

  IF NOT v_res.success THEN
    RETURN QUERY SELECT false, false, 0::numeric, v_res.previous_balance, v_res.new_balance, v_row.canonical_user_id, v_amount, v_currency;
    RETURN;
  END IF;

  v_before := v_res.previous_balance;
  v_after := v_res.new_balance;

  IF v_is_first AND v_bonus > 0 THEN
    SELECT * INTO v_res
    FROM credit_sub_account_balance(
      v_row.canonical_user_id, v_bonus, v_currency, p_provider_event_id, 'First top-up bonus (50%)'
    );
    IF v_res.success THEN
      v_after := v_res.new_balance;
      UPDATE public.payment_webhook_events
      SET status = 'confirmed',
          processed_at = now(),
          signature_valid = COALESCE(signature_valid, true)
      WHERE event_id = p_provider_event_id;
      RETURN QUERY SELECT true, true, v_bonus, v_before, v_after, v_row.canonical_user_id, v_amount, v_currency;
      RETURN;
    END IF;
  END IF;

  UPDATE public.payment_webhook_events
  SET status = 'confirmed',
      processed_at = now(),
      signature_valid = COALESCE(signature_valid, true)
  WHERE event_id = p_provider_event_id;

  RETURN QUERY SELECT true, false, 0::numeric, v_before, v_after, v_row.canonical_user_id, v_amount, v_currency;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.award_welcome_bonus(p_wallet text, p_threshold numeric DEFAULT 3)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_user record;
  v_sub record;
  v_prev numeric := 0;
  v_new numeric := 0;
  v_bonus numeric := 0;
  v_already_awarded boolean := false;
BEGIN
  -- Find the user by wallet
  SELECT cu.* INTO v_user
  FROM public.canonical_users cu
  WHERE cu.wallet_address = p_wallet
  LIMIT 1;
  IF NOT FOUND THEN RETURN; END IF;

  -- Latest USD balance row for this wallet
  SELECT sab.* INTO v_sub
  FROM public.sub_account_balances sab
  WHERE sab.wallet_address = p_wallet AND sab.currency = 'USD'
  ORDER BY sab.last_updated DESC NULLS LAST
  LIMIT 1;
  IF NOT FOUND THEN RETURN; END IF;

  v_new := COALESCE(v_sub.available_balance, 0);
  v_prev := GREATEST(0, COALESCE(v_new,0) - COALESCE(v_sub.pending_balance,0)); -- fallback if no old row; not reliable

  -- Check flag and prior tx for idempotency
  v_already_awarded := COALESCE(v_user.has_used_new_user_bonus, false);
  IF v_already_awarded = false THEN
    SELECT EXISTS (
      SELECT 1 FROM public.user_transactions ut
      WHERE ut.wallet_address = p_wallet AND ut.type = 'welcome_bonus'
    ) INTO v_already_awarded;
  END IF;
  IF v_already_awarded THEN RETURN; END IF;

  -- Qualify only if balance > threshold
  IF v_new <= p_threshold THEN RETURN; END IF;

  -- Compute the user's first deposit amount. We approximate as v_new when crossing threshold,
  -- since trigger calls on the first time balance becomes > threshold.
  -- Award 50% of that amount.
  v_bonus := ROUND(v_new * 0.5, 2);
  IF v_bonus <= 0 THEN RETURN; END IF;

  -- Insert transaction
  INSERT INTO public.user_transactions (
    user_id, canonical_user_id, wallet_address, type, amount, currency, description
  ) VALUES (
    v_user.uid, v_user.canonical_user_id, p_wallet, 'welcome_bonus', v_bonus, 'USD', '50% welcome bonus on first deposit'
  );

  -- Update user bonus balance and flag
  UPDATE public.canonical_users
  SET bonus_balance = COALESCE(bonus_balance, 0) + v_bonus,
      has_used_new_user_bonus = true,
      updated_at = now()
  WHERE id = v_user.id;

  -- Audit
  INSERT INTO public.bonus_award_audit (
    wallet_address, canonical_user_id, amount, currency, reason, sub_account_balance_before, sub_account_balance_after, note
  ) VALUES (
    p_wallet, v_user.canonical_user_id, v_bonus, 'USD', 'first_topup_over_threshold_50_percent', NULL, v_new, 'Auto-award 50% via award_welcome_bonus()'
  );
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.award_welcome_bonus(p_wallet text, p_threshold numeric DEFAULT 3, p_bonus numeric DEFAULT 100)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_user record;
  v_sub record;
  v_already_awarded boolean := false;
BEGIN
  -- Find the user by wallet
  SELECT cu.* INTO v_user
  FROM public.canonical_users cu
  WHERE cu.wallet_address = p_wallet
  LIMIT 1;

  IF NOT FOUND THEN
    -- No user for this wallet; nothing to do
    RETURN;
  END IF;

  -- Check sub account latest balance for this wallet (USD only)
  SELECT sab.* INTO v_sub
  FROM public.sub_account_balances sab
  WHERE sab.wallet_address = p_wallet AND sab.currency = 'USD'
  ORDER BY sab.last_updated DESC NULLS LAST
  LIMIT 1;

  IF NOT FOUND THEN
    RETURN; -- No balance row; skip
  END IF;

  -- Check if already awarded via flag
  v_already_awarded := COALESCE(v_user.has_used_new_user_bonus, false);

  -- If not flagged, double-check no existing welcome_bonus tx for safety
  IF v_already_awarded = false THEN
    SELECT EXISTS (
      SELECT 1 FROM public.user_transactions ut
      WHERE ut.wallet_address = p_wallet AND ut.type = 'welcome_bonus'
    ) INTO v_already_awarded;
  END IF;

  -- Qualifies only if available_balance > threshold and not already awarded
  IF COALESCE(v_sub.available_balance, 0) > p_threshold AND v_already_awarded = false THEN
    -- Insert transaction
    INSERT INTO public.user_transactions (
      user_id, canonical_user_id, wallet_address, type, amount, currency, description
    ) VALUES (
      v_user.uid, v_user.canonical_user_id, p_wallet, 'welcome_bonus', p_bonus, 'USD', 'One-time welcome bonus on first top-up'
    );

    -- Update user bonus balance and flag
    UPDATE public.canonical_users
    SET bonus_balance = COALESCE(bonus_balance, 0) + p_bonus,
        has_used_new_user_bonus = true,
        updated_at = now()
    WHERE id = v_user.id;

    -- Audit
    INSERT INTO public.bonus_award_audit (
      wallet_address, canonical_user_id, amount, currency, reason, sub_account_balance_before, sub_account_balance_after, note
    ) VALUES (
      p_wallet, v_user.canonical_user_id, p_bonus, 'USD', 'first_topup_over_threshold', NULL, v_sub.available_balance, 'Auto-award via award_welcome_bonus()'
    );
  END IF;

  RETURN;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.balance_ledger_sync_wallet()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_delta numeric;
  v_before numeric;
  v_after numeric;
BEGIN
  IF NEW.canonical_user_id IS NULL THEN
    RETURN NEW; -- nothing we can do
  END IF;

  IF NEW.amount IS NULL OR NEW.amount = 0 THEN
    RETURN NEW;
  END IF;

  v_delta := public._wallet_delta_from_txn(NEW.transaction_type, NEW.amount);

  SELECT balance_before, balance_after INTO v_before, v_after
  FROM public._apply_wallet_delta(NEW.canonical_user_id, COALESCE(NEW.currency,'USD'), v_delta);

  -- Backfill before/after if not set
  IF NEW.balance_before IS NULL OR NEW.balance_after IS NULL THEN
    UPDATE public.balance_ledger
    SET balance_before = COALESCE(NEW.balance_before, v_before),
        balance_after  = COALESCE(NEW.balance_after,  v_after)
    WHERE id = NEW.id;
  END IF;

  RETURN NEW;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.block_specific_canonical_user()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF (TG_OP = 'INSERT' AND NEW.canonical_user_id = TG_ARGV[0]) OR
     (TG_OP = 'UPDATE' AND NEW.canonical_user_id = TG_ARGV[0]) THEN
    RAISE EXCEPTION 'Insert/Update blocked for canonical_user_id: %', TG_ARGV[0];
  END IF;
  RETURN NEW;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.canonical_users_normalize()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  -- Normalize all wallet address fields using util function for consistency
  IF NEW.wallet_address IS NOT NULL THEN
    NEW.wallet_address := util.normalize_evm_address(NEW.wallet_address);
  END IF;
  
  IF NEW.base_wallet_address IS NOT NULL THEN
    NEW.base_wallet_address := util.normalize_evm_address(NEW.base_wallet_address);
  END IF;
  
  IF NEW.eth_wallet_address IS NOT NULL THEN
    NEW.eth_wallet_address := util.normalize_evm_address(NEW.eth_wallet_address);
  END IF;

  -- Auto-generate canonical_user_id if missing and we have a wallet address
  -- IMPORTANT: Skip this if canonical_user_id is a temporary placeholder (prize:pid:temp<N>)
  IF NEW.canonical_user_id IS NULL AND COALESCE(NEW.wallet_address, NEW.base_wallet_address, NEW.eth_wallet_address) IS NOT NULL THEN
    NEW.canonical_user_id := 'prize:pid:' || COALESCE(NEW.wallet_address, NEW.base_wallet_address, NEW.eth_wallet_address);
  END IF;

  RETURN NEW;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.canonical_users_normalize_before_write()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  -- Normalize wallet_address using util function
  IF NEW.wallet_address IS NOT NULL THEN
    NEW.wallet_address := util.normalize_evm_address(NEW.wallet_address);
  END IF;

  -- Set canonical_user_id based on wallet_address
  IF NEW.wallet_address IS NOT NULL THEN
    NEW.canonical_user_id := 'prize:pid:' || NEW.wallet_address;
  -- IMPORTANT: Only extract wallet from canonical_user_id if it's NOT a temporary placeholder
  ELSIF NEW.canonical_user_id IS NOT NULL AND NEW.canonical_user_id NOT LIKE 'prize:pid:temp%' THEN
    IF POSITION('prize:pid:' IN NEW.canonical_user_id) = 1 THEN
      -- Use SUBSTRING to safely extract the wallet address part
      NEW.wallet_address := SUBSTRING(NEW.canonical_user_id FROM 11);
      -- Only normalize if it looks like a valid address (starts with 0x)
      IF NEW.wallet_address LIKE '0x%' THEN
        NEW.wallet_address := util.normalize_evm_address(NEW.wallet_address);
        NEW.canonical_user_id := 'prize:pid:' || NEW.wallet_address;
      END IF;
    END IF;
  END IF;

  RETURN NEW;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.check_and_mark_competition_sold_out(p_competition_id text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_total INTEGER;
  v_sold INTEGER;
  v_is_sold_out BOOLEAN;
BEGIN
  SELECT total_tickets, sold_tickets INTO v_total, v_sold
  FROM competitions
  WHERE id = p_competition_id::UUID OR uid = p_competition_id::UUID;

  v_is_sold_out := v_sold >= v_total;

  IF v_is_sold_out THEN
    UPDATE competitions
    SET status = 'sold_out'
    WHERE id = p_competition_id::UUID OR uid = p_competition_id::UUID;
  END IF;

  RETURN jsonb_build_object(
    'is_sold_out', v_is_sold_out,
    'total_tickets', v_total,
    'sold_tickets', v_sold
  );
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.check_and_mark_competition_sold_out(p_competition_id uuid)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_total int;
  v_sold_reserved int;
  v_remaining int;
  v_status text;
BEGIN
  SELECT total_tickets, status INTO v_total, v_status
  FROM public.competitions WHERE id = p_competition_id FOR UPDATE;
  IF v_total IS NULL THEN
    RETURN false; -- competition not found
  END IF;

  SELECT COALESCE(COUNT(*),0) INTO v_sold_reserved
  FROM public.tickets
  WHERE competition_id = p_competition_id AND status IN ('sold','reserved');

  v_remaining := GREATEST(v_total - v_sold_reserved, 0);

  IF v_remaining = 0 AND v_status IN ('active','live','drawing') THEN
    UPDATE public.competitions
    SET status = 'sold_out', updated_at = NOW()
    WHERE id = p_competition_id AND status IN ('active','live','drawing');
  END IF;

  RETURN v_remaining = 0;
END;$function$
"

definition: "CREATE OR REPLACE FUNCTION public.check_balance_health(p_canonical_user_id text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_canonical_balance NUMERIC;
  v_sub_account_balance NUMERIC;
  v_ledger_balance NUMERIC;
  v_difference NUMERIC;
  v_status TEXT;
BEGIN
  SELECT usdc_balance INTO v_canonical_balance
  FROM public.canonical_users
  WHERE canonical_user_id = p_canonical_user_id;

  SELECT available_balance INTO v_sub_account_balance
  FROM public.sub_account_balances
  WHERE canonical_user_id = p_canonical_user_id AND (currency IS NULL OR currency = 'USD' OR currency = 'USDC');

  SELECT 
    COALESCE(SUM(CASE 
      WHEN transaction_type IN ('deposit', 'bonus', 'credit') THEN amount
      WHEN transaction_type IN ('purchase', 'debit', 'withdrawal') THEN -amount
      ELSE 0
    END), 0) INTO v_ledger_balance
  FROM public.balance_ledger
  WHERE canonical_user_id = p_canonical_user_id;

  v_difference := ABS(COALESCE(v_canonical_balance, 0) - COALESCE(v_sub_account_balance, 0));

  IF v_difference < 0.01 THEN
    v_status := 'healthy';
  ELSIF v_difference < 1.00 THEN
    v_status := 'minor_discrepancy';
  ELSE
    v_status := 'major_discrepancy';
  END IF;

  RETURN jsonb_build_object(
    'status', v_status,
    'canonical_balance', COALESCE(v_canonical_balance, 0),
    'sub_account_balance', COALESCE(v_sub_account_balance, 0),
    'ledger_calculated_balance', COALESCE(v_ledger_balance, 0),
    'difference', v_difference,
    'needs_sync', v_difference >= 0.01
  );
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.check_first_deposit_bonus_eligibility(p_canonical_user_id text)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_user RECORD;
BEGIN
  SELECT c.* INTO v_user
  FROM canonical_users c
  WHERE c.canonical_user_id = p_canonical_user_id
     OR (is_uuid(p_canonical_user_id) AND c.id = p_canonical_user_id::uuid)
  LIMIT 1;

  IF v_user IS NULL THEN
    RETURN jsonb_build_object('eligible', false, 'reason', 'User not found');
  END IF;

  IF COALESCE(v_user.has_used_new_user_bonus, false) THEN
    RETURN jsonb_build_object('eligible', false, 'reason', 'Bonus already used', 'has_used_bonus', true);
  END IF;

  RETURN jsonb_build_object('eligible', true, 'bonus_percentage', 50, 'has_used_bonus', false, 'message', 'User is eligible for 50% first deposit bonus');
END;$function$
"

definition: "CREATE OR REPLACE FUNCTION public.claim_prize(p_competition_id uuid, p_user_wallet_address text)
 RETURNS boolean
 LANGUAGE plpgsql
AS $function$
DECLARE
    user_id UUID;
    winner_record RECORD;
BEGIN
    -- Get user ID
    SELECT id INTO user_id 
    FROM public.users 
    WHERE wallet_address = p_user_wallet_address;

    IF user_id IS NULL THEN
        RAISE EXCEPTION 'User not found';
    END IF;

    -- Get winner record
    SELECT * INTO winner_record
    FROM public.winners
    WHERE competition_id = p_competition_id 
    AND user_id = user_id 
    AND claimed = FALSE;

    IF NOT FOUND THEN
        RAISE EXCEPTION 'No unclaimed prize found for this user';
    END IF;

    -- Mark as claimed (blockchain tx will be updated separately)
    UPDATE public.winners 
    SET claimed = TRUE,
        claimed_at = NOW()
    WHERE id = winner_record.id;

    RETURN TRUE;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.cleanup_expired_idempotency()
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_deleted INTEGER;
BEGIN
  DELETE FROM payment_idempotency
  WHERE expires_at < NOW();

  GET DIAGNOSTICS v_deleted = ROW_COUNT;

  RETURN v_deleted;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.cleanup_expired_reservations(p_grace_period_minutes integer DEFAULT 15)
 RETURNS TABLE(expired_count integer, protected_count integer)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_expired_count INTEGER := 0;
  v_protected_count INTEGER := 0;
  v_cutoff_time TIMESTAMPTZ;
BEGIN
  v_cutoff_time := NOW() - (p_grace_period_minutes || ' minutes')::INTERVAL;

  SELECT COUNT(*) INTO v_protected_count
  FROM public.pending_tickets
  WHERE status = 'pending'
    AND expires_at < NOW()
    AND created_at > v_cutoff_time;

  UPDATE public.pending_tickets
  SET 
    status = 'expired',
    updated_at = NOW(),
    note = COALESCE(note || ' | ', '') || 'Auto-expired by cleanup function'
  WHERE status = 'pending'
    AND expires_at < NOW()
    AND created_at <= v_cutoff_time;

  GET DIAGNOSTICS v_expired_count = ROW_COUNT;

  RAISE NOTICE 'Cleanup complete: % expired, % protected (within %min grace period)', 
    v_expired_count, v_protected_count, p_grace_period_minutes;

  RETURN QUERY SELECT v_expired_count, v_protected_count;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.cleanup_orphaned_pending_tickets()
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  deleted_count INTEGER := 0;
  v_rows INTEGER := 0;
BEGIN
  -- Delete items for tickets with missing user/canonical id
  WITH del_items AS (
    DELETE FROM public.pending_ticket_items
    WHERE pending_ticket_id IN (
      SELECT pt.id
      FROM public.pending_tickets pt
      LEFT JOIN public.canonical_users cu ON pt.canonical_user_id = cu.canonical_user_id
      WHERE cu.canonical_user_id IS NULL
         OR pt.canonical_user_id IS NULL
         OR pt.user_id IS NULL
    ) RETURNING 1
  ) SELECT COUNT(*) INTO v_rows FROM del_items; 
  deleted_count := deleted_count + COALESCE(v_rows,0);

  -- Delete tickets with missing user/canonical id
  WITH del_t AS (
    DELETE FROM public.pending_tickets
    WHERE id IN (
      SELECT pt.id
      FROM public.pending_tickets pt
      LEFT JOIN public.canonical_users cu ON pt.canonical_user_id = cu.canonical_user_id
      WHERE cu.canonical_user_id IS NULL
         OR pt.canonical_user_id IS NULL
         OR pt.user_id IS NULL
    ) RETURNING 1
  ) SELECT COUNT(*) INTO v_rows FROM del_t; 
  deleted_count := deleted_count + COALESCE(v_rows,0);

  -- Delete items for tickets with missing competition
  WITH del_items2 AS (
    DELETE FROM public.pending_ticket_items
    WHERE pending_ticket_id IN (
      SELECT pt.id
      FROM public.pending_tickets pt
      LEFT JOIN public.competitions c ON pt.competition_id = c.id
      WHERE c.id IS NULL
    ) RETURNING 1
  ) SELECT COUNT(*) INTO v_rows FROM del_items2; 
  deleted_count := deleted_count + COALESCE(v_rows,0);

  -- Delete tickets with missing competition
  WITH del_t2 AS (
    DELETE FROM public.pending_tickets pt
    USING public.pending_tickets pt2
    LEFT JOIN public.competitions c ON pt2.competition_id = c.id
    WHERE pt.id = pt2.id AND c.id IS NULL
    RETURNING 1
  ) SELECT COUNT(*) INTO v_rows FROM del_t2; 
  deleted_count := deleted_count + COALESCE(v_rows,0);

  RETURN deleted_count;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.competitions_sync_num_winners()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  -- Before insert/update, if only one is provided, copy to the other
  IF TG_OP IN ('INSERT','UPDATE') THEN
    IF NEW.num_winners IS NULL AND NEW.winner_count IS NOT NULL THEN
      NEW.num_winners := NEW.winner_count;
    ELSIF NEW.winner_count IS NULL AND NEW.num_winners IS NOT NULL THEN
      NEW.winner_count := NEW.num_winners;
    END IF;
  END IF;
  RETURN NEW;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.competitions_sync_tickets_sold()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF TG_OP IN ('INSERT','UPDATE') THEN
    IF NEW.tickets_sold IS NULL AND NEW.sold_tickets IS NOT NULL THEN
      NEW.tickets_sold := NEW.sold_tickets;
    ELSIF NEW.sold_tickets IS NULL AND NEW.tickets_sold IS NOT NULL THEN
      NEW.sold_tickets := NEW.tickets_sold;
    END IF;
  END IF;
  RETURN NEW;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.complete_topup_on_webhook_ref()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
BEGIN
  -- Only for coinbase topups
  IF (COALESCE(NEW.provider,'') = 'coinbase' AND COALESCE(NEW.type,'') = 'topup') THEN
    -- If webhook_ref is present and status is not already completed, flip to completed
    IF COALESCE(NEW.webhook_ref, '') <> '' AND NEW.status <> 'completed' THEN
      NEW.status := 'completed';
      NEW.completed_at := COALESCE(NEW.completed_at, NOW());
    END IF;
  END IF;
  RETURN NEW;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.confirm_pending_tickets_with_balance(p_reservation_id uuid, p_canonical_user_id text)
 RETURNS TABLE(inserted_ticket_ids uuid[], ticket_numbers integer[], total_cost numeric, new_available_balance numeric, entry_id uuid)
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
declare
  v_res pending_tickets%rowtype;
  v_items_count int;
  v_ticket_numbers int[];
  v_competition_id uuid;
  v_ticket_price numeric;
  v_total_cost numeric;
  v_bal sub_account_balances%rowtype;
  v_balance_before numeric;
  v_balance_after numeric;
  v_tx_id text;
  v_inserted_ids uuid[];
  v_entry_id uuid;
  v_now timestamptz := now();
begin
  -- Validate canonical_user_id shape (lowercase)
  if p_canonical_user_id is null or p_canonical_user_id !~ '^prize:pid:0x[a-f0-9]{40}$' then
    raise exception 'Invalid canonical_user_id format';
  end if;

  -- 1) Lock reservation
  select *
  into v_res
  from pending_tickets
  where id = p_reservation_id
  for update;

  if not found then
    raise exception 'Reservation % not found', p_reservation_id;
  end if;

  if v_res.status <> 'pending' then
    raise exception 'Reservation % is not pending (status=%)', p_reservation_id, v_res.status;
  end if;

  if v_res.expires_at <= v_now then
    raise exception 'Reservation % has expired at %', p_reservation_id, v_res.expires_at;
  end if;

  -- Ensure ownership if set
  if v_res.canonical_user_id is not null and v_res.canonical_user_id <> p_canonical_user_id then
    raise exception 'Reservation % does not belong to user %', p_reservation_id, p_canonical_user_id;
  end if;

  v_competition_id := v_res.competition_id;

  -- 2) Lock items and gather ticket numbers
  select array_agg(i.ticket_number order by i.ticket_number), count(*)
  into v_ticket_numbers, v_items_count
  from pending_ticket_items i
  where i.pending_ticket_id = p_reservation_id
  for update;

  if coalesce(v_items_count, 0) = 0 then
    if v_res.ticket_numbers is not null and array_length(v_res.ticket_numbers,1) > 0 then
      v_ticket_numbers := v_res.ticket_numbers;
      v_items_count := array_length(v_res.ticket_numbers,1);
    else
      raise exception 'Reservation % has no pending ticket items or ticket_numbers', p_reservation_id;
    end if;
  end if;

  -- 3) Price and total
  v_ticket_price := coalesce(
    v_res.ticket_price,
    (select c.ticket_price from competitions c where c.id = v_competition_id)
  );
  if v_ticket_price is null then
    raise exception 'Ticket price not resolvable for competition %', v_competition_id;
  end if;

  v_total_cost := v_ticket_price * v_items_count;

  -- 4) Lock and verify balance
  select *
  into v_bal
  from sub_account_balances
  where canonical_user_id = p_canonical_user_id
    and currency = 'USD'
  for update;

  if not found then
    raise exception 'No sub_account_balances row for % (USD)', p_canonical_user_id;
  end if;

  v_balance_before := v_bal.available_balance;

  if v_balance_before < v_total_cost then
    raise exception 'Insufficient balance: have %, need %', v_balance_before, v_total_cost;
  end if;

  v_balance_after := v_balance_before - v_total_cost;

  -- 5) Deduct balance immediately
  update sub_account_balances
  set available_balance = v_balance_after,
      last_updated = v_now
  where id = v_bal.id;

  -- 6) Write balance ledger
  insert into balance_ledger (
    canonical_user_id, transaction_type, amount, currency,
    balance_before, balance_after, reference_id, description, created_at
  )
  values (
    p_canonical_user_id, 'debit', v_total_cost, 'USD',
    v_balance_before, v_balance_after, p_reservation_id::text, 'Ticket purchase (balance confirmation)', v_now
  );

  -- 7) Insert tickets with deterministic tx_id
  v_tx_id := 'balance:' || p_reservation_id::text;

  with ins as (
    insert into tickets (
      competition_id,
      ticket_number,
      status,
      canonical_user_id,
      wallet_address,
      purchase_price,
      payment_provider,
      payment_amount,
      purchased_at,
      purchase_date,
      pending_ticket_id,
      tx_id
    )
    select
      v_competition_id,
      tnum,
      'sold',
      p_canonical_user_id,
      v_res.wallet_address,
      v_ticket_price,
      'balance',
      v_ticket_price,
      v_now,
      v_now,
      p_reservation_id,
      v_tx_id
    from unnest(v_ticket_numbers) as tnum
    returning id
  )
  select array_agg(id) into v_inserted_ids from ins;

  if v_inserted_ids is null or array_length(v_inserted_ids,1) <> v_items_count then
    raise exception 'Inserted tickets mismatch: expected %, got %', v_items_count, coalesce(array_length(v_inserted_ids,1),0);
  end if;

  -- 8) Write tickets_sold for each ticket
  insert into tickets_sold (competition_id, ticket_number, purchaser_id, sold_at)
  select v_competition_id, tnum, p_canonical_user_id, v_now
  from unnest(v_ticket_numbers) as tnum;

  -- 9) Upsert competition_entries (no VRF fields)
  with data as (
    select
      v_competition_id as competition_id,
      p_canonical_user_id as canonical_user_id,
      v_items_count as add_count,
      v_total_cost as add_amount,
      array_to_string(v_ticket_numbers, ',') as add_csv,
      v_now as ts,
      v_res.wallet_address as wallet_address
  )
  insert into competition_entries (
    id,
    canonical_user_id,
    competition_id,
    wallet_address,
    tickets_count,
    ticket_numbers_csv,
    amount_spent,
    payment_methods,
    latest_purchase_at,
    created_at,
    updated_at
  )
  select
    gen_random_uuid(),
    d.canonical_user_id,
    d.competition_id,
    d.wallet_address,
    d.add_count,
    d.add_csv,
    d.add_amount,
    'balance',
    d.ts,
    d.ts,
    d.ts
  from data d
  on conflict (competition_id, canonical_user_id)
  do update
  set tickets_count = competition_entries.tickets_count + excluded.tickets_count,
      amount_spent = coalesce(competition_entries.amount_spent, 0) + excluded.amount_spent,
      latest_purchase_at = excluded.latest_purchase_at,
      updated_at = excluded.updated_at,
      payment_methods = case
        when competition_entries.payment_methods is null or position('balance' in competition_entries.payment_methods) = 0
          then coalesce(competition_entries.payment_methods || ',balance', 'balance')
        else competition_entries.payment_methods
      end,
      ticket_numbers_csv = case
        when competition_entries.ticket_numbers_csv is null or length(competition_entries.ticket_numbers_csv) = 0
          then excluded.ticket_numbers_csv
        else competition_entries.ticket_numbers_csv || ',' || excluded.ticket_numbers_csv
      end
  returning competition_entries.id into v_entry_id;

  -- 10) Mark reservation confirmed
  update pending_tickets
  set status = 'confirmed',
      confirmed_at = v_now,
      updated_at = v_now,
      total_amount = v_total_cost
  where id = p_reservation_id;

  -- 11) Return
  inserted_ticket_ids := v_inserted_ids;
  ticket_numbers := v_ticket_numbers;
  total_cost := v_total_cost;
  new_available_balance := v_balance_after;
  entry_id := v_entry_id;
  return next;
end;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.confirm_pending_to_sold(p_reservation_id uuid, p_transaction_hash text DEFAULT NULL::text, p_payment_provider text DEFAULT 'balance'::text, p_wallet_address text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_reservation RECORD;
  v_ticket_num INTEGER;
  v_tickets_inserted INTEGER := 0;
  v_join_uid UUID;
BEGIN
  -- Lock and fetch reservation
  SELECT * INTO v_reservation
  FROM pending_tickets
  WHERE id = p_reservation_id
  FOR UPDATE NOWAIT;

  IF v_reservation IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'Reservation not found');
  END IF;

  IF v_reservation.status = 'confirmed' THEN
    RETURN jsonb_build_object('success', true, 'already_confirmed', true);
  END IF;

  IF v_reservation.status NOT IN ('pending', 'confirming') THEN
    RETURN jsonb_build_object('success', false, 'error', 'Invalid reservation status: ' || v_reservation.status);
  END IF;

  IF v_reservation.expires_at < NOW() THEN
    UPDATE pending_tickets SET status = 'expired', updated_at = NOW() WHERE id = p_reservation_id;
    RETURN jsonb_build_object('success', false, 'error', 'Reservation expired', 'expired_at', v_reservation.expires_at);
  END IF;

  -- Mark as confirming
  UPDATE pending_tickets SET status = 'confirming', updated_at = NOW() WHERE id = p_reservation_id;

  -- Insert tickets using privy_user_id column (TEXT)
  IF v_reservation.ticket_numbers IS NOT NULL THEN
    FOREACH v_ticket_num IN ARRAY v_reservation.ticket_numbers
    LOOP
      BEGIN
        INSERT INTO tickets (competition_id, ticket_number, privy_user_id, purchase_price, payment_tx_hash, pending_ticket_id, created_at)
        VALUES (v_reservation.competition_id, v_ticket_num, v_reservation.user_id, v_reservation.ticket_price, p_transaction_hash, p_reservation_id, NOW());
        v_tickets_inserted := v_tickets_inserted + 1;
      EXCEPTION WHEN unique_violation THEN NULL;
      END;
    END LOOP;
  END IF;

  -- Create joincompetition entry
  v_join_uid := gen_random_uuid();
  INSERT INTO joincompetition (uid, competitionid, userid, walletaddress, privy_user_id, numberoftickets, ticketnumbers, amountspent, chain, transactionhash, purchasedate, created_at)
  VALUES (
    v_join_uid::TEXT,
    v_reservation.competition_id::text,
    v_reservation.user_id,
    COALESCE(p_wallet_address, ''),
    v_reservation.user_id,
    COALESCE(array_length(v_reservation.ticket_numbers, 1), 0),
    array_to_string(COALESCE(v_reservation.ticket_numbers, ARRAY[]::INTEGER[]), ','),
    COALESCE(v_reservation.total_amount, 0),
    COALESCE(p_payment_provider, 'balance'),
    COALESCE(p_transaction_hash, v_reservation.id::text),
    NOW(),
    NOW()
  );

  -- Mark confirmed
  UPDATE pending_tickets SET status = 'confirmed', confirmed_at = NOW(), updated_at = NOW() WHERE id = p_reservation_id;

  RETURN jsonb_build_object('success', true, 'tickets_inserted', v_tickets_inserted, 'ticket_count', COALESCE(array_length(v_reservation.ticket_numbers, 1), 0));
EXCEPTION WHEN lock_not_available THEN
  RETURN jsonb_build_object('success', false, 'error', 'Reservation locked by another process');
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.create_entry_charge(p_canonical_user_id text, p_competition_id uuid, p_entry_price numeric, p_entry_count integer, p_payment_method text, p_tx_ref text DEFAULT NULL::text, p_metadata jsonb DEFAULT '{}'::jsonb)
 RETURNS uuid
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_total numeric := p_entry_price * p_entry_count;
  v_order_id uuid := gen_random_uuid();
  v_ok boolean;
BEGIN
  -- Optional: validate competition exists
  PERFORM 1 FROM public.competitions WHERE id = p_competition_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'Competition % not found', p_competition_id; END IF;

  IF p_payment_method = 'balance' THEN
    v_ok := public.debit_user_balance(p_canonical_user_id, v_total, 'USD');
    IF NOT v_ok THEN
      RAISE EXCEPTION 'INSUFFICIENT_FUNDS';
    END IF;
  END IF;

  -- Record transaction for audit
  INSERT INTO public.user_transactions (
    id, user_id, canonical_user_id, wallet_address, type, amount, currency,
    competition_id, order_id, description, status, metadata
  ) VALUES (
    gen_random_uuid(), NULL, p_canonical_user_id, NULL,
    CASE WHEN p_payment_method='balance' THEN 'debit' ELSE 'crypto' END,
    v_total, 'USD', p_competition_id, v_order_id,
    'Competition entry', 'completed',
    COALESCE(p_metadata, '{}'::jsonb) || jsonb_build_object('provider', p_payment_method, 'tx_ref', p_tx_ref)
  );

  -- Record order (optional)
  INSERT INTO public.orders (id, user_id, competition_id, amount, currency, status, payment_provider, payment_method, ticket_count)
  VALUES (v_order_id, p_canonical_user_id, p_competition_id, v_total, 'USDC', 'completed', p_payment_method, p_payment_method, p_entry_count);

  RETURN v_order_id;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.create_order_for_reservation(p_pending_ticket_id uuid, p_payment_provider text, p_currency text DEFAULT 'USDC'::text)
 RETURNS TABLE(order_id uuid, amount numeric, ticket_count integer)
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_amt numeric;
  v_cnt int;
  v_comp uuid;
  v_order uuid := gen_random_uuid();
BEGIN
  SELECT total_amount, ticket_count, competition_id
    INTO v_amt, v_cnt, v_comp
  FROM public.pending_tickets
  WHERE id = p_pending_ticket_id AND status = 'pending' AND (expires_at IS NULL OR expires_at > now());
  IF NOT FOUND THEN RAISE EXCEPTION 'reservation_not_found_or_expired'; END IF;

  INSERT INTO public.orders(id, user_id, competition_id, amount, currency, status, ticket_count, payment_provider)
  VALUES (v_order, (SELECT wallet_address FROM public.pending_tickets WHERE id=p_pending_ticket_id), v_comp, v_amt, p_currency, 'pending', v_cnt, p_payment_provider);

  INSERT INTO public.order_tickets(order_id, ticket_number)
  SELECT v_order, ticket_number FROM public.pending_ticket_items WHERE pending_ticket_id = p_pending_ticket_id;

  RETURN QUERY SELECT v_order, v_amt, v_cnt;
END; $function$
"

definition: "CREATE OR REPLACE FUNCTION public.create_user_if_not_exists(p_canonical_user_id text, p_wallet_address text, p_email text DEFAULT NULL::text)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_user_id UUID;
  v_existing_id UUID;
BEGIN
  SELECT id INTO v_existing_id
  FROM canonical_users
  WHERE canonical_user_id = p_canonical_user_id
     OR wallet_address = p_wallet_address
  LIMIT 1;

  IF FOUND THEN
    RETURN v_existing_id;
  END IF;

  INSERT INTO canonical_users (
    canonical_user_id, wallet_address, base_wallet_address, 
    eth_wallet_address, privy_user_id, email, username
  ) VALUES (
    p_canonical_user_id, p_wallet_address, p_wallet_address,
    p_wallet_address, p_wallet_address, LOWER(p_email), 
    COALESCE(p_email, 'user_' || substring(p_wallet_address from 3 for 6))
  )
  RETURNING id INTO v_user_id;

  RETURN v_user_id;
EXCEPTION WHEN OTHERS THEN
  RETURN NULL;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.credit_balance_topup(p_user_id text, p_amount numeric, p_tx_ref text, p_provider text, p_privy_user_id text, p_wallet_address text, p_canonical_user_id text, p_notes text)
 RETURNS jsonb
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_currency text := 'USDC';
  v_bonus_amount numeric := 0;
  v_bonus_applied boolean := false;
  v_prev_available numeric := 0;
  v_new_available numeric := 0;
  v_sub_row_exists boolean := false;
BEGIN
  -- Idempotency: if we already have a tx with same provider+tx_ref, return ok
  IF EXISTS (
    SELECT 1 FROM public.user_transactions ut
    WHERE (ut.metadata->>'provider') = p_provider
      AND (ut.metadata->>'tx_ref') = p_tx_ref
  ) THEN
    RETURN jsonb_build_object('status','ok','idempotent',true,'provider',p_provider,'tx_ref',p_tx_ref);
  END IF;

  -- Lock or initialize the sub account row
  SELECT true, COALESCE(s.available_balance,0)
  INTO v_sub_row_exists, v_prev_available
  FROM public.sub_account_balances s
  WHERE s.canonical_user_id = p_canonical_user_id AND s.currency = v_currency
  FOR UPDATE;

  IF NOT FOUND THEN
    v_sub_row_exists := false;
    v_prev_available := 0;
  END IF;

  -- First deposit if row doesn't exist: 50% bonus, no cap
  IF v_sub_row_exists = false THEN
    v_bonus_amount := p_amount * 0.5;
    v_bonus_applied := (v_bonus_amount > 0);

    -- Insert the sub account with initial available = amount + bonus
    INSERT INTO public.sub_account_balances(
      user_id, currency, available_balance, pending_balance, last_updated, canonical_user_id, privy_user_id, wallet_address, canonical_user_id_norm
    ) VALUES (
      p_user_id, v_currency, p_amount + v_bonus_amount, 0, now(), p_canonical_user_id, p_privy_user_id, p_wallet_address, p_canonical_user_id
    );

    v_new_available := p_amount + v_bonus_amount;
  ELSE
    -- Subsequent deposits: no bonus, just upsert/update available_balance
    v_bonus_amount := 0;
    v_bonus_applied := false;

    UPDATE public.sub_account_balances s
    SET available_balance = COALESCE(s.available_balance,0) + p_amount,
        last_updated = now(),
        privy_user_id = COALESCE(p_privy_user_id, s.privy_user_id),
        wallet_address = COALESCE(p_wallet_address, s.wallet_address)
    WHERE s.canonical_user_id = p_canonical_user_id AND s.currency = v_currency;

    SELECT COALESCE(s.available_balance,0) INTO v_new_available
    FROM public.sub_account_balances s
    WHERE s.canonical_user_id = p_canonical_user_id AND s.currency = v_currency;
  END IF;

  -- Ledger entry for topup
  INSERT INTO public.balance_ledger(
    canonical_user_id, transaction_type, amount, currency, balance_before, balance_after, reference_id, description, top_up_tx_id
  ) VALUES (
    p_canonical_user_id, 'topup', p_amount, v_currency, v_prev_available, v_new_available, COALESCE(p_tx_ref, gen_random_uuid()::text), p_notes, p_tx_ref
  )
  ON CONFLICT (reference_id) DO NOTHING;

  -- Detailed user transaction audit
  INSERT INTO public.user_transactions (
    user_id, canonical_user_id, wallet_address, type, amount, currency, balance_before, balance_after,
    description, status, user_privy_id, metadata, notes, completed_at, posted_to_balance
  ) VALUES (
    p_user_id, p_canonical_user_id, p_wallet_address, 'topup', p_amount, v_currency, v_prev_available, v_new_available,
    CONCAT('Top-up via ', p_provider, CASE WHEN v_bonus_applied THEN ' (+50% first-deposit bonus)' ELSE '' END),
    'completed', p_privy_user_id,
    jsonb_build_object('provider', p_provider, 'tx_ref', p_tx_ref, 'bonus_amount', v_bonus_amount, 'bonus_applied', v_bonus_applied),
    p_notes, now(), true
  );

  RETURN jsonb_build_object(
    'status','ok',
    'amount', p_amount,
    'currency', v_currency,
    'provider', p_provider,
    'tx_ref', p_tx_ref,
    'bonus_amount', v_bonus_amount,
    'bonus_applied', v_bonus_applied,
    'balance_before', v_prev_available,
    'balance_after', v_new_available
  );
EXCEPTION
  WHEN unique_violation THEN
    RETURN jsonb_build_object('status','ok','idempotent',true,'provider',p_provider,'tx_ref',p_tx_ref);
  WHEN OTHERS THEN
    -- Fallback path: try legacy helper for bonus then re-run minimal balance changes if needed
    BEGIN
      PERFORM public.credit_sub_account_with_bonus(p_canonical_user_id, p_amount, v_currency);
    EXCEPTION WHEN OTHERS THEN
      -- ignore fallback failure
    END;
    RETURN jsonb_build_object('status','error','message', SQLERRM);
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.credit_sub_account_balance_simple(p_canonical_user_id text, p_currency text, p_amount numeric)
 RETURNS TABLE(balance_before numeric, balance_after numeric)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_before numeric;
  v_after numeric;
BEGIN
  IF p_amount <= 0 THEN
    RAISE EXCEPTION 'Amount must be positive';
  END IF;

  LOOP
    BEGIN
      SELECT available_balance
      INTO v_before
      FROM public.sub_account_balances
      WHERE canonical_user_id = p_canonical_user_id
        AND currency = p_currency
      FOR UPDATE;

      IF NOT FOUND THEN
        INSERT INTO public.sub_account_balances (canonical_user_id, currency, available_balance, pending_balance, last_updated)
        VALUES (p_canonical_user_id, p_currency, 0, 0, now())
        ON CONFLICT (canonical_user_id, currency) DO NOTHING;
        CONTINUE;
      END IF;

      EXIT;
    EXCEPTION WHEN unique_violation THEN
      CONTINUE;
    END;
  END LOOP;

  IF v_before IS NULL THEN
    v_before := 0;
  END IF;

  v_after := v_before + p_amount;

  UPDATE public.sub_account_balances
  SET available_balance = v_after,
      last_updated = now()
  WHERE canonical_user_id = p_canonical_user_id
    AND currency = p_currency;

  -- FIX: ALSO update canonical_users.usdc_balance when currency is USD
  -- This keeps both tables in sync and fixes the balance discrepancy
  IF p_currency = 'USD' THEN
    UPDATE public.canonical_users
    SET usdc_balance = COALESCE(usdc_balance, 0) + p_amount,
        updated_at = now()
    WHERE canonical_user_id = p_canonical_user_id;
  END IF;

  RETURN QUERY SELECT v_before, v_after;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.credit_sub_account_with_bonus(p_canonical_user_id text, p_amount numeric, p_currency text DEFAULT 'USD'::text)
 RETURNS TABLE(success boolean, previous_balance numeric, new_balance numeric, bonus_amount numeric, bonus_applied boolean)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_user RECORD;
  v_has_used_bonus BOOLEAN;
  v_bonus_amount NUMERIC := 0;
  v_total_credit NUMERIC := 0;
  v_current_balance NUMERIC := 0;
  v_new_balance NUMERIC := 0;
  v_can_log BOOLEAN := false;
BEGIN
  SELECT c.* INTO v_user
  FROM canonical_users c
  WHERE c.canonical_user_id = p_canonical_user_id
     OR (is_uuid(p_canonical_user_id) AND c.id = p_canonical_user_id::uuid)
  LIMIT 1;

  IF v_user IS NULL THEN
    RETURN QUERY SELECT false, 0::NUMERIC, 0::NUMERIC, 0::NUMERIC, false;
    RETURN;
  END IF;

  v_has_used_bonus := COALESCE(v_user.has_used_new_user_bonus, false);
  v_current_balance := COALESCE(v_user.usdc_balance, 0);

  IF v_has_used_bonus = false THEN
    v_bonus_amount := COALESCE(p_amount,0) * 0.5;
    v_total_credit := COALESCE(p_amount,0) + v_bonus_amount;
  ELSE
    v_total_credit := COALESCE(p_amount,0);
  END IF;

  v_new_balance := v_current_balance + v_total_credit;

  UPDATE canonical_users
     SET usdc_balance = v_new_balance,
         has_used_new_user_bonus = CASE WHEN v_bonus_amount > 0 THEN true ELSE has_used_new_user_bonus END,
         updated_at = NOW()
   WHERE id = v_user.id;

  SELECT EXISTS (
    SELECT 1 FROM pg_catalog.pg_class cls
    JOIN pg_catalog.pg_namespace ns ON ns.oid = cls.relnamespace
    WHERE ns.nspname = 'public' AND cls.relname = 'balance_history' AND cls.relkind = 'r'
  ) INTO v_can_log;

  IF v_can_log THEN
    IF COALESCE(p_amount,0) > 0 THEN
      INSERT INTO public.balance_history (user_id, amount, type, reason, balance_before, balance_after, created_at)
      VALUES (v_user.id, p_amount, 'credit', 'topup', v_current_balance, v_current_balance + p_amount, NOW());
    END IF;

    IF v_bonus_amount > 0 THEN
      INSERT INTO public.balance_history (user_id, amount, type, reason, balance_before, balance_after, created_at)
      VALUES (v_user.id, v_bonus_amount, 'credit', '50% first deposit bonus', v_current_balance + p_amount, v_new_balance, NOW());
    END IF;
  ELSE
    RAISE NOTICE 'balance_history table not found in public schema — skipping audit logs';
  END IF;

  RETURN QUERY SELECT true, v_current_balance, v_new_balance, v_bonus_amount, v_bonus_amount > 0;
END;$function$
"

definition: "CREATE OR REPLACE FUNCTION public.cu_normalize_and_enforce()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  -- Normalize all wallet fields using util function for consistency
  IF NEW.wallet_address IS NOT NULL THEN
    NEW.wallet_address := util.normalize_evm_address(NEW.wallet_address);
  END IF;
  
  IF NEW.base_wallet_address IS NOT NULL THEN
    NEW.base_wallet_address := util.normalize_evm_address(NEW.base_wallet_address);
  END IF;
  
  IF NEW.eth_wallet_address IS NOT NULL THEN
    NEW.eth_wallet_address := util.normalize_evm_address(NEW.eth_wallet_address);
  END IF;

  -- If primary wallet is missing but alternates exist, pick first non-null
  IF NEW.wallet_address IS NULL THEN
    IF NEW.base_wallet_address IS NOT NULL THEN
      NEW.wallet_address := NEW.base_wallet_address;
    ELSIF NEW.eth_wallet_address IS NOT NULL THEN
      NEW.wallet_address := NEW.eth_wallet_address;
    END IF;
  END IF;

  -- Enforce canonical_user_id when we have a wallet
  -- IMPORTANT: Only set if NOT a temporary placeholder
  IF NEW.wallet_address IS NOT NULL AND (NEW.canonical_user_id IS NULL OR NEW.canonical_user_id NOT LIKE 'prize:pid:temp%') THEN
    NEW.canonical_user_id := 'prize:pid:' || NEW.wallet_address;
  END IF;

  RETURN NEW;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.debit_user_balance(p_canonical_user_id text, p_amount numeric, p_currency text DEFAULT 'USD'::text)
 RETURNS boolean
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_current numeric;
BEGIN
  -- Lock the balance row
  SELECT available_balance INTO v_current
  FROM public.sub_account_balances
  WHERE canonical_user_id = p_canonical_user_id AND currency = p_currency
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Balance row not found for % %', p_canonical_user_id, p_currency;
  END IF;

  IF v_current < p_amount THEN
    RETURN FALSE; -- insufficient funds
  END IF;

  UPDATE public.sub_account_balances
  SET available_balance = available_balance - p_amount,
      last_updated = now()
  WHERE canonical_user_id = p_canonical_user_id AND currency = p_currency;

  RETURN TRUE;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.enforce_user_transactions_balance()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  seed_balance numeric := 0;
  running_prior numeric := 0;
  v_is_completed boolean;
BEGIN
  -- Only enforce when canonical_user_id and currency are present
  IF NEW.canonical_user_id IS NULL OR NEW.currency IS NULL THEN
    RETURN NEW;
  END IF;

  v_is_completed :=
    (lower(COALESCE(NEW.status,'')) IN ('completed','confirmed')
     OR lower(COALESCE(NEW.payment_status,'')) IN ('completed','confirmed'));

  IF NEW.type = 'topup' THEN
    -- Seed from sub_account_balances
    SELECT sab.available_balance
      INTO seed_balance
    FROM public.sub_account_balances sab
    WHERE sab.canonical_user_id = NEW.canonical_user_id
      AND sab.currency = NEW.currency
    ORDER BY sab.last_updated DESC NULLS LAST
    LIMIT 1;

    seed_balance := COALESCE(seed_balance, 0);

    -- Sum prior topups for this user/currency strictly before this row's created_at/id
    SELECT COALESCE(SUM(t.amount), 0) INTO running_prior
    FROM public.user_transactions t
    WHERE t.canonical_user_id = NEW.canonical_user_id
      AND t.currency = NEW.currency
      AND t.type = 'topup'
      AND (t.created_at < COALESCE(NEW.created_at, now())
           OR (t.created_at = COALESCE(NEW.created_at, now()) AND t.id < COALESCE(NEW.id, gen_random_uuid())));

    NEW.balance_before := seed_balance + running_prior;
    NEW.balance_after  := NEW.balance_before + COALESCE(NEW.amount, 0);

    -- CRITICAL: only mark posted when truly completed
    NEW.posted_to_balance := v_is_completed;
  ELSE
    NEW.balance_before := COALESCE(OLD.balance_before, NEW.balance_before);
    NEW.balance_after  := COALESCE(OLD.balance_after, NEW.balance_after);
  END IF;

  RETURN NEW;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.ensure_canonical_user(p_email text DEFAULT NULL::text, p_wallet_address text DEFAULT NULL::text, p_base_wallet_address text DEFAULT NULL::text, p_eth_wallet_address text DEFAULT NULL::text, p_privy_user_id text DEFAULT NULL::text, p_username text DEFAULT NULL::text, p_avatar_url text DEFAULT NULL::text, p_country text DEFAULT NULL::text, p_first_name text DEFAULT NULL::text, p_last_name text DEFAULT NULL::text, p_telegram_handle text DEFAULT NULL::text)
 RETURNS canonical_users
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_email text := nullif(lower(trim(p_email)), '');
  v_wallet text := nullif(lower(trim(p_wallet_address)), '');
  v_base_wallet text := nullif(lower(trim(p_base_wallet_address)), '');
  v_eth_wallet text := nullif(lower(trim(p_eth_wallet_address)), '');
  v_privy text := nullif(trim(p_privy_user_id), '');
  v_username text := nullif(trim(p_username), '');
  v_avatar text := nullif(trim(p_avatar_url), '');
  v_country text := nullif(trim(p_country), '');
  v_first text := nullif(trim(p_first_name), '');
  v_last text := nullif(trim(p_last_name), '');
  v_tg text := nullif(trim(p_telegram_handle), '');
  v_found canonical_users;
  v_cuid text;
begin
  -- Try to find existing canonical user by strongest identifiers
  select * into v_found from public.canonical_users cu
   where (v_email is not null and cu.email = v_email)
      or (v_privy is not null and cu.privy_user_id = v_privy)
      or (v_wallet is not null and cu.wallet_address = v_wallet)
      or (v_base_wallet is not null and cu.base_wallet_address = v_base_wallet)
      or (v_eth_wallet is not null and cu.eth_wallet_address = v_eth_wallet)
  limit 1;

  if v_found.id is not null then
    -- Merge non-null provided fields into the existing row
    update public.canonical_users cu set
      email = coalesce(v_email, cu.email),
      wallet_address = coalesce(v_wallet, cu.wallet_address),
      base_wallet_address = coalesce(v_base_wallet, cu.base_wallet_address),
      eth_wallet_address = coalesce(v_eth_wallet, cu.eth_wallet_address),
      privy_user_id = coalesce(v_privy, cu.privy_user_id),
      username = coalesce(v_username, cu.username),
      avatar_url = coalesce(v_avatar, cu.avatar_url),
      country = coalesce(v_country, cu.country),
      first_name = coalesce(v_first, cu.first_name),
      last_name = coalesce(v_last, cu.last_name),
      telegram_handle = coalesce(v_tg, cu.telegram_handle),
      updated_at = now()
    where cu.id = v_found.id
    returning * into v_found;

    return v_found;
  end if;

  -- Build canonical_user_id deterministically if a wallet exists
  if v_wallet is not null then
    v_cuid := 'prize:pid:' || v_wallet;
  elsif v_base_wallet is not null then
    v_cuid := 'prize:pid:' || v_base_wallet;
  elsif v_eth_wallet is not null then
    v_cuid := 'prize:pid:' || v_eth_wallet;
  else
    -- No wallet: generate a placeholder canonical id using a generated uuid suffix
    v_cuid := 'prize:pid:' || lpad(replace(encode(gen_random_bytes(20), 'hex'), '\n', ''), 42, '0');
  end if;

  insert into public.canonical_users (
    canonical_user_id, uid, privy_user_id, email,
    wallet_address, base_wallet_address, eth_wallet_address,
    username, avatar_url, country, first_name, last_name, telegram_handle
  ) values (
    v_cuid, gen_random_uuid()::text, v_privy, v_email,
    v_wallet, v_base_wallet, v_eth_wallet,
    v_username, v_avatar, v_country, v_first, v_last, v_tg
  )
  returning * into v_found;

  return v_found;
exception when unique_violation then
  -- In case of race: re-select and merge
  select * into v_found from public.canonical_users cu
   where (v_email is not null and cu.email = v_email)
      or (v_privy is not null and cu.privy_user_id = v_privy)
      or (v_wallet is not null and cu.wallet_address = v_wallet)
      or (v_base_wallet is not null and cu.base_wallet_address = v_base_wallet)
      or (v_eth_wallet is not null and cu.eth_wallet_address = v_eth_wallet)
  limit 1;

  if v_found.id is null then
    raise; -- bubble up if truly unexpected
  end if;

  update public.canonical_users cu set
      email = coalesce(v_email, cu.email),
      wallet_address = coalesce(v_wallet, cu.wallet_address),
      base_wallet_address = coalesce(v_base_wallet, cu.base_wallet_address),
      eth_wallet_address = coalesce(v_eth_wallet, cu.eth_wallet_address),
      privy_user_id = coalesce(v_privy, cu.privy_user_id),
      username = coalesce(v_username, cu.username),
      avatar_url = coalesce(v_avatar, cu.avatar_url),
      country = coalesce(v_country, cu.country),
      first_name = coalesce(v_first, cu.first_name),
      last_name = coalesce(v_last, cu.last_name),
      telegram_handle = coalesce(v_tg, cu.telegram_handle),
      updated_at = now()
    where cu.id = v_found.id
    returning * into v_found;

  return v_found;
end;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.ensure_sub_account_balance_row(p_canonical text, p_currency text)
 RETURNS uuid
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_currency text := COALESCE(p_currency, 'USDC');
  v_id uuid;
BEGIN
  -- Normalize currency so USD and USDC don't create two rows
  IF v_currency IN ('USD','USDC') THEN
    v_currency := 'USDC';
  END IF;

  -- Return existing row id if present
  SELECT id INTO v_id
  FROM public.sub_account_balances
  WHERE canonical_user_id = p_canonical
    AND currency = v_currency
  LIMIT 1;

  IF v_id IS NOT NULL THEN
    RETURN v_id;
  END IF;

  -- Insert missing row; handle concurrent insert race
  BEGIN
    INSERT INTO public.sub_account_balances (
      id, user_id, currency, available_balance, pending_balance, last_updated, canonical_user_id
    )
    VALUES (
      gen_random_uuid(), NULL, v_currency, 0, 0, NOW(), p_canonical
    )
    RETURNING id INTO v_id;
  EXCEPTION WHEN unique_violation THEN
    SELECT id INTO v_id
    FROM public.sub_account_balances
    WHERE canonical_user_id = p_canonical
      AND currency = v_currency
    LIMIT 1;
  END;

  RETURN v_id;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.enter_competition(p_canonical_user_id text, p_competition_id uuid, p_ticket_numbers integer[], p_price numeric)
 RETURNS TABLE(ticket_id uuid, ticket_number integer, new_balance numeric)
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
declare
  v_cost numeric := (coalesce(cardinality(p_ticket_numbers),0) * p_price);
  v_balance_before numeric;
  v_balance_after numeric;
  v_now timestamptz := now();
  v_ticket_id uuid;
  v_comp_total int;
  v_comp_sold int;
begin
  if cardinality(p_ticket_numbers) = 0 then
    raise exception 'No tickets provided';
  end if;

  -- lock balance row for this canonical user
  update public.sub_account_balances sab
    set last_updated = v_now
  where sab.canonical_user_id = p_canonical_user_id
  returning sab.available_balance into v_balance_before;

  if not found then
    raise exception 'Balance not found for %', p_canonical_user_id;
  end if;

  if v_balance_before is null or v_balance_before < v_cost then
    raise exception 'Insufficient balance. Need %, have %', v_cost, v_balance_before;
  end if;

  -- reserve or sell tickets atomically
  foreach ticket_number in array p_ticket_numbers loop
    -- prevent double sell; prefer updating existing row if present
    update public.tickets t
      set status = 'sold',
          purchased_at = v_now,
          purchase_date = v_now,
          payment_amount = p_price,
          is_active = true
    where t.competition_id = p_competition_id
      and t.ticket_number = ticket_number
      and t.status <> 'sold'
    returning t.id into v_ticket_id;

    if not found then
      raise exception 'Ticket % is not available', ticket_number;
    end if;

    v_balance_before := v_balance_before - p_price;

    -- return row per ticket
    v_balance_after := v_balance_before;
    ticket_id := v_ticket_id;
    ticket_number := ticket_number;
    new_balance := v_balance_after;
    return next;
  end loop;

  -- deduct balance once (already decremented per loop in v_balance_before)
  update public.sub_account_balances sab
    set available_balance = v_balance_after,
        last_updated = v_now
  where sab.canonical_user_id = p_canonical_user_id;

  -- ledger
  insert into public.user_transactions(
    user_id, canonical_user_id, type, amount, currency, balance_before, balance_after,
    competition_id, description, status, created_at, metadata
  ) values (
    null, p_canonical_user_id, 'debit', v_cost, 'USDC', v_balance_after + v_cost, v_balance_after,
    p_competition_id, 'Competition entry', 'completed', v_now,
    jsonb_build_object('tickets', p_ticket_numbers)
  );

  -- sync denormalized counter from tickets table
  select count(*)::int into v_comp_sold
  from public.tickets t
  where t.competition_id = p_competition_id and t.status = 'sold' and t.is_active = true;

  update public.competitions c
  set tickets_sold = v_comp_sold, updated_at = v_now
  where c.id = p_competition_id;

end;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.enter_competition_and_deduct(p_competition_id uuid, p_canonical_user_id text, p_quantity integer)
 RETURNS TABLE(sold_count integer, charged_amount numeric, new_balance numeric, ticket_numbers integer[])
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$DECLARE
  v_competition_id uuid := p_competition_id::uuid;
  v_price numeric;
  v_balance numeric;
  v_now timestamptz := now();
  v_assigned int[] := '{}';
  v_sold int := 0;
  v_balance_id uuid;
BEGIN
  -- Validate inputs
  if p_quantity <= 0 then
    raise exception 'invalid_quantity' using errcode = '22023';
  end if;
  if position('prize:pid:0x' in lower(p_canonical_user_id)) <> 1 then
    raise exception 'invalid_canonical_user_id, expected prize:pid:0x…' using errcode = '22023';
  end if;

  -- Get price & lock competition row
  select ticket_price into v_price from public.competitions where id = p_competition_id for update;
  if v_price is null then
    raise exception 'competition_not_found' using errcode = '22023';
  end if;

  -- Lock the exact sub-account balance row by canonical_user_id (USD only)
  select id, available_balance into v_balance_id, v_balance
  from public.sub_account_balances
  where canonical_user_id = p_canonical_user_id and currency = 'USD'
  for update;

  if v_balance_id is null then
    raise exception 'sub_account_not_found' using errcode = '22023';
  end if;

  if coalesce(v_balance,0) < (v_price * p_quantity) then
    raise exception 'insufficient_balance' using errcode = '22023';
  end if;

  -- Compute available ticket numbers (exclude sold + active holds)
  v_assigned := array(
    with unavail as (
      select t.ticket_number
      from public.tickets t
      where t.competition_id = p_competition_id
        and t.is_active = true
        and t.status = 'sold'
      union
      select h.ticket_number
      from public.pending_ticket_items h
      where h.competition_id = p_competition_id
        and h.status = 'pending'
        and (h.expires_at is null or h.expires_at > v_now)
    ), all_nums as (
      select generate_series(1, (select c.total_tickets from public.competitions c where c.id = p_competition_id))::int as n
    )
    select n from all_nums a
    where not exists (select 1 from unavail u where u.ticket_number = a.n)
    order by n
    limit p_quantity
  );

  if coalesce(array_length(v_assigned,1),0) < p_quantity then
    raise exception 'no_available_tickets' using errcode = '22023';
  end if;

  -- Insert sold tickets with correct canonical_user_id and purchase_price
  insert into public.tickets (
    competition_id, ticket_number, status, is_active, purchased_at, purchase_price, canonical_user_id
  )
  select p_competition_id, unnest(v_assigned), 'sold', true, v_now, v_price, p_canonical_user_id;

  v_sold := coalesce(array_length(v_assigned,1),0);

  -- Deduct balance atomically
  update public.sub_account_balances
  set available_balance = coalesce(available_balance,0) - (v_price * v_sold),
      last_updated = v_now
  where id = v_balance_id
  returning available_balance into v_balance;

  -- Update sold counter
  update public.competitions
  set tickets_sold = coalesce(tickets_sold,0) + v_sold,
      updated_at = v_now
  where id = p_competition_id;

  return query select v_sold::int, (v_price * v_sold)::numeric, v_balance::numeric, v_assigned;
END;$function$
"

definition: "CREATE OR REPLACE FUNCTION public.exec_sql(sql_query text)
 RETURNS json
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE result JSON;
BEGIN
  EXECUTE sql_query;
  RETURN json_build_object('success', true, 'message', 'SQL executed successfully');
EXCEPTION WHEN OTHERS THEN
  RETURN json_build_object('success', false, 'error', SQLERRM, 'detail', SQLSTATE);
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.execute_balance_payment(p_amount numeric, p_competition_id uuid, p_idempotency_key text, p_reservation_id uuid, p_selected_tickets integer[], p_ticket_count integer, p_user_identifier text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_user_canonical_id text;
  v_currency text := 'USD';
  v_balance_before numeric;
  v_balance_after numeric;
  v_sub_balance_id uuid;
  v_existing jsonb;
  v_result jsonb := '{}'::jsonb;
  v_pending record;
  v_ticket_price numeric;
  v_csv_existing text;
  v_now timestamptz := now();
  v_join_id uuid;
  v_ticket int;
BEGIN
  -- Idempotency check
  SELECT result INTO v_existing
  FROM public.payment_idempotency
  WHERE idempotency_key = p_idempotency_key;
  IF FOUND AND v_existing IS NOT NULL THEN
    RETURN v_existing || jsonb_build_object('idempotent', true);
  END IF;

  -- Resolve canonical user id from provided identifier
  IF p_user_identifier ~ '^prize:pid:0x[a-f0-9]{40}$' THEN
    v_user_canonical_id := p_user_identifier;
  ELSE
    SELECT canonical_user_id INTO v_user_canonical_id
    FROM public.canonical_users
    WHERE primary_wallet_address = p_user_identifier
       OR wallet_address = p_user_identifier
       OR email = p_user_identifier
       OR uid = p_user_identifier
    ORDER BY created_at DESC
    LIMIT 1;
  END IF;
  IF v_user_canonical_id IS NULL THEN
    RAISE EXCEPTION 'Could not resolve user from identifier %', p_user_identifier USING ERRCODE = '22023';
  END IF;

  -- Load and lock reservation
  SELECT * INTO v_pending
  FROM public.pending_tickets
  WHERE reservation_id = p_reservation_id
    AND competition_id = p_competition_id
    AND (canonical_user_id = v_user_canonical_id OR canonical_user_id IS NULL)
    AND status IN ('pending','confirming')
  FOR UPDATE;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'Valid pending reservation not found (reservation %, competition %, user %)', p_reservation_id, p_competition_id, v_user_canonical_id;
  END IF;

  -- Validate counts, tickets, amount
  IF v_pending.ticket_count IS DISTINCT FROM p_ticket_count THEN
    RAISE EXCEPTION 'ticket_count mismatch: pending %, got %', v_pending.ticket_count, p_ticket_count;
  END IF;
  IF v_pending.ticket_numbers IS DISTINCT FROM p_selected_tickets THEN
    RAISE EXCEPTION 'selected_tickets mismatch';
  END IF;
  v_ticket_price := COALESCE(v_pending.ticket_price, (SELECT ticket_price FROM public.competitions WHERE id = p_competition_id));
  IF v_ticket_price IS NULL THEN
    RAISE EXCEPTION 'ticket_price not found for competition %', p_competition_id;
  END IF;
  IF COALESCE(v_pending.total_amount, v_ticket_price * p_ticket_count) <> p_amount THEN
    RAISE EXCEPTION 'amount mismatch: expected %, got %', COALESCE(v_pending.total_amount, v_ticket_price * p_ticket_count), p_amount;
  END IF;

  -- Lock sub_account_balance row for update
  SELECT id, available_balance INTO v_sub_balance_id, v_balance_before
  FROM public.sub_account_balances
  WHERE canonical_user_id = v_user_canonical_id AND currency = v_currency
  FOR UPDATE;
  IF v_sub_balance_id IS NULL THEN
    RAISE EXCEPTION 'Balance account not found for % in %', v_user_canonical_id, v_currency USING ERRCODE = '22023';
  END IF;
  IF COALESCE(v_balance_before,0) < p_amount THEN
    RAISE EXCEPTION 'Insufficient balance: have %, need %', v_balance_before, p_amount USING ERRCODE = '22023';
  END IF;

  -- Deduct balance
  UPDATE public.sub_account_balances
  SET available_balance = available_balance - p_amount,
      last_updated = v_now
  WHERE id = v_sub_balance_id;
  SELECT available_balance INTO v_balance_after FROM public.sub_account_balances WHERE id = v_sub_balance_id;

  -- Insert ledger entry as "entry"
  INSERT INTO public.balance_ledger (
    id, canonical_user_id, transaction_type, amount, currency, balance_before, balance_after, reference_id, description, created_at
  ) VALUES (
    gen_random_uuid(), v_user_canonical_id, 'entry', p_amount, v_currency, v_balance_before, v_balance_after, p_idempotency_key,
    'Execute balance payment', v_now
  );

  -- Confirm reservation
  UPDATE public.pending_tickets
  SET status = 'confirmed', confirmed_at = v_now, updated_at = v_now, idempotency_key = COALESCE(v_pending.idempotency_key, p_idempotency_key), canonical_user_id = COALESCE(v_pending.canonical_user_id, v_user_canonical_id)
  WHERE id = v_pending.id;

  -- Allocate tickets
  FOREACH v_ticket IN ARRAY p_selected_tickets LOOP
    INSERT INTO public.tickets (id, competition_id, ticket_number, status, purchased_at, user_id, canonical_user_id, purchase_price)
    VALUES (gen_random_uuid(), p_competition_id, v_ticket, 'sold', v_now, NULL, v_user_canonical_id, v_ticket_price)
    ON CONFLICT (competition_id, ticket_number) DO UPDATE
      SET status = 'sold', purchased_at = EXCLUDED.purchased_at, canonical_user_id = EXCLUDED.canonical_user_id, purchase_price = EXCLUDED.purchase_price;
  END LOOP;

  -- Upsert joincompetition row for aggregation
  SELECT id INTO v_join_id FROM public.joincompetition
  WHERE canonical_user_id = v_user_canonical_id AND competitionid = p_competition_id
  LIMIT 1;

  IF v_join_id IS NULL THEN
    INSERT INTO public.joincompetition (id, userid, wallet_address, competitionid, ticketnumbers, purchasedate, status, created_at, numberoftickets, amountspent, canonical_user_id)
    VALUES (gen_random_uuid(), NULL, NULL, p_competition_id, array_to_string(p_selected_tickets, ','), v_now, 'active', v_now, p_ticket_count, p_amount, v_user_canonical_id);
  ELSE
    SELECT ticketnumbers INTO v_csv_existing FROM public.joincompetition WHERE id = v_join_id;
    UPDATE public.joincompetition
    SET numberoftickets = COALESCE(numberoftickets,0) + p_ticket_count,
        amountspent = COALESCE(amountspent,0) + p_amount,
        ticketnumbers = CASE WHEN v_csv_existing IS NULL OR v_csv_existing = '' THEN array_to_string(p_selected_tickets, ',') ELSE v_csv_existing || ',' || array_to_string(p_selected_tickets, ',') END,
        purchasedate = v_now,
        updated_at = v_now
    WHERE id = v_join_id;
  END IF;

  -- Assemble result
  v_result := jsonb_build_object(
    'status', 'success',
    'reservation_id', p_reservation_id,
    'competition_id', p_competition_id,
    'ticket_count', p_ticket_count,
    'selected_tickets', COALESCE(to_jsonb(p_selected_tickets), '[]'::jsonb),
    'amount', p_amount,
    'currency', v_currency,
    'user', v_user_canonical_id,
    'balance_after', v_balance_after
  );

  INSERT INTO public.payment_idempotency (id, idempotency_key, user_id, competition_id, amount, ticket_count, result, canonical_user_id)
  VALUES (gen_random_uuid(), p_idempotency_key, p_user_identifier, p_competition_id, p_amount, p_ticket_count, v_result, v_user_canonical_id)
  ON CONFLICT (idempotency_key) DO UPDATE SET result = EXCLUDED.result;

  RETURN v_result;
EXCEPTION WHEN others THEN
  v_result := jsonb_build_object('status','error','message', SQLERRM, 'code', SQLSTATE);
  INSERT INTO public.payment_idempotency (id, idempotency_key, user_id, competition_id, amount, ticket_count, result, canonical_user_id)
  VALUES (gen_random_uuid(), p_idempotency_key, p_user_identifier, p_competition_id, p_amount, p_ticket_count, v_result, v_user_canonical_id)
  ON CONFLICT (idempotency_key) DO UPDATE SET result = EXCLUDED.result;
  RAISE;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.finalize_order(p_reservation_id text, p_user_id text, p_competition_id text, p_unit_price numeric)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_ticket_numbers INTEGER[];
  v_ticket_number INTEGER;
  v_ticket_count INTEGER;
  v_canonical_user_id TEXT;
BEGIN
  -- Get canonical user ID
  SELECT canonical_user_id INTO v_canonical_user_id
  FROM canonical_users
  WHERE uid = p_user_id OR canonical_user_id = p_user_id
  LIMIT 1;

  -- Get reserved tickets (pending_ticket_items.competition_id is still TEXT)
  SELECT ARRAY_AGG(ticket_number) INTO v_ticket_numbers
  FROM pending_ticket_items
  WHERE pending_ticket_id = p_reservation_id;

  v_ticket_count := array_length(v_ticket_numbers, 1);

  -- Create tickets (tickets.competition_id is UUID now)
  FOREACH v_ticket_number IN ARRAY v_ticket_numbers
  LOOP
    INSERT INTO tickets (
      competition_id,
      ticket_number,
      user_id,
      canonical_user_id,
      status,
      purchase_price
    ) VALUES (
      p_competition_id::UUID,  -- Cast to UUID
      v_ticket_number,
      p_user_id,
      v_canonical_user_id,
      'active',
      p_unit_price
    ) ON CONFLICT DO NOTHING;

    -- Mark as sold (tickets_sold.competition_id is still TEXT)
    INSERT INTO tickets_sold (competition_id, ticket_number, purchaser_id)
    VALUES (p_competition_id, v_ticket_number, p_user_id)
    ON CONFLICT DO NOTHING;
  END LOOP;

  -- Update competition sold_tickets count (competitions.id is UUID now)
  UPDATE competitions
  SET sold_tickets = sold_tickets + v_ticket_count
  WHERE id = p_competition_id::UUID OR uid = p_competition_id::UUID;

  -- Delete pending tickets (pending_ticket_items.competition_id is still TEXT)
  DELETE FROM pending_ticket_items WHERE pending_ticket_id = p_reservation_id;
  DELETE FROM pending_tickets WHERE id = p_reservation_id;

  RETURN jsonb_build_object(
    'success', true,
    'ticket_count', v_ticket_count,
    'ticket_numbers', v_ticket_numbers
  );
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.finalize_pending_tickets_autoreplace(p_pending_ticket_id uuid, p_expected_user_id text, p_expected_competition_id uuid, p_payment_provider text DEFAULT 'balance'::text)
 RETURNS TABLE(success boolean, ticket_numbers integer[], replaced_count integer, error text)
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
declare
  v_pt public.pending_tickets%rowtype;
  v_total_tickets int;
  v_reserved int[];
  v_conflicted int[];
  v_need int := 0;
  v_repl int[];
  v_attempt int := 0;
  v_max_attempts int := 2000;
  v_replaced_total int := 0;
begin
  select * into v_pt
  from public.pending_tickets
  where id = p_pending_ticket_id
  for update;

  if not found then
    return query select false, null::int[], 0, 'reservation_not_found';
    return;
  end if;

  if v_pt.status <> 'pending' then
    return query select false, null::int[], 0, 'reservation_not_pending';
    return;
  end if;

  if v_pt.user_id <> p_expected_user_id then
    return query select false, null::int[], 0, 'reservation_user_mismatch';
    return;
  end if;

  if v_pt.competition_id <> p_expected_competition_id then
    return query select false, null::int[], 0, 'reservation_competition_mismatch';
    return;
  end if;

  if v_pt.expires_at is not null and v_pt.expires_at < now() then
    update public.pending_tickets
      set status = 'expired',
          updated_at = now()
    where id = p_pending_ticket_id;

    return query select false, null::int[], 0, 'reservation_expired';
    return;
  end if;

  select c.total_tickets into v_total_tickets
  from public.competitions c
  where c.id = v_pt.competition_id;

  if v_total_tickets is null or v_total_tickets <= 0 then
    return query select false, null::int[], 0, 'competition_has_no_total_tickets';
    return;
  end if;

  v_reserved := coalesce(v_pt.ticket_numbers, '{}'::int[]);
  if array_length(v_reserved, 1) is null or array_length(v_reserved, 1) = 0 then
    return query select false, null::int[], 0, 'reservation_has_no_tickets';
    return;
  end if;

  -- de-dupe
  select array_agg(distinct n order by n) into v_reserved
  from unnest(v_reserved) as n;

  while v_attempt < v_max_attempts loop
    v_attempt := v_attempt + 1;

    -- insert reserved tickets for this user (ignore conflicts)
    insert into public.tickets (
      competition_id,
      ticket_number,
      user_id,
      canonical_user_id,
      wallet_address,
      pending_ticket_id,
      status,
      payment_provider,
      created_at,
      purchased_at,
      purchase_date
    )
    select
      v_pt.competition_id,
      n,
      v_pt.user_id,
      v_pt.user_id,
      v_pt.wallet_address,
      v_pt.id,
      'sold',
      p_payment_provider,
      now(),
      now(),
      now()
    from unnest(v_reserved) as n
    on conflict (competition_id, ticket_number) do nothing;

    -- conflicted = tickets that exist but are owned by someone else
    select array_agg(n order by n) into v_conflicted
    from unnest(v_reserved) as n
    join public.tickets t
      on t.competition_id = v_pt.competition_id
     and t.ticket_number = n
    where coalesce(t.user_id,'') <> v_pt.user_id;

    if v_conflicted is null then
      v_conflicted := '{}'::int[];
    end if;

    v_need := coalesce(array_length(v_conflicted, 1), 0);

    if v_need = 0 then
      update public.pending_tickets
        set status = 'confirmed',
            confirmed_at = coalesce(confirmed_at, now()),
            updated_at = now(),
            ticket_numbers = v_reserved,
            ticket_count = coalesce(v_pt.ticket_count, array_length(v_reserved, 1))
      where id = v_pt.id;

      return query select true, v_reserved, v_replaced_total, null::text;
      return;
    end if;

    -- choose replacements not sold and not pending (other users)
    with used as (
      select ticket_number
      from public.tickets
      where competition_id = v_pt.competition_id
      union
      select unnest(pt.ticket_numbers)::int
      from public.pending_tickets pt
      where pt.competition_id = v_pt.competition_id
        and pt.status = 'pending'
        and (pt.expires_at is null or pt.expires_at > now())
        and pt.id <> v_pt.id
    ),
    candidates as (
      select gs as n
      from generate_series(1, v_total_tickets) gs
      left join used u on u.ticket_number = gs
      where u.ticket_number is null
        and not (gs = any(v_reserved))
      order by random()
      limit v_need
    )
    select array_agg(n) into v_repl from candidates;

    if v_repl is null or array_length(v_repl, 1) < v_need then
      return query select false, v_reserved, v_replaced_total, 'sold_out_or_not_enough_replacements';
      return;
    end if;

    -- replace conflicted numbers with replacements
    select array_agg(n order by n) into v_reserved
    from (
      select unnest(v_reserved) as n
      except
      select unnest(v_conflicted) as n
      union all
      select unnest(v_repl) as n
    ) s;

    v_replaced_total := v_replaced_total + v_need;
    perform pg_sleep(0.01);
  end loop;

  return query select false, v_reserved, v_replaced_total, 'finalize_failed_after_max_attempts';
end;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.finalize_purchase(p_reservation_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_pending record;
  v_now timestamptz := now();
  v_total numeric;
  v_ticket_price numeric;
  v_balance_before numeric;
  v_balance_after numeric;
  v_entry_id uuid;
  v_existing_entry uuid;
  v_comp_id uuid;
  v_cuid text;
  v_ticket_count int;
  v_tickets int[];
  v_reference text;
  v_updated_rows int;
BEGIN
  if p_reservation_id is null then
    raise exception 'reservation_id is required';
  end if;

  -- lock the pending reservation
  select * into v_pending
  from public.pending_tickets
  where id = p_reservation_id
  for update;

  if not found then
    raise exception 'Reservation % not found', p_reservation_id;
  end if;

  if v_pending.status <> 'pending' then
    raise exception 'Reservation % is not pending (status=%)', p_reservation_id, v_pending.status;
  end if;

  if v_pending.expires_at is not null and v_pending.expires_at < v_now then
    raise exception 'Reservation % expired at %', p_reservation_id, v_pending.expires_at;
  end if;

  v_comp_id := v_pending.competition_id;
  v_cuid := coalesce(v_pending.canonical_user_id, v_pending.user_id);
  v_ticket_count := coalesce(v_pending.ticket_count, 0);
  v_ticket_price := coalesce(v_pending.ticket_price, 0);
  v_total := coalesce(v_pending.total_amount, v_ticket_price * v_ticket_count);

  if v_cuid is null then
    raise exception 'Reservation missing canonical user id';
  end if;

  -- derive ticket list; prefer pending_ticket_items if populated
  select array_agg(pti.ticket_number order by pti.ticket_number)
    into v_tickets
  from public.pending_ticket_items pti
  where pti.pending_ticket_id = v_pending.id;

  -- balance snapshot before
  select sab.available_balance
    into v_balance_before
  from public.sub_account_balances sab
  where sab.canonical_user_id = v_cuid and sab.currency = 'USD'
  for update;

  if v_balance_before is null then
    -- initialize balance row if missing
    insert into public.sub_account_balances(id, user_id, canonical_user_id, currency, available_balance, pending_balance, last_updated)
    values (gen_random_uuid(), v_cuid, v_cuid, 'USD', 0, 0, v_now)
    returning available_balance into v_balance_before;
  end if;

  -- idempotency reference (time-based; callers should avoid repeating within same second if possible)
  v_reference := v_cuid || '-' || v_comp_id || '-' || v_total || '-' || v_ticket_count || '-' || extract(epoch from v_now)::bigint::text;

  -- Mark tickets as sold based on numbers if available
  if v_ticket_count > 0 then
    if v_tickets is not null and array_length(v_tickets,1) is not null then
      update public.tickets t
      set status = 'sold', purchased_by = null, purchased_at = v_now, purchase_price = v_ticket_price, payment_amount = v_total / greatest(v_ticket_count,1), canonical_user_id = v_cuid
      where t.competition_id = v_comp_id
        and t.ticket_number = any(v_tickets)
        and t.status = 'available';
      GET DIAGNOSTICS v_updated_rows = ROW_COUNT;
      if v_updated_rows <> v_ticket_count then
        raise exception 'Could not mark all reserved tickets as sold (expected %, updated %)', v_ticket_count, v_updated_rows;
      end if;
    else
      raise exception 'No ticket list found for reservation %', p_reservation_id;
    end if;
  end if;

  -- upsert competition_entries aggregate
  select id into v_existing_entry
  from public.competition_entries
  where canonical_user_id = v_cuid and competition_id = v_comp_id
  for update;

  if v_existing_entry is null then
    insert into public.competition_entries(id, canonical_user_id, competition_id, wallet_address, tickets_count, amount_spent, latest_purchase_at, created_at, updated_at)
    values (gen_random_uuid(), v_cuid, v_comp_id, v_pending.wallet_address, v_ticket_count, v_total, v_now, v_now, v_now)
    returning id into v_entry_id;
  else
    update public.competition_entries
    set tickets_count = coalesce(tickets_count,0) + v_ticket_count,
        amount_spent = coalesce(amount_spent,0) + v_total,
        latest_purchase_at = v_now,
        updated_at = v_now
    where id = v_existing_entry
    returning id into v_entry_id;
  end if;

  -- record user_transactions
  insert into public.user_transactions(id, user_id, canonical_user_id, wallet_address, type, amount, currency, balance_before, balance_after, competition_id, description, status, created_at)
  values (gen_random_uuid(), v_cuid, v_cuid, v_pending.wallet_address, 'entry', v_total, 'USD', null, null, v_comp_id, 'Ticket purchase', 'completed', v_now);

  -- mark reservation confirmed
  update public.pending_tickets
  set status = 'confirmed', confirmed_at = v_now, updated_at = v_now
  where id = p_reservation_id;

  -- adjust balances: available -= total, pending -= total
  update public.sub_account_balances
  set available_balance = coalesce(available_balance,0) - v_total,
      pending_balance = greatest(coalesce(pending_balance,0) - v_total, 0),
      last_updated = v_now
  where canonical_user_id = v_cuid and currency = 'USD'
  returning available_balance into v_balance_after;

  -- ledger entry (time-based reference)
  if not exists (
    select 1 from public.balance_ledger bl
    where bl.reference_id = v_reference
  ) then
    insert into public.balance_ledger(id, canonical_user_id, transaction_type, amount, currency, balance_before, balance_after, reference_id, description, created_at)
    values (gen_random_uuid(), v_cuid, 'entry', v_total, 'USD', v_balance_before, v_balance_after, v_reference, 'Ticket purchase', v_now);
  end if;

  return jsonb_build_object(
    'success', true,
    'entry_id', v_entry_id,
    'tickets_created', coalesce(v_tickets, ARRAY[]::int[]),
    'total_cost', v_total,
    'balance_before', v_balance_before,
    'balance_after', v_balance_after,
    'competition_id', v_comp_id
  );

EXCEPTION WHEN others THEN
  return jsonb_build_object(
    'success', false,
    'error', SQLERRM,
    'reservation_id', p_reservation_id
  );
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.fn_credit_sub_account_on_instant_wallet_topup()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_user text;
  v_currency text;
  v_amount numeric;
BEGIN
  IF NOT (
    NEW.payment_provider = 'instant_wallet_topup' AND
    NEW.status = 'completed' AND
    COALESCE(NEW.payment_status, 'confirmed') IN ('confirmed','succeeded') AND
    NEW.amount > 0
  ) THEN
    RETURN NEW;
  END IF;

  v_user := NEW.canonical_user_id;
  v_currency := CASE UPPER(COALESCE(NEW.currency, 'USD')) WHEN 'USDC' THEN 'USD' ELSE UPPER(NEW.currency) END;
  IF v_currency IS NULL THEN v_currency := 'USD'; END IF;
  v_amount := NEW.amount;

  INSERT INTO public.sub_account_balances (
    canonical_user_id, currency, available_balance, pending_balance, last_updated
  ) VALUES (
    v_user, v_currency, 0, COALESCE((SELECT pending_balance FROM public.sub_account_balances WHERE canonical_user_id = v_user AND currency = v_currency), 0), now()
  )
  ON CONFLICT (canonical_user_id, currency) DO NOTHING;

  UPDATE public.sub_account_balances
     SET available_balance = COALESCE(available_balance, 0) + v_amount,
         last_updated = now()
   WHERE canonical_user_id = v_user AND currency = v_currency;

  -- Removed ledger insert to avoid unrelated triggers
  RETURN NEW;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.get_balance_by_any_id(p_user_id text)
 RETURNS numeric
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_canonical TEXT;
  v_balance NUMERIC;
BEGIN
  v_canonical := to_canonical_user_id(p_user_id);

  -- Try canonical first
  SELECT balance INTO v_balance 
  FROM sub_account_balances 
  WHERE lower(user_id) = lower(v_canonical);

  IF v_balance IS NOT NULL THEN
    RETURN v_balance;
  END IF;

  -- Fallback to raw input
  SELECT balance INTO v_balance 
  FROM sub_account_balances 
  WHERE lower(user_id) = lower(p_user_id);

  RETURN COALESCE(v_balance, 0);
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.get_competition_ticket_availability(competition_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'extensions'
AS $function$
DECLARE
  v_total int;
  v_sold int;
  v_available int;
BEGIN
  -- Use competitions.total_tickets as the source of truth
  SELECT c.total_tickets INTO v_total
  FROM public.competitions c
  WHERE c.id = competition_id;

  IF v_total IS NULL THEN
    RETURN jsonb_build_object(
      'error', 'competition not found',
      'is_authoritative', false
    );
  END IF;

  -- Sold tickets are tickets with status='sold' for this competition
  SELECT count(*)::int INTO v_sold
  FROM public.tickets t
  WHERE t.competition_id = competition_id
    AND t.status = 'sold';

  v_available := GREATEST(0, v_total - v_sold);

  RETURN jsonb_build_object(
    'total_tickets', v_total,
    'sold_count', v_sold,
    'available_count', v_available,
    'is_authoritative', true
  );
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.get_competition_ticket_availability_text(competition_id_text text)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'extensions'
AS $function$
DECLARE
  v_uuid uuid;
BEGIN
  BEGIN
    v_uuid := competition_id_text::uuid;
  EXCEPTION WHEN invalid_text_representation THEN
    RETURN jsonb_build_object(
      'error', 'invalid uuid format',
      'is_authoritative', false
    );
  END;

  RETURN public.get_competition_ticket_availability(v_uuid);
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.get_unavailable_tickets(p_competition_id text)
 RETURNS integer[]
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_competition_uuid UUID;
  v_comp_uid TEXT;
  v_unavailable INTEGER[] := ARRAY[]::INTEGER[];
  v_sold_jc INTEGER[] := ARRAY[]::INTEGER[];
  v_sold_tickets INTEGER[] := ARRAY[]::INTEGER[];
  v_pending INTEGER[] := ARRAY[]::INTEGER[];
BEGIN
  -- Handle NULL or empty input
  IF p_competition_id IS NULL OR TRIM(p_competition_id) = '' THEN
    RETURN ARRAY[]::INTEGER[];
  END IF;

  -- Parse UUID
  BEGIN
    v_competition_uuid := p_competition_id::UUID;
  EXCEPTION WHEN invalid_text_representation THEN
    SELECT c.id, c.uid INTO v_competition_uuid, v_comp_uid
    FROM competitions c
    WHERE c.uid = p_competition_id::UUID
    LIMIT 1;

    IF v_competition_uuid IS NULL THEN
      RETURN ARRAY[]::INTEGER[];
    END IF;
  END;

  -- Get uid if not already set
  IF v_comp_uid IS NULL THEN
    SELECT c.uid INTO v_comp_uid
    FROM competitions c
    WHERE c.id = v_competition_uuid;
  END IF;

  -- Get sold tickets from joincompetition (competitionid is TEXT)
  SELECT COALESCE(array_agg(DISTINCT ticket_num), ARRAY[]::INTEGER[])
  INTO v_sold_jc
  FROM (
    SELECT CAST(TRIM(unnest(string_to_array(ticketnumbers::TEXT, ','))) AS INTEGER) AS ticket_num
    FROM joincompetition
    WHERE (
      competitionid = v_competition_uuid::TEXT
      OR (v_comp_uid IS NOT NULL AND competitionid = v_comp_uid::TEXT)
      OR competitionid = p_competition_id
    )
      AND ticketnumbers IS NOT NULL
      AND TRIM(ticketnumbers::TEXT) != ''
  ) AS jc_tickets
  WHERE ticket_num IS NOT NULL;

  v_sold_jc := COALESCE(v_sold_jc, ARRAY[]::INTEGER[]);

  -- Get sold tickets from tickets table (competition_id is now UUID)
  BEGIN
    SELECT COALESCE(array_agg(DISTINCT t.ticket_number), ARRAY[]::INTEGER[])
    INTO v_sold_tickets
    FROM tickets t
    WHERE t.competition_id = v_competition_uuid
      OR (v_comp_uid IS NOT NULL AND t.competition_id = v_comp_uid);
  EXCEPTION WHEN undefined_table THEN
    v_sold_tickets := ARRAY[]::INTEGER[];
  WHEN undefined_column THEN
    v_sold_tickets := ARRAY[]::INTEGER[];
  END;

  v_sold_tickets := COALESCE(v_sold_tickets, ARRAY[]::INTEGER[]);

  -- Get pending tickets from pending_ticket_items (competition_id is still TEXT)
  BEGIN
    SELECT COALESCE(array_agg(DISTINCT pti.ticket_number), ARRAY[]::INTEGER[])
    INTO v_pending
    FROM pending_ticket_items pti
    INNER JOIN pending_tickets pt ON pti.pending_ticket_id = pt.id
    WHERE (
      pti.competition_id = p_competition_id
      OR pti.competition_id = v_competition_uuid::TEXT
      OR (v_comp_uid IS NOT NULL AND pti.competition_id = v_comp_uid::TEXT)
    )
      AND pt.status = 'pending'
      AND pt.expires_at > NOW();
  EXCEPTION WHEN undefined_table THEN
    v_pending := ARRAY[]::INTEGER[];
  WHEN undefined_column THEN
    v_pending := ARRAY[]::INTEGER[];
  END;

  v_pending := COALESCE(v_pending, ARRAY[]::INTEGER[]);

  -- Combine all unavailable tickets
  v_unavailable := ARRAY(
    SELECT DISTINCT unnest(v_sold_jc || v_sold_tickets || v_pending)
    ORDER BY 1
  );

  RETURN v_unavailable;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.get_user_balance(p_user_identifier text DEFAULT NULL::text, p_canonical_user_id text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  user_balance NUMERIC := 0;
  bonus_bal NUMERIC := 0;
  search_wallet TEXT;
  identifier TEXT;
BEGIN
  identifier := COALESCE(p_user_identifier, p_canonical_user_id);
  IF identifier IS NULL OR identifier = '' THEN
    RETURN jsonb_build_object('success', true, 'balance', 0, 'bonus_balance', 0, 'total_balance', 0);
  END IF;

  IF identifier LIKE 'prize:pid:0x%' THEN search_wallet := LOWER(SUBSTRING(identifier FROM 11));
  ELSIF identifier LIKE '0x%' AND LENGTH(identifier) = 42 THEN search_wallet := LOWER(identifier);
  ELSE search_wallet := NULL; END IF;

  BEGIN
    SELECT COALESCE(available_balance, 0), COALESCE(sab.bonus_balance, 0) INTO user_balance, bonus_bal
    FROM public.sub_account_balances sab WHERE currency = 'USD'
    AND (canonical_user_id = identifier OR canonical_user_id = LOWER(identifier) OR (search_wallet IS NOT NULL AND canonical_user_id = 'prize:pid:' || search_wallet) OR user_id = identifier OR privy_user_id = identifier)
    ORDER BY available_balance DESC NULLS LAST LIMIT 1;
    IF user_balance IS NOT NULL AND user_balance > 0 THEN
      RETURN jsonb_build_object('success', true, 'balance', user_balance, 'bonus_balance', bonus_bal, 'total_balance', user_balance + bonus_bal);
    END IF;
  EXCEPTION WHEN OTHERS THEN NULL; END;

  BEGIN
    SELECT COALESCE(usdc_balance, 0), COALESCE(cu.bonus_balance, 0) INTO user_balance, bonus_bal
    FROM public.canonical_users cu WHERE canonical_user_id = identifier OR canonical_user_id = LOWER(identifier)
    OR (search_wallet IS NOT NULL AND LOWER(wallet_address) = search_wallet) OR (search_wallet IS NOT NULL AND LOWER(base_wallet_address) = search_wallet)
    OR LOWER(wallet_address) = LOWER(identifier) OR privy_user_id = identifier
    ORDER BY usdc_balance DESC NULLS LAST LIMIT 1;
  EXCEPTION WHEN OTHERS THEN user_balance := 0; bonus_bal := 0; END;

  RETURN jsonb_build_object('success', true, 'balance', COALESCE(user_balance, 0), 'bonus_balance', COALESCE(bonus_bal, 0), 'total_balance', COALESCE(user_balance, 0) + COALESCE(bonus_bal, 0));
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.get_user_stats(p_wallet_address text)
 RETURNS json
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_user_id UUID;
    total_spent DECIMAL(18,8);
    total_tickets INTEGER;
    total_wins INTEGER;
    total_prizes_won DECIMAL(18,8);
    result JSON;
BEGIN
    -- Get user ID by wallet address
    SELECT id INTO v_user_id 
    FROM users 
    WHERE wallet_address = p_wallet_address;

    IF v_user_id IS NULL THEN
        RETURN json_build_object(
            'error', 'User not found',
            'wallet_address', p_wallet_address
        );
    END IF;

    -- Get comprehensive statistics
    SELECT 
        COALESCE(SUM(t.purchase_price), 0),
        COUNT(t.id),
        COUNT(CASE WHEN w.id IS NOT NULL THEN 1 END),
        COALESCE(SUM(w.prize_amount), 0)
    INTO total_spent, total_tickets, total_wins, total_prizes_won
    FROM tickets t
    LEFT JOIN winners w ON t.user_id = w.user_id AND t.competition_id = w.competition_id
    WHERE t.user_id = v_user_id
      AND t.is_cancelled = FALSE;

    result := json_build_object(
        'user_id', v_user_id,
        'wallet_address', p_wallet_address,
        'total_spent', total_spent,
        'total_tickets_purchased', total_tickets,
        'total_wins', total_wins,
        'total_prizes_won', total_prizes_won,
        'win_rate', CASE 
            WHEN total_tickets > 0 THEN ROUND((total_wins::DECIMAL / total_tickets) * 100, 2)
            ELSE 0 
        END
    );

    RETURN result;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.get_user_wallet_balance(user_identifier text)
 RETURNS numeric
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  balance NUMERIC;
  resolved_id TEXT;
  lower_identifier TEXT;
BEGIN
  resolved_id := public.resolve_canonical_user_id(user_identifier);
  lower_identifier := LOWER(user_identifier);

  SELECT COALESCE(sab.available_balance, 0) INTO balance
  FROM public.sub_account_balances sab
  WHERE sab.currency = 'USD'
    AND (
      sab.canonical_user_id = resolved_id
      OR sab.user_id = resolved_id
      OR LOWER(COALESCE(sab.user_id, '')) = lower_identifier
      OR LOWER(COALESCE(sab.wallet_address, '')) = lower_identifier
    )
  ORDER BY (sab.canonical_user_id = resolved_id) DESC
  LIMIT 1;

  RETURN COALESCE(balance, 0);
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.insert_rng_log(p_timestamp timestamp with time zone, p_source text, p_function_name text, p_competition_id uuid, p_competition_type text, p_context text, p_outcome text, p_is_winner boolean DEFAULT false, p_security_level text DEFAULT 'MEDIUM'::text)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    log_id UUID;
BEGIN
    INSERT INTO rng_logs (
        timestamp, source, function_name, competition_id, 
        competition_type, context, outcome, is_winner, security_level
    ) VALUES (
        p_timestamp, p_source, p_function_name, p_competition_id,
        p_competition_type, p_context, p_outcome, p_is_winner, p_security_level
    );

    RETURN TRUE;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.joincompetition_balance_guard()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF NEW.chain = 'balance' THEN
    IF NEW.canonical_user_id IS NULL THEN
      NEW.canonical_user_id := COALESCE(NEW.userid, NEW.wallet_address, NEW.uid);
    END IF;
    IF NEW.purchasedate IS NULL THEN
      NEW.purchasedate := now();
    END IF;
    IF NEW.numberoftickets IS NULL THEN
      NEW.numberoftickets := CASE
        WHEN NEW.ticketnumbers IS NULL OR NEW.ticketnumbers = '' THEN 0
        ELSE array_length(string_to_array(NEW.ticketnumbers, ','), 1)
      END;
    END IF;
    IF NEW.amountspent IS NULL THEN
      NEW.amountspent := 0;
    END IF;
  END IF;
  RETURN NEW;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.joincompetition_normalize()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  norm text;
  cnt int;
BEGIN
  -- normalize CSV
  norm := public.normalize_ticket_csv(NEW.ticketnumbers);
  NEW.ticketnumbers := norm;

  -- set numberoftickets to distinct count
  IF norm IS NULL OR norm = '' THEN
    NEW.numberoftickets := 0;
  ELSE
    SELECT count(*) INTO cnt FROM unnest(string_to_array(norm, ',')) AS x;
    NEW.numberoftickets := cnt;
  END IF;

  RETURN NEW;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.joincompetition_sync_wallet()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF NEW.canonical_user_id IS NOT NULL AND (NEW.wallet_address IS NULL OR NEW.wallet_address = '') THEN
    NEW.wallet_address := replace(NEW.canonical_user_id, 'prize:pid:', '');
  END IF;
  RETURN NEW;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.link_additional_wallet(user_identifier text, p_wallet_address text, p_wallet_type text DEFAULT 'external'::text, p_nickname text DEFAULT NULL::text)
 RETURNS json
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_user RECORD;
  v_normalized_address TEXT;
  v_new_wallet JSONB;
  v_existing_wallets JSONB;
  v_wallet_exists BOOLEAN;
BEGIN
  -- Normalize wallet address
  v_normalized_address := LOWER(p_wallet_address);

  -- Find user by various identifiers
  SELECT * INTO v_user
  FROM canonical_users cu
  WHERE cu.canonical_user_id = user_identifier
     OR LOWER(cu.wallet_address) = LOWER(user_identifier)
     OR LOWER(cu.base_wallet_address) = LOWER(user_identifier)
     OR cu.privy_user_id = user_identifier
     OR cu.email ILIKE user_identifier
     OR cu.uid::TEXT = user_identifier
  LIMIT 1;

  IF v_user IS NULL THEN
    RETURN json_build_object('success', false, 'error', 'User not found');
  END IF;

  -- Check if wallet already exists in linked_wallets
  v_existing_wallets := COALESCE(v_user.linked_wallets, '[]'::JSONB);

  SELECT EXISTS(
    SELECT 1 FROM jsonb_array_elements(v_existing_wallets) AS w
    WHERE LOWER(w->>'address') = v_normalized_address
  ) INTO v_wallet_exists;

  IF v_wallet_exists THEN
    RETURN json_build_object('success', false, 'error', 'Wallet already linked to this account');
  END IF;

  -- Check if wallet is already linked to another user
  IF EXISTS(
    SELECT 1 FROM canonical_users cu
    WHERE cu.uid != v_user.uid
    AND (
      LOWER(cu.wallet_address) = v_normalized_address
      OR LOWER(cu.base_wallet_address) = v_normalized_address
      OR LOWER(cu.linked_external_wallet) = v_normalized_address
      OR LOWER(cu.primary_wallet_address) = v_normalized_address
      OR EXISTS(
        SELECT 1 FROM jsonb_array_elements(COALESCE(cu.linked_wallets, '[]'::JSONB)) AS w
        WHERE LOWER(w->>'address') = v_normalized_address
      )
    )
  ) THEN
    RETURN json_build_object('success', false, 'error', 'Wallet is already linked to another account');
  END IF;

  -- Build new wallet object
  v_new_wallet := jsonb_build_object(
    'address', v_normalized_address,
    'type', p_wallet_type,
    'nickname', COALESCE(p_nickname,
      CASE p_wallet_type
        WHEN 'base' THEN 'Base Wallet'
        WHEN 'external' THEN 'External Wallet'
        ELSE 'Wallet'
      END
    ),
    'is_primary', (jsonb_array_length(v_existing_wallets) = 0), -- First wallet is primary
    'linked_at', NOW()
  );

  -- Add to linked_wallets array
  UPDATE canonical_users
  SET
    linked_wallets = v_existing_wallets || jsonb_build_array(v_new_wallet),
    primary_wallet_address = CASE
      WHEN primary_wallet_address IS NULL THEN v_normalized_address
      ELSE primary_wallet_address
    END,
    updated_at = NOW()
  WHERE uid = v_user.uid;

  RETURN json_build_object(
    'success', true,
    'message', 'Wallet linked successfully',
    'wallet', v_new_wallet
  );
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.link_external_wallet(p_canonical_user_id text, p_external_wallet text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_result JSONB;
BEGIN
  IF p_canonical_user_id IS NULL OR p_external_wallet IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'Missing required parameters');
  END IF;

  UPDATE canonical_users
  SET eth_wallet_address = LOWER(p_external_wallet), updated_at = NOW()
  WHERE canonical_user_id = p_canonical_user_id OR uid = p_canonical_user_id;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'User not found');
  END IF;

  RETURN jsonb_build_object('success', true, 'wallet_address', LOWER(p_external_wallet));
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.migrate_privy_users(p_privy_wallet_mapping jsonb)
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE
    mapping JSONB;
    user_id UUID;
    migrated_count INTEGER := 0;
BEGIN
    -- Process each mapping
    FOR mapping IN SELECT * FROM jsonb_array_elements(p_privy_wallet_mapping)
    LOOP
        BEGIN
            -- Try to find existing user by wallet address
            SELECT id INTO user_id 
            FROM users 
            WHERE wallet_address = (mapping->>'wallet_address')::TEXT;

            IF user_id IS NOT NULL THEN
                -- Update existing user with Privy migration info
                UPDATE users 
                SET legacy_privy_id = (mapping->>'privy_id')::TEXT,
                    migrated_from_privy = TRUE,
                    migration_date = NOW(),
                    updated_at = NOW()
                WHERE id = user_id;

                migrated_count := migrated_count + 1;
            ELSE
                -- Create new user with Privy migration info
                INSERT INTO users (
                    wallet_address, 
                    legacy_privy_id, 
                    migrated_from_privy, 
                    migration_date
                ) VALUES (
                    (mapping->>'wallet_address')::TEXT,
                    (mapping->>'privy_id')::TEXT,
                    TRUE,
                    NOW()
                );

                migrated_count := migrated_count + 1;
            END IF;
        EXCEPTION WHEN OTHERS THEN
            -- Continue with next mapping if one fails
            CONTINUE;
        END;
    END LOOP;

    RETURN migrated_count;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.normalize_sub_account_currency()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  -- Default NULL to USD
  IF NEW.currency IS NULL THEN
    NEW.currency := 'USD';
  END IF;

  -- Normalize case/whitespace
  NEW.currency := upper(btrim(NEW.currency));

  -- Allow known currencies; reject everything else to avoid silent corruption
  IF NEW.currency NOT IN ('USD', 'USDC') THEN
    RAISE EXCEPTION 'Unsupported currency for sub_account_balances: %', NEW.currency;
  END IF;

  RETURN NEW;
END
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.on_email_verification_merge()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_email text;
  v_row public.canonical_users;
begin
  -- Only act when verification succeeds; prefer verified_at, fallback to used_at
  if (NEW.verified_at is not null) or (NEW.used_at is not null) then
    v_email := lower(trim(NEW.email));
    if v_email is not null and v_email <> '' then
      -- Call the canonical upsert with just the email for now
      v_row := public.ensure_canonical_user(p_email => v_email);
    end if;
  end if;
  return NEW;
end;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.pending_tickets_autofill_cuid()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
BEGIN
  IF NEW.canonical_user_id IS NULL AND NEW.user_id IS NOT NULL THEN
    IF EXISTS (
      SELECT 1 FROM public.canonical_users cu
      WHERE cu.canonical_user_id = NEW.user_id
    ) THEN
      NEW.canonical_user_id := NEW.user_id;
    END IF;
  END IF;
  RETURN NEW;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.pending_tickets_enforce_expiry()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF NEW.expires_at IS NULL THEN
    NEW.expires_at := COALESCE(NEW.created_at, now()) + interval '5 minutes';
  END IF;
  IF NEW.status = 'pending' AND now() > NEW.expires_at THEN
    NEW.status := 'expired';
    NEW.updated_at := now();
    NEW.note := coalesce(NEW.note, '') || CASE WHEN NEW.note IS NULL OR NEW.note = '' THEN '' ELSE ' | ' END ||
      'auto-expired by trigger at ' || to_char(now(), 'YYYY-MM-DD HH24:MI:SS TZ');
  END IF;
  RETURN NEW;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.post_user_transaction_to_balance()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_currency text;
  v_effect numeric;
  v_bal_id uuid;
  v_currency_final text;
BEGIN
  -- Skip if already posted to balance
  IF NEW.posted_to_balance = true THEN
    RETURN NEW;
  END IF;

  -- Skip if not completed
  IF NEW.status <> 'completed' THEN
    RETURN NEW;
  END IF;

  -- CRITICAL FIX: Skip external crypto payments
  IF NEW.payment_provider IN (
    'base_account',
    'coinbase_commerce',
    'coinbase',
    'privy_base_wallet',
    'onchainkit',
    'onchainkit_checkout'
  ) THEN
    NEW.posted_to_balance := true;
    RETURN NEW;
  END IF;

  -- ONLY process balance payments and onramp top-ups
  IF NEW.payment_provider NOT IN ('balance', 'onramp', 'coinbase_onramp') THEN
    NEW.posted_to_balance := true;
    RETURN NEW;
  END IF;

  -- Determine currency
  BEGIN
    EXECUTE 'SELECT ($1).' || quote_ident('currency') INTO v_currency USING NEW;
  EXCEPTION WHEN others THEN
    v_currency := NULL;
  END;
  v_currency_final := COALESCE(v_currency, NEW.metadata->>'currency', 'USD');

  -- Calculate balance effect
  IF NEW.type IN ('entry','payment') THEN
    v_effect := - NEW.amount;
  ELSIF NEW.type IN ('topup','refund','adjustment') THEN
    v_effect := NEW.amount;
  ELSE
    v_effect := 0;
  END IF;

  -- Only proceed if there's an effect
  IF v_effect != 0 THEN
    PERFORM public.ensure_sub_account_balance_row(NEW.canonical_user_id, v_currency_final);

    SELECT id INTO v_bal_id
    FROM public.sub_account_balances
    WHERE canonical_user_id = NEW.canonical_user_id
      AND currency = v_currency_final
    LIMIT 1;

    UPDATE public.sub_account_balances b
    SET available_balance = b.available_balance + v_effect,
        last_updated = NOW()
    WHERE b.id = v_bal_id;
  END IF;

  NEW.posted_to_balance := true;
  IF NEW.completed_at IS NULL THEN
    NEW.completed_at := NOW();
  END IF;
  RETURN NEW;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.purchase_tickets_with_balance(p_user_identifier text, p_competition_id text, p_ticket_price numeric, p_ticket_count integer DEFAULT NULL::integer, p_ticket_numbers integer[] DEFAULT NULL::integer[], p_idempotency_key text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_canonical_user_id TEXT; v_user_uuid TEXT; v_current_balance NUMERIC; v_total_cost NUMERIC; v_new_balance NUMERIC;
  v_final_tickets INTEGER[]; v_competition_total_tickets INTEGER; v_competition_status TEXT; v_entry_id TEXT;
  v_ticket_numbers_str TEXT; v_used_tickets INTEGER[]; v_available_tickets INTEGER[]; v_needed_count INTEGER;
  v_i INTEGER; v_random_index INTEGER; v_ticket_number INTEGER;
BEGIN
  IF p_user_identifier IS NULL OR LENGTH(TRIM(p_user_identifier)) = 0 THEN RETURN jsonb_build_object('success', false, 'error', 'User identifier is required'); END IF;
  IF p_competition_id IS NULL OR LENGTH(TRIM(p_competition_id)) = 0 THEN RETURN jsonb_build_object('success', false, 'error', 'Competition ID is required'); END IF;
  IF p_ticket_price IS NULL OR p_ticket_price <= 0 THEN RETURN jsonb_build_object('success', false, 'error', 'Ticket price must be positive'); END IF;
  IF (p_ticket_count IS NULL AND (p_ticket_numbers IS NULL OR array_length(p_ticket_numbers, 1) IS NULL)) THEN RETURN jsonb_build_object('success', false, 'error', 'Must provide either ticket_count or ticket_numbers'); END IF;

  IF p_user_identifier ~ '^0x[a-fA-F0-9]{40}$' THEN v_canonical_user_id := 'prize:pid:' || LOWER(p_user_identifier);
  ELSIF p_user_identifier LIKE 'prize:pid:%' THEN v_canonical_user_id := LOWER(p_user_identifier);
  ELSE v_canonical_user_id := 'prize:pid:' || LOWER(p_user_identifier); END IF;

  SELECT available_balance, id INTO v_current_balance, v_user_uuid FROM sub_account_balances WHERE canonical_user_id = v_canonical_user_id AND currency = 'USD' FOR UPDATE;
  IF NOT FOUND THEN
    IF p_user_identifier ~ '^0x[a-fA-F0-9]{40}$' THEN
      SELECT sab.available_balance, sab.id INTO v_current_balance, v_user_uuid FROM sub_account_balances sab
      JOIN canonical_users cu ON cu.canonical_user_id = sab.canonical_user_id
      WHERE (LOWER(cu.wallet_address) = LOWER(p_user_identifier) OR LOWER(cu.base_wallet_address) = LOWER(p_user_identifier) OR LOWER(cu.eth_wallet_address) = LOWER(p_user_identifier))
      AND sab.currency = 'USD' LIMIT 1 FOR UPDATE;
    END IF;
    IF NOT FOUND THEN RETURN jsonb_build_object('success', false, 'error', 'User balance not found', 'error_code', 'NO_BALANCE_RECORD'); END IF;
  END IF;

  SELECT total_tickets, status INTO v_competition_total_tickets, v_competition_status FROM competitions WHERE id = p_competition_id;
  IF NOT FOUND THEN RETURN jsonb_build_object('success', false, 'error', 'Competition not found'); END IF;
  IF v_competition_status != 'active' THEN RETURN jsonb_build_object('success', false, 'error', 'Competition is not active', 'competition_status', v_competition_status); END IF;

  IF p_ticket_numbers IS NOT NULL AND array_length(p_ticket_numbers, 1) > 0 THEN v_final_tickets := p_ticket_numbers;
  ELSE
    v_final_tickets := ARRAY[]::INTEGER[];
    SELECT array_agg(DISTINCT ticket_number) INTO v_used_tickets FROM tickets WHERE competition_id = p_competition_id AND ticket_number IS NOT NULL;
    v_available_tickets := ARRAY[]::INTEGER[];
    FOR v_i IN 1..v_competition_total_tickets LOOP
      IF v_used_tickets IS NULL OR NOT (v_i = ANY(v_used_tickets)) THEN v_available_tickets := array_append(v_available_tickets, v_i); END IF;
    END LOOP;
    IF array_length(v_available_tickets, 1) < p_ticket_count THEN
      RETURN jsonb_build_object('success', false, 'error', 'Not enough tickets available', 'available_count', COALESCE(array_length(v_available_tickets, 1), 0), 'requested_count', p_ticket_count);
    END IF;
    v_needed_count := p_ticket_count;
    FOR v_i IN 1..v_needed_count LOOP
      v_random_index := 1 + floor(random() * (array_length(v_available_tickets, 1) - v_i + 1))::INTEGER;
      v_ticket_number := v_available_tickets[v_random_index];
      v_final_tickets := array_append(v_final_tickets, v_ticket_number);
      v_available_tickets[v_random_index] := v_available_tickets[array_length(v_available_tickets, 1) - v_i + 1];
    END LOOP;
  END IF;

  v_total_cost := p_ticket_price * array_length(v_final_tickets, 1);
  IF v_current_balance < v_total_cost THEN RETURN jsonb_build_object('success', false, 'error', 'Insufficient balance', 'error_code', 'INSUFFICIENT_BALANCE', 'required', v_total_cost, 'available', v_current_balance); END IF;
  v_new_balance := v_current_balance - v_total_cost;

  UPDATE sub_account_balances SET available_balance = v_new_balance, updated_at = NOW() WHERE canonical_user_id = v_canonical_user_id AND currency = 'USD';

  INSERT INTO balance_ledger (canonical_user_id, transaction_type, amount, currency, balance_before, balance_after, reference_id, description, created_at)
  VALUES (v_canonical_user_id, 'debit', -v_total_cost, 'USD', v_current_balance, v_new_balance, COALESCE(p_idempotency_key, 'purchase_' || gen_random_uuid()::TEXT), 'Purchase ' || array_length(v_final_tickets, 1) || ' tickets', NOW());

  v_entry_id := gen_random_uuid()::TEXT;
  v_ticket_numbers_str := array_to_string(v_final_tickets, ',');

  BEGIN
    INSERT INTO joincompetition (uid, userid, competitionid, ticketnumbers, ticketcount, amountspent, transactionhash, createdat, updatedat)
    VALUES (v_entry_id, v_canonical_user_id, p_competition_id, v_ticket_numbers_str, array_length(v_final_tickets, 1), v_total_cost, COALESCE(p_idempotency_key, 'balance_' || v_entry_id), NOW(), NOW());
  EXCEPTION WHEN OTHERS THEN NULL; END;

  BEGIN
    INSERT INTO tickets (competition_id, ticket_number, user_id, canonical_user_id, status, created_at)
    SELECT p_competition_id, unnest(v_final_tickets), v_canonical_user_id, v_canonical_user_id, 'sold', NOW();
  EXCEPTION WHEN OTHERS THEN NULL; END;

  RETURN jsonb_build_object('success', true, 'entry_id', v_entry_id, 'ticket_numbers', v_final_tickets, 'ticket_count', array_length(v_final_tickets, 1), 'total_cost', v_total_cost, 'previous_balance', v_current_balance, 'new_balance', v_new_balance, 'competition_id', p_competition_id);
EXCEPTION WHEN OTHERS THEN
  RETURN jsonb_build_object('success', false, 'error', 'Internal error: ' || SQLERRM, 'error_code', 'INTERNAL_ERROR');
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.release_reservation(p_reservation_id uuid, p_user_id text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_reservation RECORD;
BEGIN
  SELECT * INTO v_reservation
  FROM public.pending_tickets
  WHERE id = p_reservation_id
    AND user_id = p_user_id
  FOR UPDATE SKIP LOCKED;

  IF v_reservation IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'Reservation not found or already locked');
  END IF;

  IF v_reservation.status <> 'pending' THEN
    RETURN jsonb_build_object('success', false, 'error', 'Reservation is already ' || v_reservation.status);
  END IF;

  UPDATE public.pending_tickets
  SET status = 'cancelled',
      updated_at = NOW()
  WHERE id = p_reservation_id;

  RETURN jsonb_build_object('success', true, 'message', 'Reservation cancelled successfully');
EXCEPTION
  WHEN OTHERS THEN
    RETURN jsonb_build_object('success', false, 'error', 'Failed to cancel reservation: ' || SQLERRM);
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.repair_topup_provider_and_status()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  has_coinbase boolean := false;
  ev_id_suffix text;
  new_meta jsonb;
  new_status text;
BEGIN
  -- Only for topups; do not affect entries
  IF NEW.type <> 'topup' THEN
    RETURN NEW;
  END IF;

  -- Determine if Coinbase webhook exists for this transaction
  ev_id_suffix := NEW.id::text;

  SELECT EXISTS (
    SELECT 1
    FROM public.payment_webhook_events pwe
    WHERE pwe.provider = 'coinbase-commerce'
      AND (
        (NEW.charge_id IS NOT NULL AND pwe.transaction_id = NEW.charge_id)
        OR (pwe.event_id LIKE 'TOPUP_%_' || ev_id_suffix)
      )
  ) INTO has_coinbase;

  new_meta := COALESCE(NEW.metadata, '{}'::jsonb);

  IF has_coinbase THEN
    IF COALESCE(new_meta->>'provider', '') <> 'coinbase' THEN
      new_meta := new_meta || jsonb_build_object('provider', 'coinbase');
    END IF;
  END IF;

  -- Auto-confirm when posted_to_balance is true
  IF NEW.posted_to_balance IS TRUE THEN
    new_status := 'confirmed';
  ELSE
    new_status := COALESCE(NEW.payment_status, 'pending');
  END IF;

  IF new_meta IS DISTINCT FROM NEW.metadata OR new_status IS DISTINCT FROM NEW.payment_status THEN
    NEW.metadata := new_meta;
    NEW.payment_status := new_status;
  END IF;

  RETURN NEW;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.reserve_competition_tickets(p_user_id text, p_competition_id uuid, p_ticket_numbers integer[], p_hold_minutes integer DEFAULT 15)
 RETURNS jsonb
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_parent_id uuid := gen_random_uuid();
  v_now timestamptz := now();
  v_expires_at timestamptz := v_now + make_interval(mins => COALESCE(p_hold_minutes, 15));
  v_total integer := COALESCE(array_length(p_ticket_numbers, 1), 0);
  v_conflicts int[];
  v_inserted_count int := 0;
  v_status text;
BEGIN
  IF p_user_id IS NULL OR p_competition_id IS NULL OR v_total = 0 THEN
    RETURN jsonb_build_object(
      'success', false,
      'error', 'invalid_payload',
      'message', 'user_id, competition_id and ticket_numbers[] are required'
    );
  END IF;

  SELECT status INTO v_status FROM public.competitions WHERE id = p_competition_id;
  IF v_status IS NULL OR v_status NOT IN ('active','live','running','open','ongoing') THEN
    RETURN jsonb_build_object(
      'success', false,
      'error', 'competition_not_active',
      'message', 'Competition is not accepting reservations'
    );
  END IF;

  INSERT INTO public.pending_tickets (id, user_id, competition_id, status, hold_minutes, expires_at, created_at, ticket_count, ticket_price, total_amount, updated_at, ticket_numbers)
  VALUES (v_parent_id, p_user_id, p_competition_id, 'pending', COALESCE(p_hold_minutes,15), v_expires_at, v_now, v_total, NULL, NULL, v_now, NULL);

  WITH to_try AS (
    SELECT unnest(p_ticket_numbers) AS ticket_number
  ), ins AS (
    INSERT INTO public.pending_ticket_items (id, pending_ticket_id, competition_id, ticket_number, status, expires_at, created_at)
    SELECT gen_random_uuid(), v_parent_id, p_competition_id, t.ticket_number, 'pending', v_expires_at, v_now
    FROM to_try t
    ON CONFLICT (competition_id, ticket_number, expires_at) WHERE status='pending'
    DO NOTHING
    RETURNING ticket_number
  )
  SELECT COUNT(*) INTO v_inserted_count FROM ins;

  IF v_inserted_count <> v_total THEN
    SELECT ARRAY(
      SELECT t.ticket_number
      FROM (SELECT unnest(p_ticket_numbers) AS ticket_number) t
      EXCEPT
      SELECT i.ticket_number FROM public.pending_ticket_items i
      WHERE i.pending_ticket_id = v_parent_id
    ) INTO v_conflicts;

    DELETE FROM public.pending_ticket_items WHERE pending_ticket_id = v_parent_id;
    DELETE FROM public.pending_tickets WHERE id = v_parent_id;

    RETURN jsonb_build_object(
      'success', false,
      'error', 'conflict',
      'message', 'Some requested tickets are no longer available',
      'unavailableTickets', v_conflicts
    );
  END IF;

  UPDATE public.pending_tickets
  SET ticket_numbers = p_ticket_numbers, ticket_count = v_total, updated_at = now()
  WHERE id = v_parent_id;

  RETURN jsonb_build_object(
    'success', true,
    'reservationId', v_parent_id,
    'reserved', p_ticket_numbers,
    'expiresAt', v_expires_at
  );
EXCEPTION
  WHEN unique_violation THEN
    RETURN jsonb_build_object(
      'success', false,
      'error', 'conflict',
      'message', 'Requested tickets are no longer available'
    );
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.reserve_selected_tickets(p_user_id text, p_competition_id uuid, p_ticket_numbers integer[], p_ticket_price numeric DEFAULT 1, p_hold_minutes integer DEFAULT 15, p_session_id text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_total_tickets integer;
  v_unavailable integer[];
  v_conflicts integer[] := ARRAY[]::integer[];
  v_clean integer[];
  v_count int;
  v_reservation_id uuid;
  v_expires_at timestamptz;
  v_total_amount numeric;
  v_inserted int;
BEGIN
  -- Validate inputs
  IF p_ticket_numbers IS NULL OR array_length(p_ticket_numbers,1) IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'No tickets provided');
  END IF;

  -- Basic competition check and lock
  SELECT total_tickets INTO v_total_tickets
  FROM competitions
  WHERE id = p_competition_id AND deleted = false AND status = 'active'
  FOR UPDATE SKIP LOCKED;

  IF v_total_tickets IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'Competition not found or locked', 'retryable', true);
  END IF;

  -- Normalize input: distinct, within range
  SELECT array_agg(DISTINCT t)
  INTO v_clean
  FROM unnest(p_ticket_numbers) t
  WHERE t BETWEEN 1 AND v_total_tickets;

  IF v_clean IS NULL OR array_length(v_clean,1) IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'No valid tickets in range');
  END IF;

  -- Build current unavailable set
  SELECT COALESCE(array_agg(ticket_number), ARRAY[]::int[])
  INTO v_unavailable
  FROM get_competition_unavailable_tickets(p_competition_id);

  -- Pre-check conflicts vs current state
  SELECT COALESCE(array_agg(t), ARRAY[]::int[])
  INTO v_conflicts
  FROM unnest(v_clean) t
  WHERE v_unavailable @> ARRAY[t];

  IF array_length(v_conflicts,1) IS NOT NULL AND array_length(v_conflicts,1) > 0 THEN
    RETURN jsonb_build_object(
      'success', false,
      'error', 'Some selected tickets are unavailable',
      'status', 409,
      'unavailableTickets', v_conflicts,
      'retryable', true
    );
  END IF;

  -- Create reservation header
  v_reservation_id := gen_random_uuid();
  v_count := array_length(v_clean,1);
  v_expires_at := NOW() + make_interval(mins => LEAST(GREATEST(p_hold_minutes, 1), 60));
  v_total_amount := v_count * p_ticket_price;

  INSERT INTO pending_tickets (
    id, user_id, competition_id, ticket_numbers, ticket_count, ticket_price, total_amount,
    status, session_id, expires_at, created_at, updated_at
  ) VALUES (
    v_reservation_id, p_user_id, p_competition_id, v_clean, v_count, p_ticket_price, v_total_amount,
    'pending', p_session_id, v_expires_at, NOW(), NOW()
  );

  -- Per-ticket locking via pending_ticket_items unique partial index
  WITH ins AS (
    INSERT INTO pending_ticket_items(competition_id, pending_ticket_id, ticket_number, status, created_at, updated_at)
    SELECT p_competition_id, v_reservation_id, t, 'pending', NOW(), NOW()
    FROM unnest(v_clean) t
    ON CONFLICT DO NOTHING
    RETURNING ticket_number
  )
  SELECT COUNT(*) INTO v_inserted FROM ins;

  IF v_inserted < v_count THEN
    -- Determine which failed
    SELECT COALESCE(array_agg(t), ARRAY[]::int[])
    INTO v_conflicts
    FROM unnest(v_clean) t
    WHERE t NOT IN (
      SELECT ticket_number FROM pending_ticket_items WHERE pending_ticket_id = v_reservation_id
    );

    -- Cleanup header and any partial items
    DELETE FROM pending_ticket_items WHERE pending_ticket_id = v_reservation_id;
    DELETE FROM pending_tickets WHERE id = v_reservation_id;

    RETURN jsonb_build_object(
      'success', false,
      'error', 'Some selected tickets were claimed concurrently',
      'status', 409,
      'unavailableTickets', v_conflicts,
      'retryable', true
    );
  END IF;

  RETURN jsonb_build_object(
    'success', true,
    'reservation_id', v_reservation_id,
    'ticket_numbers', v_clean,
    'ticket_count', v_count,
    'total_amount', v_total_amount,
    'expires_at', v_expires_at
  );

EXCEPTION WHEN OTHERS THEN
  -- Cleanup on error if header exists
  IF v_reservation_id IS NOT NULL THEN
    DELETE FROM pending_ticket_items WHERE pending_ticket_id = v_reservation_id;
    DELETE FROM pending_tickets WHERE id = v_reservation_id;
  END IF;
  RETURN jsonb_build_object('success', false, 'error', 'Failed to reserve: ' || SQLERRM, 'retryable', true);
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.reserve_tickets(p_competition_id uuid, p_wallet_address text, p_ticket_count integer, p_hold_minutes integer DEFAULT 15)
 RETURNS TABLE(pending_ticket_id uuid, expires_at timestamp with time zone, ticket_numbers integer[])
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_price numeric;
  v_now timestamptz := now();
  v_pending_id uuid := gen_random_uuid();
  v_expires timestamptz := v_now + make_interval(mins => p_hold_minutes);
  v_numbers int[] := '{}';
BEGIN
  -- Validate competition and price
  SELECT ticket_price INTO v_price FROM public.competitions WHERE id = p_competition_id AND deleted = false AND status IN ('active','upcoming') LIMIT 1;
  IF NOT FOUND THEN RAISE EXCEPTION 'competition_not_available'; END IF;

  -- Create pending_tickets shell
  INSERT INTO public.pending_tickets(id, user_id, wallet_address, competition_id, status, hold_minutes, expires_at, ticket_count, ticket_price, total_amount)
  VALUES (v_pending_id, p_wallet_address, p_wallet_address, p_competition_id, 'pending', p_hold_minutes, v_expires, p_ticket_count, v_price, v_price * p_ticket_count);

  -- Pick available numbers: prefer from tickets where status='available'; otherwise allocate next numbers
  WITH avail AS (
    SELECT ticket_number FROM public.tickets
    WHERE competition_id = p_competition_id AND status = 'available'
    ORDER BY ticket_number
    LIMIT p_ticket_count
  ), fallback AS (
    SELECT generate_series(1, (SELECT total_tickets FROM public.competitions WHERE id = p_competition_id)) AS ticket_number
  ), chosen AS (
    SELECT ticket_number FROM avail
    UNION
    SELECT f.ticket_number FROM fallback f
    LEFT JOIN public.tickets t ON t.competition_id = p_competition_id AND t.ticket_number = f.ticket_number
    LEFT JOIN public.pending_ticket_items pti ON pti.competition_id = p_competition_id AND pti.ticket_number = f.ticket_number AND pti.status='pending' AND pti.expires_at > v_now
    WHERE t.id IS NULL AND pti.id IS NULL
    ORDER BY ticket_number
    LIMIT p_ticket_count
  )
  INSERT INTO public.pending_ticket_items(id, pending_ticket_id, competition_id, ticket_number, status, expires_at)
  SELECT gen_random_uuid(), v_pending_id, p_competition_id, ticket_number, 'pending', v_expires FROM chosen
  RETURNING ticket_number INTO v_numbers;

  IF array_length(v_numbers,1) IS DISTINCT FROM p_ticket_count THEN
    -- Not enough tickets; cleanup
    DELETE FROM public.pending_ticket_items WHERE pending_ticket_id = v_pending_id;
    DELETE FROM public.pending_tickets WHERE id = v_pending_id;
    RAISE EXCEPTION 'insufficient_tickets_available';
  END IF;

  RETURN QUERY SELECT v_pending_id, v_expires, v_numbers;
END; $function$
"

definition: "CREATE OR REPLACE FUNCTION public.resolve_canonical_identity(p_id uuid DEFAULT NULL::uuid, p_canonical_user_id text DEFAULT NULL::text, p_wallet_address text DEFAULT NULL::text, p_privy_user_id text DEFAULT NULL::text, p_email text DEFAULT NULL::text, p_username text DEFAULT NULL::text)
 RETURNS TABLE(id uuid, canonical_user_id text, wallet_address text, email text, privy_user_id text, username text, resolved_via text)
 LANGUAGE plpgsql
 STABLE
AS $function$
declare
  v_row public.canonical_users%rowtype;
begin
  -- 1) Match by internal UUID id
  if p_id is not null then
    select *
      into v_row
    from public.canonical_users cu
    where cu.id = p_id
    limit 1;

    if found then
      return query
      select v_row.id, v_row.canonical_user_id, v_row.wallet_address, v_row.email,
             v_row.privy_user_id, v_row.username, 'id'::text as resolved_via;
      return;
    end if;
  end if;

  -- 2) Match by canonical_user_id (exact)
  if p_canonical_user_id is not null then
    select *
      into v_row
    from public.canonical_users cu
    where cu.canonical_user_id = p_canonical_user_id
    limit 1;

    if found then
      return query
      select v_row.id, v_row.canonical_user_id, v_row.wallet_address, v_row.email,
             v_row.privy_user_id, v_row.username, 'canonical_user_id'::text as resolved_via;
      return;
    end if;
  end if;

  -- 3) Match by privy_user_id (exact)
  if p_privy_user_id is not null then
    select *
      into v_row
    from public.canonical_users cu
    where cu.privy_user_id = p_privy_user_id
    limit 1;

    if found then
      return query
      select v_row.id, v_row.canonical_user_id, v_row.wallet_address, v_row.email,
             v_row.privy_user_id, v_row.username, 'privy_user_id'::text as resolved_via;
      return;
    end if;
  end if;

  -- 4) Match by wallet_address (case-insensitive)
  if p_wallet_address is not null then
    select *
      into v_row
    from public.canonical_users cu
    where lower(cu.wallet_address) = lower(p_wallet_address)
    limit 1;

    if found then
      return query
      select v_row.id, v_row.canonical_user_id, v_row.wallet_address, v_row.email,
             v_row.privy_user_id, v_row.username, 'wallet_address'::text as resolved_via;
      return;
    end if;
  end if;

  -- 5) Match by email (case-insensitive)
  if p_email is not null then
    select *
      into v_row
    from public.canonical_users cu
    where lower(cu.email) = lower(p_email)
    limit 1;

    if found then
      return query
      select v_row.id, v_row.canonical_user_id, v_row.wallet_address, v_row.email,
             v_row.privy_user_id, v_row.username, 'email'::text as resolved_via;
      return;
    end if;
  end if;

  -- 6) Match by username (case-insensitive)
  if p_username is not null then
    select *
      into v_row
    from public.canonical_users cu
    where lower(cu.username) = lower(p_username)
    limit 1;

    if found then
      return query
      select v_row.id, v_row.canonical_user_id, v_row.wallet_address, v_row.email,
             v_row.privy_user_id, v_row.username, 'username'::text as resolved_via;
      return;
    end if;
  end if;

  -- If nothing matched, return no rows (NULL result)
  return;
end;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.resolve_canonical_user_id(input_id text)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
declare
  cid text;
begin
  if input_id is null then
    return null;
  end if;

  if input_id ~ '^prize:pid:' then
    return input_id;
  end if;

  if lower(input_id) ~ '^0x[a-f0-9]{40}$' then
    select cu.canonical_user_id into cid
    from public.canonical_users cu
    where cu.wallet_address = lower(input_id)
       or cu.base_wallet_address = lower(input_id)
       or cu.eth_wallet_address = lower(input_id);

    return cid;
  end if;

  if input_id ~ '^did:privy:' then
    select cu.canonical_user_id into cid
    from public.canonical_users cu
    where cu.privy_user_id = input_id;

    return cid;
  end if;

  select cu.canonical_user_id into cid
  from public.canonical_users cu
  where cu.canonical_user_id = input_id;

  return cid;
end;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.resolve_or_create_canonical_user(p_canonical_user_id text)
 RETURNS canonical_users
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
declare
  u public.canonical_users;
begin
  if p_canonical_user_id is null or p_canonical_user_id !~ '^prize:pid:0x[a-f0-9]{40}$' then
    raise exception 'Invalid canonical_user_id format';
  end if;

  select * into u
  from public.canonical_users
  where canonical_user_id = p_canonical_user_id;

  if not found then
    insert into public.canonical_users (canonical_user_id)
    values (p_canonical_user_id)
    returning * into u;
  end if;

  return u;
end;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.rpc_debit_balance_for_order(p_order_id uuid)
 RETURNS json
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_order public.orders%ROWTYPE;
  v_canon text;
  v_amount numeric;
BEGIN
  v_canon := (auth.jwt() ->> 'canonical_user_id');
  IF v_canon IS NULL THEN
    RAISE EXCEPTION 'Missing canonical_user_id claim';
  END IF;

  SELECT * INTO v_order FROM public.orders WHERE id = p_order_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'Order not found';
  END IF;
  IF v_order.user_id <> v_canon THEN
    RAISE EXCEPTION 'Forbidden';
  END IF;
  IF NOT ((v_order.payment_method = 'balance' OR v_order.order_type = 'balance')
          AND (v_order.status ILIKE 'completed' OR COALESCE(v_order.payment_status,'') ILIKE 'paid%')) THEN
    RAISE EXCEPTION 'Order is not marked completed/paid via balance';
  END IF;

  v_amount := COALESCE(v_order.amount_usd, v_order.amount);
  RETURN public.debit_balance_and_confirm_tickets(
    v_canon,
    v_order.id,
    v_order.competition_id,
    v_amount,
    md5(v_order.id::text || '-balance'),
    'USD'
  );
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.set_canonical_user_id_from_wallet()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF NEW.canonical_user_id IS NULL AND NEW.wallet_address IS NOT NULL THEN
    -- normalize wallet to lowercase
    NEW.wallet_address := lower(NEW.wallet_address);
    IF NEW.wallet_address ~ '^0x[a-f0-9]{40}$' THEN
      NEW.canonical_user_id := 'prize:pid:' || NEW.wallet_address;
    END IF;
  END IF;
  RETURN NEW;
END;$function$
"

definition: "CREATE OR REPLACE FUNCTION public.set_primary_wallet(user_identifier text, p_wallet_address text)
 RETURNS json
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_user RECORD;
  v_normalized_address TEXT;
  v_existing_wallets JSONB;
  v_updated_wallets JSONB;
  v_wallet_found BOOLEAN := false;
  v_old_canonical_id TEXT;
  v_new_canonical_id TEXT;
BEGIN
  -- Normalize wallet address
  v_normalized_address := LOWER(p_wallet_address);

  -- Find user by various identifiers
  SELECT * INTO v_user
  FROM canonical_users cu
  WHERE cu.canonical_user_id = user_identifier
     OR LOWER(cu.wallet_address) = LOWER(user_identifier)
     OR LOWER(cu.base_wallet_address) = LOWER(user_identifier)
     OR cu.privy_user_id = user_identifier
     OR cu.email ILIKE user_identifier
     OR cu.uid::TEXT = user_identifier
  LIMIT 1;

  IF v_user IS NULL THEN
    RETURN json_build_object('success', false, 'error', 'User not found');
  END IF;

  -- Get existing wallets
  v_existing_wallets := COALESCE(v_user.linked_wallets, '[]'::JSONB);

  -- Check if wallet exists in linked_wallets or is the current base/external wallet
  SELECT EXISTS(
    SELECT 1 FROM jsonb_array_elements(v_existing_wallets) AS w
    WHERE LOWER(w->>'address') = v_normalized_address
  ) OR LOWER(v_user.base_wallet_address) = v_normalized_address
    OR LOWER(v_user.linked_external_wallet) = v_normalized_address
    OR LOWER(v_user.wallet_address) = v_normalized_address
  INTO v_wallet_found;

  IF NOT v_wallet_found THEN
    RETURN json_build_object('success', false, 'error', 'Wallet not found in account');
  END IF;

  -- Store old canonical ID for reference
  v_old_canonical_id := v_user.canonical_user_id;

  -- Generate new canonical ID based on new primary wallet
  v_new_canonical_id := 'prize:pid:' || v_normalized_address;

  -- Update is_primary flag in linked_wallets array
  SELECT jsonb_agg(
    CASE
      WHEN LOWER(w->>'address') = v_normalized_address
      THEN w || '{"is_primary": true}'::JSONB
      ELSE w || '{"is_primary": false}'::JSONB
    END
  )
  INTO v_updated_wallets
  FROM jsonb_array_elements(v_existing_wallets) AS w;

  -- Update the user record
  UPDATE canonical_users
  SET
    primary_wallet_address = v_normalized_address,
    wallet_address = v_normalized_address,
    canonical_user_id = v_new_canonical_id,
    linked_wallets = COALESCE(v_updated_wallets, v_existing_wallets),
    updated_at = NOW()
  WHERE uid = v_user.uid;

  RETURN json_build_object(
    'success', true,
    'message', 'Primary wallet updated successfully',
    'old_canonical_id', v_old_canonical_id,
    'new_canonical_id', v_new_canonical_id,
    'primary_wallet', v_normalized_address
  );
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.set_updated_at()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  NEW.updated_at = now();
  RETURN NEW;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.staging_force_credit_topup_overwrite_balances()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_amount numeric := COALESCE(NEW.amount, 0);
  v_currency text := COALESCE(NEW.currency, 'USDC');
  v_now timestamptz := now();
  v_bal_id uuid;
BEGIN
  -- Only act on completed topups
  IF lower(COALESCE(NEW.type,'')) <> 'topup' THEN
    RETURN NEW;
  END IF;

  IF NOT (
    lower(COALESCE(NEW.status,'')) IN ('completed','confirmed')
    OR lower(COALESCE(NEW.payment_status,'')) IN ('completed','confirmed')
  ) THEN
    RETURN NEW;
  END IF;

  -- Normalize currency to USDC
  IF v_currency IN ('USD','USDC') THEN
    v_currency := 'USDC';
  END IF;

  -- Ensure sub_account_balances row exists (by canonical_user_id)
  PERFORM public.ensure_sub_account_balance_row(NEW.canonical_user_id, v_currency);

  SELECT id INTO v_bal_id
  FROM public.sub_account_balances
  WHERE canonical_user_id = NEW.canonical_user_id
    AND currency = v_currency
  LIMIT 1;

  -- OVERWRITE / CREDIT: just add amount to available_balance
  UPDATE public.sub_account_balances b
  SET available_balance = COALESCE(b.available_balance, 0) + v_amount,
      last_updated = v_now
  WHERE b.id = v_bal_id;

  -- Mirror into canonical_users.usdc_balance (aggressive overwrite)
  UPDATE public.canonical_users cu
  SET usdc_balance = (
        SELECT b.available_balance
        FROM public.sub_account_balances b
        WHERE b.id = v_bal_id
      ),
      updated_at = v_now
  WHERE cu.canonical_user_id = NEW.canonical_user_id;

  -- Mark posted so other posting triggers don't fight us
  NEW.posted_to_balance := true;
  NEW.completed_at := COALESCE(NEW.completed_at, v_now);

  RETURN NEW;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.sub_account_balances_sync_ids()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF NEW.user_id IS NOT NULL THEN
    NEW.user_id := 'prize:pid:' || lower(replace(NEW.user_id::text, 'prize:pid:', ''));
    NEW.canonical_user_id := NEW.user_id;
  ELSIF NEW.canonical_user_id IS NOT NULL THEN
    NEW.canonical_user_id := 'prize:pid:' || lower(replace(NEW.canonical_user_id::text, 'prize:pid:', ''));
    NEW.user_id := NEW.canonical_user_id;
  END IF;
  RETURN NEW;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.sub_account_bonus_trigger()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_prev numeric := COALESCE((CASE WHEN TG_OP = 'UPDATE' THEN OLD.available_balance ELSE NULL END), 0);
  v_new numeric := COALESCE(NEW.available_balance, 0);
BEGIN
  -- Only USD rows and only when crossing strictly above 3
  IF NEW.currency = 'USD' AND v_new > 3 AND COALESCE(v_prev, 0) <= 3 THEN
    PERFORM public.award_welcome_bonus(NEW.wallet_address, 3, 100);
  END IF;
  RETURN NEW;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.sync_competition_status_if_ended(p_competition_id text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_end_date TIMESTAMP WITH TIME ZONE;
  v_current_status TEXT;
BEGIN
  SELECT end_date, status INTO v_end_date, v_current_status
  FROM competitions
  WHERE id = p_competition_id::UUID OR uid = p_competition_id::UUID;

  IF v_end_date IS NOT NULL AND v_end_date < NOW() AND v_current_status != 'ended' THEN
    UPDATE competitions
    SET status = 'ended'
    WHERE id = p_competition_id::UUID OR uid = p_competition_id::UUID;

    RETURN jsonb_build_object(
      'status_changed', true,
      'old_status', v_current_status,
      'new_status', 'ended'
    );
  END IF;

  RETURN jsonb_build_object(
    'status_changed', false,
    'current_status', v_current_status
  );
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.sync_competition_status_if_ended(p_competition_id uuid)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  comp_end_date TIMESTAMPTZ;
  comp_status TEXT;
BEGIN
  SELECT status, end_date INTO comp_status, comp_end_date
  FROM competitions
  WHERE id = p_competition_id;

  IF NOT FOUND THEN
    RETURN FALSE;
  END IF;

  IF comp_status IN ('completed', 'drawn', 'cancelled') THEN
    RETURN FALSE;
  END IF;

  IF comp_end_date IS NOT NULL AND comp_end_date < NOW() THEN
    UPDATE competitions
    SET
      status = 'completed',
      updated_at = NOW()
    WHERE id = p_competition_id
      AND status IN ('active', 'drawing', 'paused');

    IF FOUND THEN
      RETURN TRUE;
    END IF;
  END IF;

  RETURN FALSE;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.sync_external_wallet_balances(privy_user_id_param text)
 RETURNS TABLE(user_wallet_address text, external_balance numeric, previous_internal_balance numeric, new_internal_balance numeric, difference numeric)
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE v_user_record RECORD; v_ext NUMERIC; v_prev NUMERIC; v_new NUMERIC; BEGIN
  SELECT * INTO v_user_record FROM canonical_users WHERE privy_user_id=privy_user_id_param LIMIT 1;
  IF v_user_record IS NULL THEN RETURN; END IF;
  v_ext := 0; v_prev := COALESCE(v_user_record.usdc_balance,0); v_new := v_prev + v_ext;
  UPDATE canonical_users SET usdc_balance=v_new, updated_at=NOW() WHERE id=v_user_record.id;
  RETURN QUERY SELECT v_user_record.wallet_address, v_ext, v_prev, v_new, v_new - v_prev; END; $function$
"

definition: "CREATE OR REPLACE FUNCTION public.sync_identity_columns()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_row_json jsonb;
    v_canonical_user canonical_users%ROWTYPE;
    v_lookup_id text;
    v_found boolean := false;
BEGIN
    -- Convert the incoming row to JSON to check available fields
    v_row_json := to_jsonb(NEW);

    -- Only proceed if we need to fill in missing identity information
    -- Check if canonical_user_id is NULL and we have something to look up
    IF (v_row_json ? 'canonical_user_id' AND (v_row_json->>'canonical_user_id') IS NULL) OR
       (v_row_json ? 'wallet_address' AND (v_row_json->>'wallet_address') IS NULL) THEN

        -- Try lookup by canonical_user_id first (if present and not null)
        IF v_row_json ? 'canonical_user_id' AND (v_row_json->>'canonical_user_id') IS NOT NULL THEN
            v_lookup_id := v_row_json->>'canonical_user_id';
            SELECT * INTO v_canonical_user
            FROM canonical_users
            WHERE canonical_user_id = v_lookup_id
            LIMIT 1;
            v_found := FOUND;
        END IF;

        -- Try lookup by privy_user_id if not found and field exists
        IF NOT v_found AND v_row_json ? 'privy_user_id' AND (v_row_json->>'privy_user_id') IS NOT NULL THEN
            v_lookup_id := v_row_json->>'privy_user_id';
            SELECT * INTO v_canonical_user
            FROM canonical_users
            WHERE privy_user_id = v_lookup_id
            LIMIT 1;
            v_found := FOUND;
        END IF;

        -- Try lookup by user_id if not found and field exists (might be a wallet or canonical ID)
        IF NOT v_found AND v_row_json ? 'user_id' AND (v_row_json->>'user_id') IS NOT NULL THEN
            v_lookup_id := v_row_json->>'user_id';
            -- Try as canonical_user_id first
            SELECT * INTO v_canonical_user
            FROM canonical_users
            WHERE canonical_user_id = v_lookup_id
            LIMIT 1;
            v_found := FOUND;

            -- Try as wallet_address (case insensitive)
            IF NOT v_found AND v_lookup_id LIKE '0x%' THEN
                SELECT * INTO v_canonical_user
                FROM canonical_users
                WHERE LOWER(wallet_address) = LOWER(v_lookup_id)
                   OR LOWER(base_wallet_address) = LOWER(v_lookup_id)
                LIMIT 1;
                v_found := FOUND;
            END IF;

            -- Try as privy_user_id
            IF NOT v_found THEN
                SELECT * INTO v_canonical_user
                FROM canonical_users
                WHERE privy_user_id = v_lookup_id
                LIMIT 1;
                v_found := FOUND;
            END IF;

            -- Try as uid
            IF NOT v_found THEN
                SELECT * INTO v_canonical_user
                FROM canonical_users
                WHERE uid::text = v_lookup_id
                LIMIT 1;
                v_found := FOUND;
            END IF;
        END IF;

        -- Try lookup by wallet_address if not found and field exists
        IF NOT v_found AND v_row_json ? 'wallet_address' AND (v_row_json->>'wallet_address') IS NOT NULL THEN
            v_lookup_id := v_row_json->>'wallet_address';
            SELECT * INTO v_canonical_user
            FROM canonical_users
            WHERE LOWER(wallet_address) = LOWER(v_lookup_id)
               OR LOWER(base_wallet_address) = LOWER(v_lookup_id)
            LIMIT 1;
            v_found := FOUND;
        END IF;

        -- Try lookup by uid if not found and field exists
        IF NOT v_found AND v_row_json ? 'uid' AND (v_row_json->>'uid') IS NOT NULL THEN
            v_lookup_id := v_row_json->>'uid';
            SELECT * INTO v_canonical_user
            FROM canonical_users
            WHERE uid::text = v_lookup_id
            LIMIT 1;
            v_found := FOUND;
        END IF;

        -- If we found a matching canonical user, enrich the row
        IF v_found THEN
            -- Fill canonical_user_id if column exists and is NULL
            IF v_row_json ? 'canonical_user_id' AND (v_row_json->>'canonical_user_id') IS NULL THEN
                IF v_canonical_user.canonical_user_id IS NOT NULL THEN
                    NEW.canonical_user_id := v_canonical_user.canonical_user_id;
                END IF;
            END IF;

            -- Fill wallet_address if column exists and is NULL
            IF v_row_json ? 'wallet_address' AND (v_row_json->>'wallet_address') IS NULL THEN
                IF v_canonical_user.wallet_address IS NOT NULL THEN
                    NEW.wallet_address := v_canonical_user.wallet_address;
                ELSIF v_canonical_user.base_wallet_address IS NOT NULL THEN
                    NEW.wallet_address := v_canonical_user.base_wallet_address;
                END IF;
            END IF;
        END IF;
    END IF;

    RETURN NEW;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.tickets_finalize_spend_trigger()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_finalized boolean;
  v_amount numeric;
  v_cuid text;
  v_provider text;
BEGIN
  -- Only act after insert or update to a finalized state
  v_finalized := (NEW.status IN ('sold','purchased')) AND NEW.payment_amount IS NOT NULL;
  IF NOT v_finalized THEN
    RETURN NEW;
  END IF;

  v_amount := NEW.payment_amount;
  v_cuid := public._ticket_cuid(NEW.user_id, NEW.canonical_user_id, NEW.wallet_address);
  v_provider := NEW.payment_provider; -- may be null; acceptable

  -- Ensure we only process once per ticket id
  -- Type-safe comparison: match by canonical_user_id when present, otherwise compare user_id::text
  PERFORM 1 FROM public.user_transactions ut
  WHERE ut.type = 'entry'
    AND ut.status = 'completed'
    AND ut.amount = v_amount
    AND (ut.order_id = NEW.order_id OR (NEW.order_id IS NULL AND ut.order_id IS NULL))
    AND (ut.description = NEW.id::text OR ut.description IS NULL)
    AND (
      (ut.canonical_user_id IS NOT NULL AND ut.canonical_user_id = v_cuid)
      OR (ut.canonical_user_id IS NULL AND ut.user_id IS NOT NULL AND ut.user_id::text = v_cuid)
    );
  IF FOUND THEN
    RETURN NEW;
  END IF;

  -- Insert transaction (v_cuid is canonical text id)
  PERFORM public._insert_user_spend_tx(v_cuid, v_amount, NEW.competition_id, NEW.order_id, NEW.id, v_provider, NEW.wallet_address);

  -- Deduct from balance using canonical id text
  PERFORM public._deduct_sub_account_balance(v_cuid, v_amount);

  RETURN NEW;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.tickets_sync_wallet()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF NEW.canonical_user_id IS NOT NULL AND (NEW.wallet_address IS NULL OR NEW.wallet_address = '') THEN
    NEW.wallet_address := replace(NEW.canonical_user_id, 'prize:pid:', '');
  END IF;
  RETURN NEW;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.to_canonical_user_id(p_input text)
 RETURNS text
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$
BEGIN
  IF p_input IS NULL OR p_input = '' THEN
    RETURN NULL;
  END IF;

  -- Already canonical
  IF p_input LIKE 'prize:pid:%' THEN
    RETURN p_input;
  END IF;

  -- Privy DID
  IF p_input LIKE 'did:privy:%' THEN
    RETURN 'prize:pid:' || substring(p_input from 11);
  END IF;

  -- Wallet address
  IF p_input LIKE '0x%' THEN
    RETURN 'prize:pid:' || lower(p_input);
  END IF;

  -- Default
  RETURN 'prize:pid:' || p_input;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.trg_competition_entries_normalize_wallet()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
