definition: "CREATE OR REPLACE FUNCTION public.update_profile_flex(payload jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_identifier text := COALESCE(
    payload->>'identifier', payload->>'user_identifier', payload->>'canonical_user_id',
    payload->>'p_identifier', payload->>'p_canonical_user_id', payload->>'email'
  );
  v_username text := COALESCE(payload->>'username', payload->>'p_username');
  v_email text := COALESCE(payload->>'email', payload->>'p_email');
  v_phone text := COALESCE(payload->>'phone', payload->>'telephone', payload->>'telephone_number', payload->>'p_phone');
  v_country text := COALESCE(payload->>'country', payload->>'p_country');
  v_telegram text := payload->>'telegram_handle';
  v_telnum text := COALESCE(payload->>'telephone_number', payload->>'p_telephone_number');
BEGIN
  IF v_identifier IS NULL THEN
    RAISE EXCEPTION 'missing_identifier' USING MESSAGE = 'identifier (canonical_user_id or email) is required';
  END IF;
  RETURN public.update_user_profile_by_identifier(v_identifier, v_username, v_email, v_phone, v_country, v_telegram, v_telnum);
END; $function$
"

definition: "CREATE OR REPLACE FUNCTION public.update_transaction_status(p_id text, p_status text)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF p_id IS NULL OR length(p_id) = 0 THEN
    RAISE EXCEPTION 'update_transaction_status: p_id is empty';
  END IF;
  UPDATE public.user_transactions
  SET status = p_status, updated_at = now()
  WHERE id = p_id::uuid;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'update_transaction_status: no user_transactions row with id=%', p_id;
  END IF;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.update_wallet_nickname(user_identifier text, p_wallet_address text, p_nickname text)
 RETURNS json
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_user RECORD;
  v_normalized_address TEXT;
  v_existing_wallets JSONB;
  v_updated_wallets JSONB;
BEGIN
  v_normalized_address := LOWER(p_wallet_address);

  -- Find user
  SELECT * INTO v_user
  FROM canonical_users cu
  WHERE cu.canonical_user_id = user_identifier
     OR LOWER(cu.wallet_address) = LOWER(user_identifier)
     OR cu.privy_user_id = user_identifier
     OR cu.email ILIKE user_identifier
     OR cu.uid::TEXT = user_identifier
  LIMIT 1;

  IF v_user IS NULL THEN
    RETURN json_build_object('success', false, 'error', 'User not found');
  END IF;

  v_existing_wallets := COALESCE(v_user.linked_wallets, '[]'::JSONB);

  -- Update the nickname for the specified wallet
  SELECT jsonb_agg(
    CASE
      WHEN LOWER(w->>'address') = v_normalized_address
      THEN jsonb_set(w, '{nickname}', to_jsonb(p_nickname))
      ELSE w
    END
  )
  INTO v_updated_wallets
  FROM jsonb_array_elements(v_existing_wallets) AS w;

  UPDATE canonical_users
  SET
    linked_wallets = COALESCE(v_updated_wallets, v_existing_wallets),
    updated_at = NOW()
  WHERE uid = v_user.uid;

  RETURN json_build_object('success', true, 'message', 'Nickname updated successfully');
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.user_transactions_post_to_wallet()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_before numeric := 0;
  v_after numeric := 0;
  v_delta numeric := 0;
  v_currency text;
  v_uid text;
BEGIN
  IF (TG_OP <> 'INSERT' AND TG_OP <> 'UPDATE') THEN
    RETURN NEW;
  END IF;

  IF NEW.posted_to_balance IS TRUE THEN
    RETURN NEW;
  END IF;

  IF lower(COALESCE(NEW.status,'')) <> 'completed' THEN
    RETURN NEW;
  END IF;

  IF lower(COALESCE(NEW.type,'')) = 'entry'
     AND lower(COALESCE(NEW.payment_provider,'')) <> 'balance' THEN
    NEW.balance_before := NULL;
    NEW.balance_after := NULL;
    RETURN NEW;
  END IF;

  v_currency := upper(btrim(COALESCE(NEW.currency, 'USDC')));

  -- normalize user id to match sub_account_balances_sync_ids()
  v_uid := 'prize:pid:' || lower(replace(COALESCE(NEW.canonical_user_id,'')::text, 'prize:pid:', ''));

  IF v_uid = 'prize:pid:' THEN
    NEW.balance_before := NULL;
    NEW.balance_after := NULL;
    NEW.posted_to_balance := false;
    RETURN NEW;
  END IF;

  IF lower(COALESCE(NEW.type,'')) = 'topup' THEN
    v_delta := abs(COALESCE(NEW.amount,0));
  ELSIF lower(COALESCE(NEW.type,'')) = 'entry' THEN
    v_delta := -abs(COALESCE(NEW.amount,0));
  ELSE
    RETURN NEW;
  END IF;

  INSERT INTO public.sub_account_balances (canonical_user_id, currency, available_balance, last_updated)
  VALUES (v_uid, v_currency, 0, now())
  ON CONFLICT (canonical_user_id, currency) DO NOTHING;

  SELECT COALESCE(available_balance,0)
    INTO v_before
  FROM public.sub_account_balances
  WHERE canonical_user_id = v_uid
    AND currency = v_currency
  FOR UPDATE;

  IF NOT FOUND THEN
    NEW.balance_before := NULL;
    NEW.balance_after := NULL;
    NEW.posted_to_balance := false;
    RETURN NEW;
  END IF;

  v_after := v_before + v_delta;

  IF v_delta < 0 AND v_after < 0 THEN
    RAISE EXCEPTION 'Not enough balance';
  END IF;

  UPDATE public.sub_account_balances
     SET available_balance = v_after,
         last_updated = now()
   WHERE canonical_user_id = v_uid
     AND currency = v_currency;

  IF v_currency = 'USDC' THEN
    UPDATE public.canonical_users
       SET usdc_balance = v_after,
           updated_at = now()
     WHERE canonical_user_id = v_uid;
  END IF;

  NEW.balance_before := v_before;
  NEW.balance_after := v_after;
  NEW.posted_to_balance := true;
  NEW.completed_at := COALESCE(NEW.completed_at, now());

  -- optionally also normalize the transaction row’s canonical_user_id to match
  NEW.canonical_user_id := v_uid;

  RETURN NEW;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.user_transactions_sync_wallet()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF NEW.canonical_user_id IS NOT NULL AND (NEW.wallet_address IS NULL OR NEW.wallet_address = '') THEN
    NEW.wallet_address := replace(NEW.canonical_user_id, 'prize:pid:', '');
  END IF;
  RETURN NEW;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.user_tx_autocomplete_if_expired()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF NEW.status = 'pending' AND NEW.expires_at IS NOT NULL AND NEW.expires_at <= NOW() THEN
    NEW.status := 'completed';
    NEW.completed_at := NOW();
  END IF;
  RETURN NEW;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.user_tx_before_insert()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  NEW.type := lower(COALESCE(NEW.type, 'entry'));
  NEW.status := lower(COALESCE(NEW.status, 'pending'));

  IF NEW.status = 'pending' AND NEW.expires_at IS NULL THEN
    NEW.expires_at := NOW() + INTERVAL '2 minutes';
  END IF;

  RETURN NEW;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.user_tx_guard_no_double_post()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF OLD.posted_to_balance = true AND NEW.status = 'completed' THEN
    NEW.posted_to_balance := true;
  END IF;
  RETURN NEW;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.users_autolink_canonical_before_ins()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_email text := nullif(lower(trim(new.email)), '');
  v_wallet text := nullif(lower(trim(new.wallet_address)), '');
  v_row public.canonical_users;
begin
  -- If canonical_user_id already provided, allow
  if new.canonical_user_id is not null and length(new.canonical_user_id) > 0 then
    return new;
  end if;

  -- Try to resolve via ensure_canonical_user using whatever is present
  v_row := public.ensure_canonical_user(
    p_email => v_email,
    p_wallet_address => v_wallet
  );

  new.canonical_user_id := v_row.canonical_user_id;

  if new.canonical_user_id is null then
    raise exception 'canonical_user_id could not be resolved for email=% wallet=%', v_email, v_wallet;
  end if;

  return new;
end;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.users_normalize_before_write()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
begin
  if new.wallet_address is not null then
    new.wallet_address := util.normalize_evm_address(new.wallet_address);
  end if;

  if new.wallet_address is not null then
    new.canonical_user_id := 'prize:pid:' || new.wallet_address;
  elsif new.canonical_user_id is not null then
    -- If only canonical provided, try to extract wallet
    if position('prize:pid:' in new.canonical_user_id) = 1 then
      new.wallet_address := replace(new.canonical_user_id, 'prize:pid:', '');
    end if;
  end if;

  return new;
end;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.validate_reservation(p_reservation_id uuid, p_user_id text, p_competition_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  rec record;
  result jsonb := '{}'::jsonb;
  now_ts timestamptz := now();
BEGIN
  SELECT id, user_id::text AS user_id_text, competition_id, status, expires_at, created_at
  INTO rec
  FROM public.pending_tickets
  WHERE id = p_reservation_id;

  IF NOT FOUND THEN
    RETURN jsonb_build_object(
      'ok', false,
      'reason', 'not_found'
    );
  END IF;

  result := jsonb_build_object(
    'ok', true,
    'reservation', jsonb_build_object(
      'id', rec.id,
      'user_id', rec.user_id_text,
      'competition_id', rec.competition_id,
      'status', rec.status,
      'expires_at', rec.expires_at,
      'created_at', rec.created_at
    )
  );

  -- user mismatch
  IF rec.user_id_text IS DISTINCT FROM p_user_id THEN
    result := result || jsonb_build_object('user_mismatch', true);
  END IF;

  -- competition mismatch
  IF rec.competition_id IS DISTINCT FROM p_competition_id THEN
    result := result || jsonb_build_object('competition_mismatch', true);
  END IF;

  -- expired
  IF rec.expires_at <= now_ts THEN
    result := result || jsonb_build_object('expired', true);
  END IF;

  -- invalid status (expects pending)
  IF rec.status <> 'pending' THEN
    result := result || jsonb_build_object('invalid_status', rec.status);
  END IF;

  RETURN result;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.winners_sync_wallet()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF TG_OP IN ('INSERT','UPDATE') THEN
    BEGIN
      -- Try to set from canonical_user_id if column exists
      PERFORM 1 FROM information_schema.columns WHERE table_schema='public' AND table_name=TG_TABLE_NAME AND column_name='canonical_user_id';
      IF FOUND THEN
        IF NEW.canonical_user_id IS NOT NULL AND (NEW.wallet_address IS NULL OR NEW.wallet_address = '') THEN
          NEW.wallet_address := replace(NEW.canonical_user_id, 'prize:pid:', '');
        END IF;
      END IF;
    EXCEPTION WHEN undefined_column THEN
      -- no-op if canonical_user_id not present
      NULL;
    END;
  END IF;
  RETURN NEW;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION public.winners_sync_wallet_from_user_id()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF NEW.user_id IS NOT NULL AND NEW.user_id LIKE 'prize:pid:%' AND (NEW.wallet_address IS NULL OR NEW.wallet_address = '') THEN
    NEW.wallet_address := replace(NEW.user_id, 'prize:pid:', '');
  END IF;
  RETURN NEW;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION realtime.broadcast_changes(topic_name text, event_name text, operation text, table_name text, table_schema text, new record, old record, level text DEFAULT 'ROW'::text)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
    -- Declare a variable to hold the JSONB representation of the row
    row_data jsonb := '{}'::jsonb;
BEGIN
    IF level = 'STATEMENT' THEN
        RAISE EXCEPTION 'function can only be triggered for each row, not for each statement';
    END IF;
    -- Check the operation type and handle accordingly
    IF operation = 'INSERT' OR operation = 'UPDATE' OR operation = 'DELETE' THEN
        row_data := jsonb_build_object('old_record', OLD, 'record', NEW, 'operation', operation, 'table', table_name, 'schema', table_schema);
        PERFORM realtime.send (row_data, event_name, topic_name);
    ELSE
        RAISE EXCEPTION 'Unexpected operation type: %', operation;
    END IF;
EXCEPTION
    WHEN OTHERS THEN
        RAISE EXCEPTION 'Failed to process the row: %', SQLERRM;
END;

$function$
"

definition: "CREATE OR REPLACE FUNCTION realtime.send(payload jsonb, event text, topic text, private boolean DEFAULT true)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
  generated_id uuid;
  final_payload jsonb;
BEGIN
  BEGIN
    -- Generate a new UUID for the id
    generated_id := gen_random_uuid();

    -- Check if payload has an 'id' key, if not, add the generated UUID
    IF payload ? 'id' THEN
      final_payload := payload;
    ELSE
      final_payload := jsonb_set(payload, '{id}', to_jsonb(generated_id));
    END IF;

    -- Set the topic configuration
    EXECUTE format('SET LOCAL realtime.topic TO %L', topic);

    -- Attempt to insert the message
    INSERT INTO realtime.messages (id, payload, event, topic, private, extension)
    VALUES (generated_id, final_payload, event, topic, private, 'broadcast');
  EXCEPTION
    WHEN OTHERS THEN
      -- Capture and notify the error
      RAISE WARNING 'ErrorSendingBroadcastMessage: %', SQLERRM;
  END;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION realtime.subscription_check_filters()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
    /*
    Validates that the user defined filters for a subscription:
    - refer to valid columns that the claimed role may access
    - values are coercable to the correct column type
    */
    declare
        col_names text[] = coalesce(
                array_agg(c.column_name order by c.ordinal_position),
                '{}'::text[]
            )
            from
                information_schema.columns c
            where
                format('%I.%I', c.table_schema, c.table_name)::regclass = new.entity
                and pg_catalog.has_column_privilege(
                    (new.claims ->> 'role'),
                    format('%I.%I', c.table_schema, c.table_name)::regclass,
                    c.column_name,
                    'SELECT'
                );
        filter realtime.user_defined_filter;
        col_type regtype;

        in_val jsonb;
    begin
        for filter in select * from unnest(new.filters) loop
            -- Filtered column is valid
            if not filter.column_name = any(col_names) then
                raise exception 'invalid column for filter %', filter.column_name;
            end if;

            -- Type is sanitized and safe for string interpolation
            col_type = (
                select atttypid::regtype
                from pg_catalog.pg_attribute
                where attrelid = new.entity
                      and attname = filter.column_name
            );
            if col_type is null then
                raise exception 'failed to lookup type for column %', filter.column_name;
            end if;

            -- Set maximum number of entries for in filter
            if filter.op = 'in'::realtime.equality_op then
                in_val = realtime.cast(filter.value, (col_type::text || '[]')::regtype);
                if coalesce(jsonb_array_length(in_val), 0) > 100 then
                    raise exception 'too many values for `in` filter. Maximum 100';
                end if;
            else
                -- raises an exception if value is not coercable to type
                perform realtime.cast(filter.value, col_type);
            end if;

        end loop;

        -- Apply consistent order to filters so the unique constraint on
        -- (subscription_id, entity, filters) can't be tricked by a different filter order
        new.filters = coalesce(
            array_agg(f order by f.column_name, f.op, f.value),
            '{}'
        ) from unnest(new.filters) f;

        return new;
    end;
    $function$
"

definition: "CREATE OR REPLACE FUNCTION util.finalize_pending_user_transactions()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_curr_balance numeric;
BEGIN
  IF NEW.status = 'pending' THEN
    SELECT COALESCE(sab.available_balance, 0)
      INTO v_curr_balance
      FROM public.sub_account_balances sab
     WHERE sab.canonical_user_id = NEW.canonical_user_id
       AND sab.currency = NEW.currency
     LIMIT 1;

    NEW.balance_before := COALESCE(v_curr_balance, 0);
    NEW.balance_after  := COALESCE(v_curr_balance, 0) + COALESCE(NEW.amount, 0);
    NEW.status := 'completed';
    NEW.completed_at := NOW();
    NEW.posted_to_balance := true;

    -- Upsert balance atomically
    INSERT INTO public.sub_account_balances (
      user_id, canonical_user_id, currency, available_balance, pending_balance, last_updated
    ) VALUES (
      NEW.user_id, NEW.canonical_user_id, NEW.currency, COALESCE(NEW.amount,0), 0, NOW()
    )
    ON CONFLICT (canonical_user_id, currency)
    DO UPDATE SET available_balance = public.sub_account_balances.available_balance + EXCLUDED.available_balance,
                  last_updated = NOW();
  END IF;

  RETURN NEW;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION util.resolve_canonical_user_id(p_wallet text, p_privy text)
 RETURNS text
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
AS $function$
    DECLARE
      v_wallet text := util.normalize_wallet(p_wallet);
      v_cuid text;
    BEGIN
      IF v_wallet IS NOT NULL THEN
        SELECT cu.canonical_user_id
        INTO v_cuid
        FROM public.canonical_users cu
        WHERE v_wallet = ANY(ARRAY[
          cu.wallet_address,
          cu.base_wallet_address,
          cu.eth_wallet_address,
          cu.primary_wallet_address
        ])
        LIMIT 1;
        IF v_cuid IS NOT NULL THEN
          RETURN v_cuid;
        END IF;

        SELECT cu.canonical_user_id
        INTO v_cuid
        FROM public.canonical_users cu
        WHERE cu.linked_wallets ? v_wallet
        LIMIT 1;
        IF v_cuid IS NOT NULL THEN
          RETURN v_cuid;
        END IF;
      END IF;

      IF p_privy IS NOT NULL THEN
        SELECT cu.canonical_user_id
        INTO v_cuid
        FROM public.canonical_users cu
        WHERE cu.privy_user_id = p_privy
        LIMIT 1;
        IF v_cuid IS NOT NULL THEN
          RETURN v_cuid;
        END IF;
      END IF;

      RETURN NULL;
    END;
    $function$
"

definition: "CREATE OR REPLACE FUNCTION util.trg_set_cuid_from_context()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF NEW.canonical_user_id IS NULL THEN
    NEW.canonical_user_id := util.resolve_canonical_user_id(
      NEW.wallet_address,
      COALESCE(NEW.privy_user_id, NEW.user_privy_id)
    );
  END IF;
  RETURN NEW;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION util.upsert_canonical_user_from_auth(in_p_canonical_id text, in_p_wallet_address text, in_p_email text, in_p_auth_provider text DEFAULT NULL::text)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_id uuid;
  v_wallet text := util.normalize_evm_address(in_p_wallet_address);
  v_email text := NULLIF(lower(trim(in_p_email)), '');
  v_canon text := CASE 
    WHEN in_p_canonical_id IS NOT NULL AND length(trim(in_p_canonical_id))>0 THEN lower(trim(in_p_canonical_id))
    WHEN v_wallet IS NOT NULL THEN 'prize:pid:' || v_wallet
    ELSE NULL
  END;
BEGIN
  -- Optional small delay to let client events settle
  PERFORM pg_sleep(2);

  -- Try canonical id first
  IF v_canon IS NOT NULL THEN
    SELECT id INTO v_id FROM public.canonical_users WHERE canonical_user_id = v_canon LIMIT 1;
    IF FOUND THEN
      UPDATE public.canonical_users SET
        wallet_address = COALESCE(wallet_address, v_wallet),
        base_wallet_address = COALESCE(base_wallet_address, v_wallet),
        eth_wallet_address = COALESCE(eth_wallet_address, v_wallet),
        email = COALESCE(email, v_email),
        auth_provider = COALESCE(auth_provider, in_p_auth_provider),
        wallet_linked = COALESCE(wallet_linked, (v_wallet IS NOT NULL)),
        updated_at = NOW()
      WHERE id = v_id;
      RETURN v_id;
    END IF;
  END IF;

  -- Try wallet next
  IF v_wallet IS NOT NULL THEN
    SELECT id INTO v_id FROM public.canonical_users WHERE wallet_address = v_wallet LIMIT 1;
    IF FOUND THEN
      UPDATE public.canonical_users SET
        canonical_user_id = COALESCE(canonical_user_id, v_canon),
        email = COALESCE(email, v_email),
        auth_provider = COALESCE(auth_provider, in_p_auth_provider),
        wallet_linked = COALESCE(wallet_linked, true),
        updated_at = NOW()
      WHERE id = v_id;
      RETURN v_id;
    END IF;
  END IF;

  -- Try email last (case-insensitive)
  IF v_email IS NOT NULL THEN
    SELECT id INTO v_id FROM public.canonical_users WHERE lower(email) = v_email LIMIT 1;
    IF FOUND THEN
      UPDATE public.canonical_users SET
        canonical_user_id = COALESCE(canonical_user_id, v_canon),
        wallet_address = COALESCE(wallet_address, v_wallet),
        base_wallet_address = COALESCE(base_wallet_address, v_wallet),
        eth_wallet_address = COALESCE(eth_wallet_address, v_wallet),
        auth_provider = COALESCE(auth_provider, in_p_auth_provider),
        wallet_linked = COALESCE(wallet_linked, (v_wallet IS NOT NULL)),
        updated_at = NOW()
      WHERE id = v_id;
      RETURN v_id;
    END IF;
  END IF;

  -- Insert new if none found. Enforce canonical id and wallet normalization.
  INSERT INTO public.canonical_users (
    id, canonical_user_id, uid, email, wallet_address, base_wallet_address, eth_wallet_address, auth_provider, wallet_linked
  ) VALUES (
    gen_random_uuid(), v_canon, gen_random_uuid(), v_email, v_wallet, v_wallet, v_wallet, in_p_auth_provider, (v_wallet IS NOT NULL)
  )
  ON CONFLICT (canonical_user_id) DO UPDATE SET
    email = COALESCE(public.canonical_users.email, EXCLUDED.email),
    wallet_address = COALESCE(public.canonical_users.wallet_address, EXCLUDED.wallet_address),
    base_wallet_address = COALESCE(public.canonical_users.base_wallet_address, EXCLUDED.base_wallet_address),
    eth_wallet_address = COALESCE(public.canonical_users.eth_wallet_address, EXCLUDED.eth_wallet_address),
    auth_provider = COALESCE(public.canonical_users.auth_provider, EXCLUDED.auth_provider),
    wallet_linked = COALESCE(public.canonical_users.wallet_linked, EXCLUDED.wallet_linked),
    updated_at = NOW()
  RETURNING id INTO v_id;

  RETURN v_id;
END;
$function$
"

definition: "CREATE OR REPLACE FUNCTION util.uuid_from_text(p_input text)
 RETURNS uuid
 LANGUAGE plpgsql
 STABLE
AS $function$
declare
  ns uuid := '6ba7b811-9dad-11d1-80b4-00c04fd430c8'; -- DNS namespace as base
  hash bytea;
  bytes bytea;
begin
  if p_input is null or length(p_input) = 0 then
    return null;
  end if;
  -- v5 uuid = sha1(namespace || name)
  hash := digest(convert_to(ns::text || p_input, 'utf8'), 'sha1');
  bytes := substring(hash from 1 for 16);
  -- set version (0101 for v5) and variant (10xx)
  bytes := set_bit(bytes, 52, 1); -- version bit 52..55 -> 0101; set 52 and 54
  bytes := set_bit(bytes, 53, 0);
  bytes := set_bit(bytes, 54, 1);
  bytes := set_bit(bytes, 55, 0);
  bytes := set_bit(bytes, 64, 1); -- variant bits 64..65 -> 10
  bytes := set_bit(bytes, 65, 0);
  bytes := set_bit(bytes, 66, get_bit(bytes,66));
  bytes := set_bit(bytes, 67, get_bit(bytes,67));
  return (
    lpad(to_hex(get_byte(bytes,0)),2,'0') ||
    lpad(to_hex(get_byte(bytes,1)),2,'0') ||
    lpad(to_hex(get_byte(bytes,2)),2,'0') ||
    lpad(to_hex(get_byte(bytes,3)),2,'0') || '-' ||
    lpad(to_hex(get_byte(bytes,4)),2,'0') ||
    lpad(to_hex(get_byte(bytes,5)),2,'0') || '-' ||
    lpad(to_hex(get_byte(bytes,6)),2,'0') ||
    lpad(to_hex(get_byte(bytes,7)),2,'0') || '-' ||
    lpad(to_hex(get_byte(bytes,8)),2,'0') ||
    lpad(to_hex(get_byte(bytes,9)),2,'0') || '-' ||
    lpad(to_hex(get_byte(bytes,10)),2,'0') ||
    lpad(to_hex(get_byte(bytes,11)),2,'0') ||
    lpad(to_hex(get_byte(bytes,12)),2,'0') ||
    lpad(to_hex(get_byte(bytes,13)),2,'0') ||
    lpad(to_hex(get_byte(bytes,14)),2,'0') ||
    lpad(to_hex(get_byte(bytes,15)),2,'0')
  )::uuid;
end;
$function$
"
